INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Mac and Cheese Waffles','mac-and-cheese-waffles','Crispy golden waffles stuffed with creamy macaroni and cheese for the ultimate comfort food mashup. These savory waffles are perfect for brunch or a fun dinner.','Leftover mac and cheese gets pressed into a waffle iron for a crispy cheesy treat.','American','Easy',10,20,30,4,520,18,58,24,2,'[{"amount":3,"unit":"cups","item":"prepared macaroni and cheese","group":"base"},{"amount":2,"unit":"large","item":"eggs","group":"base"},{"amount":1,"unit":"cup","item":"shredded cheddar cheese","group":"cheese"},{"amount":0.5,"unit":"cup","item":"all purpose flour","group":"base"},{"amount":0.5,"unit":"cup","item":"breadcrumbs","group":"base"},{"amount":1,"unit":"teaspoon","item":"garlic powder","group":"seasoning"},{"amount":0.5,"unit":"teaspoon","item":"smoked paprika","group":"seasoning"},{"amount":2,"unit":"tablespoons","item":"unsalted butter melted","group":"cooking"}]','[{"title":"Mix the Batter","text":"In a large bowl combine the prepared macaroni and cheese with eggs flour breadcrumbs garlic powder and smoked paprika. Stir until fully combined and the mixture holds together.","timer":0},{"title":"Preheat the Waffle Iron","text":"Preheat your waffle iron to medium high heat and brush both plates generously with melted butter to prevent sticking.","timer":180},{"title":"Fill the Waffle Iron","text":"Scoop about three quarters of a cup of the mac and cheese mixture onto the center of the waffle iron. Sprinkle shredded cheddar on top before closing the lid.","timer":0},{"title":"Cook Until Crispy","text":"Close the waffle iron and cook for 4 to 5 minutes until the waffle is deeply golden and crispy on the outside. Do not open the iron early or the waffle will fall apart.","timer":300},{"title":"Serve Hot","text":"Carefully remove the waffle and serve immediately topped with sour cream hot sauce or extra shredded cheese.","timer":0}]','[{"original":"all purpose flour","swap":"gluten free flour blend"},{"original":"cheddar cheese","swap":"gruyere or gouda"},{"original":"breadcrumbs","swap":"crushed crackers or panko"}]','["Opening the waffle iron too early causes the waffle to break apart","Using mac and cheese that is too wet makes the waffles soggy instead of crispy","Not greasing the waffle iron enough leads to severe sticking"]','["comfort food","brunch","cheesy","waffles","mac and cheese","savory"]','["vegetarian"]','Brunch','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cereal Milk French Toast','cereal-milk-french-toast','Thick brioche slices soaked in nostalgic cereal infused milk for a playful twist on classic French toast. The result is a sweet custardy breakfast that tastes like childhood in every bite.','Brioche soaked in cereal steeped milk creates the most nostalgic French toast you will ever eat.','American','Easy',15,15,30,4,430,12,62,16,1,'[{"amount":2,"unit":"cups","item":"whole milk","group":"custard"},{"amount":2,"unit":"cups","item":"fruity corn cereal such as Froot Loops","group":"custard"},{"amount":3,"unit":"large","item":"eggs","group":"custard"},{"amount":2,"unit":"tablespoons","item":"granulated sugar","group":"custard"},{"amount":1,"unit":"teaspoon","item":"vanilla extract","group":"custard"},{"amount":8,"unit":"slices","item":"thick cut brioche bread","group":"base"},{"amount":2,"unit":"tablespoons","item":"unsalted butter","group":"cooking"},{"amount":0.5,"unit":"teaspoon","item":"ground cinnamon","group":"seasoning"}]','[{"title":"Make the Cereal Milk","text":"Combine whole milk and cereal in a bowl and let steep for 10 minutes. Strain the milk through a fine mesh sieve pressing on the cereal to extract all the flavor. Discard the soggy cereal.","timer":600},{"title":"Make the Custard","text":"Whisk the cereal milk together with eggs sugar vanilla extract and cinnamon in a shallow baking dish until fully combined and smooth.","timer":0},{"title":"Soak the Bread","text":"Dip each slice of brioche into the custard mixture letting it soak for 30 seconds per side. Do not soak for too long or the bread will fall apart in the pan.","timer":0},{"title":"Cook the French Toast","text":"Melt butter in a large skillet over medium heat. Cook each soaked slice for 2 to 3 minutes per side until golden brown and cooked through.","timer":180},{"title":"Serve and Top","text":"Serve immediately topped with maple syrup whipped cream and a handful of fresh dry cereal for crunch.","timer":0}]','[{"original":"brioche bread","swap":"challah or Texas toast"},{"original":"fruity corn cereal","swap":"Cocoa Puffs or Cinnamon Toast Crunch"},{"original":"whole milk","swap":"oat milk for a dairy free version"}]','["Soaking the bread too long causes it to become too saturated and fall apart while cooking","Cooking on too high heat burns the outside before the custard inside is set","Skipping the steeping step results in plain French toast without the cereal flavor"]','["breakfast","brunch","sweet","french toast","cereal","nostalgic","brioche"]','["vegetarian"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Everything Bagel Avocado Toast','everything-bagel-avocado-toast','Creamy smashed avocado piled high on toasted sourdough and finished with a generous coating of everything bagel seasoning. This quick toast is packed with bold savory flavor and healthy fats.','Smashed avocado on sourdough toast topped with everything bagel seasoning for a fast savory breakfast.','American','Easy',5,5,10,2,310,7,32,19,8,'[{"amount":2,"unit":"slices","item":"sourdough bread","group":"base"},{"amount":2,"unit":"medium","item":"ripe avocados","group":"topping"},{"amount":1,"unit":"tablespoon","item":"fresh lemon juice","group":"topping"},{"amount":2,"unit":"teaspoons","item":"everything bagel seasoning","group":"seasoning"},{"amount":0.25,"unit":"teaspoon","item":"red pepper flakes","group":"seasoning"},{"amount":0.25,"unit":"teaspoon","item":"flaky sea salt","group":"seasoning"},{"amount":1,"unit":"tablespoon","item":"extra virgin olive oil","group":"finishing"},{"amount":2,"unit":"large","item":"eggs optional for topping","group":"topping"}]','[{"title":"Toast the Bread","text":"Toast sourdough slices in a toaster or under the broiler until deeply golden and crispy. The bread should be sturdy enough to hold the avocado without becoming soggy.","timer":180},{"title":"Smash the Avocado","text":"Halve and pit the avocados then scoop the flesh into a bowl. Add lemon juice and a pinch of salt then smash with a fork to your desired consistency leaving some chunks for texture.","timer":0},{"title":"Fry the Eggs","text":"If using eggs heat olive oil in a small skillet over medium heat. Crack in the eggs and fry for 2 to 3 minutes until the whites are set but the yolk is still runny.","timer":180},{"title":"Assemble the Toast","text":"Spread the smashed avocado generously over each slice of toasted bread. Drizzle with olive oil and top with a fried egg if desired.","timer":0},{"title":"Season and Serve","text":"Sprinkle everything bagel seasoning red pepper flakes and flaky sea salt over the top. Serve immediately while the toast is still warm and crispy.","timer":0}]','[{"original":"sourdough bread","swap":"whole grain bread or a toasted bagel"},{"original":"fresh lemon juice","swap":"fresh lime juice"},{"original":"everything bagel seasoning","swap":"mix of sesame seeds poppy seeds garlic flakes and onion flakes"}]','["Using underripe avocados results in a bland and difficult to smash topping","Assembling the toast too far in advance makes the bread soggy","Skipping the acid from lemon juice causes the avocado to brown quickly"]','["breakfast","brunch","avocado toast","quick","healthy","vegetarian","everything bagel"]','["vegetarian","dairy free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Spicy Honey Butter Cornbread Waffles','spicy-honey-butter-cornbread-waffles','Fluffy cornbread batter cooked in a waffle iron and topped with spicy honey butter for a sweet and heat filled treat. These waffles work as a side dish or a standalone savory breakfast.','Cornbread batter made into crispy waffles and finished with homemade spicy honey butter.','Southern American','Easy',10,20,30,4,480,9,54,26,3,'[{"amount":1.5,"unit":"cups","item":"yellow cornmeal","group":"batter"},{"amount":0.5,"unit":"cup","item":"all purpose flour","group":"batter"},{"amount":1,"unit":"cup","item":"buttermilk","group":"batter"},{"amount":2,"unit":"large","item":"eggs","group":"batter"},{"amount":4,"unit":"tablespoons","item":"unsalted butter melted plus more for iron","group":"batter"},{"amount":3,"unit":"tablespoons","item":"honey","group":"spicy butter"},{"amount":1,"unit":"teaspoon","item":"cayenne pepper","group":"spicy butter"},{"amount":1,"unit":"teaspoon","item":"baking powder","group":"batter"}]','[{"title":"Make the Spicy Honey Butter","text":"Melt 4 tablespoons of butter and whisk together with honey and cayenne pepper in a small bowl. Set aside to use as a topping.","timer":0},{"title":"Mix the Cornbread Batter","text":"In a large bowl whisk together cornmeal flour and baking powder. Add buttermilk eggs and melted butter and stir until just combined. Do not overmix or the waffles will be tough.","timer":0},{"title":"Preheat and Grease the Iron","text":"Preheat your waffle iron to medium high and brush both plates with melted butter until well coated.","timer":180},{"title":"Cook the Waffles","text":"Pour about half a cup of batter onto the waffle iron and cook for 4 to 5 minutes until golden and crispy. The waffle should release easily when done.","timer":300},{"title":"Serve with Spicy Honey Butter","text":"Stack the cornbread waffles on a plate and drizzle generously with the spicy honey butter. Serve immediately while hot.","timer":0}]','[{"original":"buttermilk","swap":"whole milk mixed with one tablespoon of white vinegar"},{"original":"cayenne pepper","swap":"hot sauce stirred into the honey butter"},{"original":"honey","swap":"maple syrup for a different sweetness"}]','["Overmixing the batter develops too much gluten and makes the waffles dense and chewy","Not preheating the waffle iron long enough results in pale and undercooked waffles","Using too much batter causes overflow and makes a mess on the waffle iron"]','["brunch","waffles","cornbread","spicy","southern","honey butter","comfort food"]','["vegetarian"]','Brunch','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Brown Butter Banana Pancakes','brown-butter-banana-pancakes','Fluffy banana pancakes made with nutty brown butter for a rich depth of flavor that regular pancakes simply cannot match. Ripe bananas add natural sweetness and moisture to every bite.','Ripe banana pancakes elevated with nutty brown butter for a deeply flavorful breakfast stack.','American','Medium',10,20,30,4,390,10,56,15,3,'[{"amount":4,"unit":"tablespoons","item":"unsalted butter","group":"brown butter"},{"amount":2,"unit":"medium","item":"very ripe bananas mashed","group":"batter"},{"amount":1.5,"unit":"cups","item":"all purpose flour","group":"batter"},{"amount":1,"unit":"cup","item":"whole milk","group":"batter"},{"amount":2,"unit":"large","item":"eggs","group":"batter"},{"amount":2,"unit":"teaspoons","item":"baking powder","group":"batter"},{"amount":2,"unit":"tablespoons","item":"brown sugar","group":"batter"},{"amount":1,"unit":"teaspoon","item":"vanilla extract","group":"batter"}]','[{"title":"Brown the Butter","text":"Melt butter in a light colored saucepan over medium heat swirling constantly. Cook until the butter turns golden amber and smells nutty with brown bits on the bottom. Remove from heat immediately and let cool slightly.","timer":300},{"title":"Mix the Batter","text":"In a large bowl mash the bananas until smooth then whisk in eggs milk brown sugar vanilla extract and the cooled brown butter. Add flour and baking powder and stir until just combined with small lumps remaining.","timer":0},{"title":"Rest the Batter","text":"Let the batter rest for 5 minutes so the baking powder activates and the flour hydrates fully. Do not skip this step or your pancakes will be less fluffy.","timer":300},{"title":"Cook the Pancakes","text":"Heat a nonstick skillet or griddle over medium heat. Pour a quarter cup of batter per pancake and cook for 2 to 3 minutes until bubbles form on the surface and the edges look set. Flip and cook for 1 to 2 more minutes.","timer":180},{"title":"Serve Immediately","text":"Stack the pancakes and serve with sliced bananas maple syrup and a drizzle of extra brown butter if desired.","timer":0}]','[{"original":"whole milk","swap":"almond milk or oat milk"},{"original":"all purpose flour","swap":"white whole wheat flour for added fiber"},{"original":"brown sugar","swap":"coconut sugar or regular granulated sugar"}]','["Burning the butter past golden brown makes it taste bitter instead of nutty","Overmixing the batter creates tough and flat pancakes instead of fluffy ones","Flipping the pancakes before bubbles form on the surface results in uncooked centers"]','["breakfast","pancakes","banana","brown butter","fluffy","weekend brunch"]','["vegetarian"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Croissant Breakfast Boats','croissant-breakfast-boats','Buttery croissants hollowed out and filled with eggs, cheese, and savory toppings. A stunning breakfast that looks impressive but comes together in minutes.','Egg and cheese filled croissant boats baked until golden and set.','American','Easy',10,20,30,4,420,18,28,26,1,'[{"amount":4,"unit":"large","item":"croissants","group":"base"},{"amount":6,"unit":"large","item":"eggs","group":"filling"},{"amount":1,"unit":"cup","item":"shredded cheddar cheese","group":"filling"},{"amount":4,"unit":"strips","item":"cooked bacon chopped","group":"filling"},{"amount":2,"unit":"tablespoons","item":"heavy cream","group":"filling"},{"amount":0.25,"unit":"cup","item":"diced bell pepper","group":"filling"},{"amount":0.5,"unit":"teaspoon","item":"garlic powder","group":"seasoning"},{"amount":0.5,"unit":"teaspoon","item":"black pepper","group":"seasoning"}]','[{"title":"Preheat and prep croissants","text":"Preheat oven to 375 degrees F. Slice each croissant lengthwise across the top to create a deep pocket. Gently press down the insides to form a boat shape without tearing through the bottom.","timer":0},{"title":"Make the egg mixture","text":"Whisk together eggs and heavy cream in a bowl. Season with garlic powder and black pepper. Stir in half of the shredded cheddar cheese.","timer":0},{"title":"Fill the boats","text":"Place croissants on a lined baking sheet. Distribute the chopped bacon and diced bell pepper evenly into each croissant. Pour the egg mixture carefully into each boat filling nearly to the top.","timer":0},{"title":"Add cheese and bake","text":"Sprinkle the remaining cheddar cheese over each filled croissant. Bake in the preheated oven for 18 to 20 minutes until the eggs are fully set and the cheese is bubbly and golden.","timer":1200},{"title":"Rest and serve","text":"Remove from the oven and let the croissant boats rest for 2 minutes before serving. Serve immediately while warm and the cheese is still melty.","timer":120}]','[{"original":"bacon","swap":"cooked breakfast sausage crumbles"},{"original":"cheddar cheese","swap":"gruyere or pepper jack cheese"},{"original":"bell pepper","swap":"diced jalapeno or sun dried tomatoes"}]','["Overfilling the croissants causes the egg mixture to spill and burn on the pan","Using cold eggs straight from the fridge leads to uneven cooking","Not pressing down the inside of the croissant enough so the filling has no room to set"]','["breakfast","eggs","croissant","baked","brunch","easy morning","cheese"]','["nut-free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Birria Eggs Benedict','birria-eggs-benedict','A bold fusion of Mexican birria braised beef and classic eggs benedict topped with rich consomme hollandaise. This brunch showstopper combines two beloved dishes into one unforgettable plate.','Slow braised birria beef topped with poached eggs and a smoky consomme hollandaise.','Mexican-American Fusion','Hard',30,180,210,4,680,42,32,44,3,'[{"amount":1.5,"unit":"lbs","item":"beef chuck roast","group":"birria"},{"amount":3,"unit":"whole","item":"dried guajillo chiles stemmed and seeded","group":"birria"},{"amount":2,"unit":"whole","item":"dried ancho chiles stemmed and seeded","group":"birria"},{"amount":4,"unit":"large","item":"eggs","group":"eggs"},{"amount":3,"unit":"large","item":"egg yolks","group":"hollandaise"},{"amount":0.5,"unit":"cup","item":"unsalted butter melted","group":"hollandaise"},{"amount":4,"unit":"whole","item":"brioche buns toasted","group":"base"},{"amount":2,"unit":"tablespoons","item":"white vinegar","group":"poaching"},{"amount":0.5,"unit":"cup","item":"reserved birria consomme","group":"hollandaise"},{"amount":1,"unit":"teaspoon","item":"smoked paprika","group":"seasoning"}]','[{"title":"Braise the birria beef","text":"Toast dried chiles in a dry skillet for 1 minute per side then rehydrate in hot water for 15 minutes. Blend chiles with 1 cup water into a smooth paste. Sear the beef chuck in a Dutch oven until browned on all sides then add the chile paste and enough water to cover. Braise covered at 325 degrees F for 3 hours until the beef is fall apart tender. Reserve the consomme liquid.","timer":10800},{"title":"Shred the beef","text":"Remove the braised beef from the Dutch oven and shred it using two forks. Toss the shredded beef with a ladle of the reserved consomme to keep it moist and flavorful. Season with smoked paprika and additional salt if needed.","timer":0},{"title":"Make consomme hollandaise","text":"Whisk egg yolks with 2 tablespoons of warm birria consomme in a heatproof bowl over a pot of barely simmering water. Whisk constantly until the mixture thickens and doubles in volume. Remove from heat and slowly drizzle in the melted butter while whisking continuously until a thick and glossy sauce forms.","timer":0},{"title":"Poach the eggs","text":"Fill a wide saucepan with 3 inches of water and add white vinegar. Bring to a gentle simmer. Crack each egg into a small cup then slide them one at a time into the simmering water. Poach for exactly 3 minutes for a runny yolk. Remove with a slotted spoon and drain on paper towels.","timer":180},{"title":"Assemble and serve","text":"Place toasted brioche bun halves on plates. Top each with a generous portion of shredded birria beef followed by a poached egg. Spoon the consomme hollandaise liberally over each egg. Serve with a small bowl of extra consomme on the side for dipping.","timer":0}]','[{"original":"beef chuck roast","swap":"bone in short ribs for richer flavor"},{"original":"brioche buns","swap":"toasted bolillo rolls or English muffins"},{"original":"guajillo chiles","swap":"dried New Mexico chiles for a milder version"}]','["Skipping the chile toasting step which removes the deep smoky flavor from the birria","Adding butter too quickly to the hollandaise causing it to break and become greasy","Poaching eggs in water that is boiling too vigorously which tears apart the egg whites"]','["brunch","birria","eggs benedict","fusion","Mexican","poached eggs","hollandaise","weekend"]','["gluten-free optional"]','Brunch','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Hot Honey Chicken Biscuit Sliders','hot-honey-chicken-biscuit-sliders','Crispy fried chicken thighs nestled in fluffy homemade biscuits and drizzled with fiery hot honey. These sliders balance sweet heat and buttery richness in every single bite.','Crunchy fried chicken sliders on buttermilk biscuits with a spicy honey drizzle.','Southern American','Medium',25,25,50,6,520,28,48,24,2,'[{"amount":6,"unit":"small","item":"boneless skinless chicken thighs","group":"chicken"},{"amount":1,"unit":"cup","item":"buttermilk","group":"marinade"},{"amount":1.5,"unit":"cups","item":"all purpose flour","group":"breading"},{"amount":1,"unit":"teaspoon","item":"cayenne pepper","group":"breading"},{"amount":0.5,"unit":"cup","item":"honey","group":"hot honey"},{"amount":2,"unit":"teaspoons","item":"red pepper flakes","group":"hot honey"},{"amount":6,"unit":"whole","item":"store bought or homemade buttermilk biscuits","group":"base"},{"amount":2,"unit":"cups","item":"vegetable oil for frying","group":"frying"},{"amount":1,"unit":"teaspoon","item":"garlic powder","group":"breading"},{"amount":0.5,"unit":"teaspoon","item":"smoked paprika","group":"breading"}]','[{"title":"Marinate the chicken","text":"Place chicken thighs in a bowl and pour buttermilk over them ensuring every piece is fully submerged. Cover and refrigerate for at least 30 minutes or up to overnight. The buttermilk tenderizes the chicken and helps the breading adhere perfectly.","timer":1800},{"title":"Make the hot honey","text":"Combine honey and red pepper flakes in a small saucepan over low heat. Warm gently for 5 minutes stirring occasionally until the honey is infused with heat. Do not let it boil. Set aside to cool slightly.","timer":300},{"title":"Bread the chicken","text":"Mix flour with cayenne pepper garlic powder smoked paprika and 1 teaspoon salt in a shallow dish. Remove each chicken thigh from the buttermilk letting excess drip off then dredge thoroughly in the seasoned flour pressing firmly so the coating adheres on all sides.","timer":0},{"title":"Fry the chicken","text":"Heat vegetable oil in a heavy skillet to 350 degrees F. Fry the breaded chicken thighs in batches for 5 to 6 minutes per side until the internal temperature reaches 165 degrees F and the crust is deep golden brown. Transfer to a wire rack to drain and rest.","timer":720},{"title":"Assemble the sliders","text":"Split each biscuit in half. Place a fried chicken thigh on the bottom half of each biscuit. Drizzle a generous amount of warm hot honey directly over the chicken. Add the biscuit top and serve immediately while the chicken is still crispy.","timer":0}]','[{"original":"chicken thighs","swap":"chicken breast cutlets pounded thin for faster cooking"},{"original":"buttermilk","swap":"whole milk mixed with 1 tablespoon apple cider vinegar"},{"original":"vegetable oil","swap":"peanut oil for a higher smoke point and cleaner fry"}]','["Not pressing the flour breading firmly enough onto the chicken causing it to fall off during frying","Frying at too low a temperature which results in greasy soggy chicken instead of a crispy crust","Assembling the sliders too far in advance so the biscuit becomes soggy from the hot honey"]','["sliders","fried chicken","hot honey","biscuits","Southern","spicy","brunch","game day"]','["dairy-free optional"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Shakshuka with Feta and Herbs','shakshuka-with-feta-and-herbs','Eggs poached directly in a spiced tomato and pepper sauce then crowned with creamy feta and fresh herbs. This North African classic is a one pan wonder that feeds a crowd effortlessly.','Spiced tomato braised eggs finished with crumbled feta and fresh parsley.','North African','Easy',10,25,35,4,310,16,22,18,5,'[{"amount":6,"unit":"large","item":"eggs","group":"eggs"},{"amount":1,"unit":"can","item":"crushed tomatoes 28 oz","group":"sauce"},{"amount":1,"unit":"large","item":"red bell pepper diced","group":"sauce"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"sauce"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":2,"unit":"teaspoons","item":"ground cumin","group":"spices"},{"amount":1,"unit":"teaspoon","item":"smoked paprika","group":"spices"},{"amount":0.5,"unit":"cup","item":"crumbled feta cheese","group":"topping"},{"amount":0.25,"unit":"cup","item":"fresh parsley chopped","group":"topping"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"cooking"}]','[{"title":"Saute the vegetables","text":"Heat olive oil in a large oven safe skillet over medium heat. Add the diced onion and bell pepper and cook for 6 to 7 minutes until softened and lightly caramelized. Add the minced garlic and cook for 1 more minute until fragrant.","timer":420},{"title":"Build the tomato sauce","text":"Add cumin and smoked paprika to the softened vegetables and stir for 30 seconds to toast the spices. Pour in the crushed tomatoes and stir to combine. Season generously with salt and black pepper. Simmer the sauce uncovered for 10 minutes until it thickens slightly.","timer":600},{"title":"Add the eggs","text":"Use a spoon to create 6 small wells in the tomato sauce. Crack one egg carefully into each well. Do not stir the sauce after adding the eggs or the yolks will break.","timer":0},{"title":"Cover and cook eggs","text":"Cover the skillet with a lid and cook over medium low heat for 8 to 10 minutes. Check after 8 minutes. The whites should be fully set while the yolks remain jammy and slightly runny. Remove from heat immediately to prevent overcooking.","timer":540},{"title":"Garnish and serve","text":"Scatter crumbled feta cheese and fresh chopped parsley generously over the top of the shakshuka. Serve directly from the skillet at the table with warm crusty bread or pita for dipping into the rich sauce.","timer":0}]','[{"original":"feta cheese","swap":"goat cheese for a creamier and tangier topping"},{"original":"crushed tomatoes","swap":"fresh ripe tomatoes blended smooth during summer"},{"original":"red bell pepper","swap":"roasted poblano pepper for a smokier flavor profile"}]','["Cooking the eggs on too high heat which causes rubbery whites before the yolks have time to set","Not seasoning the tomato sauce generously enough before adding the eggs","Stirring the sauce after adding eggs which breaks the yolks and ruins the presentation"]','["shakshuka","eggs","vegetarian","one pan","North African","brunch","tomato","feta"]','["vegetarian","gluten-free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Smash Burger Breakfast Tacos','smash-burger-breakfast-tacos','Crispy smashed beef patties and scrambled eggs wrapped in warm flour tortillas with all the classic burger toppings. This mashup brings diner energy to your morning taco routine.','Smashed beef and egg breakfast tacos loaded with cheese pickles and special sauce.','American-Tex Mex Fusion','Easy',15,15,30,4,580,32,38,34,2,'[{"amount":0.75,"unit":"lbs","item":"80 20 ground beef","group":"burger"},{"amount":4,"unit":"large","item":"eggs","group":"eggs"},{"amount":8,"unit":"small","item":"flour tortillas","group":"base"},{"amount":4,"unit":"slices","item":"American cheese","group":"cheese"},{"amount":0.25,"unit":"cup","item":"mayonnaise","group":"sauce"},{"amount":1,"unit":"tablespoon","item":"yellow mustard","group":"sauce"},{"amount":0.25,"unit":"cup","item":"dill pickle slices","group":"topping"},{"amount":1,"unit":"tablespoon","item":"ketchup","group":"sauce"},{"amount":0.5,"unit":"teaspoon","item":"onion powder","group":"seasoning"}]','[{"title":"Make the special sauce","text":"Whisk together mayonnaise yellow mustard and ketchup in a small bowl until fully combined and smooth. Season with a pinch of onion powder. Set aside in the refrigerator until ready to assemble.","timer":0},{"title":"Smash the beef patties","text":"Divide the ground beef into 8 equal loose balls without packing them too tightly. Heat a cast iron skillet over high heat until smoking. Place a beef ball on the skillet and immediately smash it flat with a heavy spatula. Season with salt and pepper. Cook for 2 minutes until deeply charred on the bottom.","timer":120},{"title":"Add cheese and flip","text":"Flip each smashed patty and immediately place a slice of American cheese over two patties to melt. Cook for 1 more minute then remove from heat. The edges should be crispy and lacy from the high heat smash.","timer":60},{"title":"Scramble the eggs","text":"Reduce the skillet heat to medium low. Whisk eggs with a pinch of salt and pour into the same skillet using the remaining beef fat for flavor. Gently fold the eggs slowly with a spatula creating large soft curds. Remove from heat while still slightly underdone as they will continue cooking.","timer":180},{"title":"Warm tortillas and assemble","text":"Warm flour tortillas directly over a gas flame or in a dry skillet for 30 seconds per side until slightly charred and pliable. Spread special sauce on each tortilla then layer with scrambled eggs one smashed patty and dill pickle slices. Fold and serve immediately.","timer":60}]','[{"original":"flour tortillas","swap":"corn tortillas for a more traditional taco texture"},{"original":"American cheese","swap":"white cheddar or pepper jack cheese"},{"original":"ground beef","swap":"ground turkey for a lighter option with less fat"}]','["Not heating the skillet hot enough before smashing which prevents the crispy crust from forming","Packing the beef balls too tightly before smashing which creates dense patties instead of lacy crispy ones","Overcooking the scrambled eggs in the first pan so they become dry and rubbery by the time the tacos are assembled"]','["breakfast tacos","smash burger","fusion","eggs","beef","quick breakfast","tacos","weekday"]','["nut-free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Pancake Tacos','pancake-tacos','Fluffy pancakes folded into taco shells and filled with scrambled eggs, crispy bacon, and maple syrup drizzle. A fun breakfast mashup that brings together sweet and savory flavors in one handheld bite.','Fluffy pancake shells loaded with eggs and bacon for the ultimate breakfast taco.','American Fusion','Easy',10,20,30,4,420,18,48,18,2,'[{"amount":1.5,"unit":"cups","item":"all purpose flour","group":"pancake batter"},{"amount":2,"unit":"tsp","item":"baking powder","group":"pancake batter"},{"amount":1,"unit":"cup","item":"whole milk","group":"pancake batter"},{"amount":2,"unit":"whole","item":"eggs","group":"pancake batter"},{"amount":2,"unit":"tbsp","item":"melted butter","group":"pancake batter"},{"amount":6,"unit":"strips","item":"bacon","group":"filling"},{"amount":4,"unit":"whole","item":"eggs","group":"filling"},{"amount":3,"unit":"tbsp","item":"pure maple syrup","group":"topping"},{"amount":0.5,"unit":"cup","item":"shredded cheddar cheese","group":"filling"}]','[{"title":"Cook the Bacon","text":"Cook bacon strips in a skillet over medium heat until crispy. Transfer to a paper towel lined plate and set aside. Reserve one tablespoon of bacon drippings.","timer":480},{"title":"Make the Pancake Batter","text":"Whisk flour and baking powder together in a bowl. In a separate bowl whisk milk, eggs, and melted butter. Combine wet and dry ingredients until just mixed. Do not over stir the batter.","timer":120},{"title":"Cook the Pancakes","text":"Heat a nonstick skillet over medium heat and lightly grease. Pour 3 inch rounds of batter and cook until bubbles form on the surface. Flip and cook the other side for one more minute.","timer":300},{"title":"Scramble the Eggs","text":"Whisk the filling eggs with a pinch of salt. Cook in the reserved bacon drippings over low heat, stirring gently until soft curds form. Remove from heat while still slightly glossy.","timer":240},{"title":"Assemble the Tacos","text":"Fold each warm pancake into a taco shape. Fill with scrambled eggs, crumbled bacon, and shredded cheddar. Drizzle with maple syrup and serve immediately.","timer":60}]','[{"original":"bacon","swap":"turkey sausage crumbles"},{"original":"whole milk","swap":"oat milk"},{"original":"cheddar cheese","swap":"pepper jack cheese"}]','["Over mixing the batter which creates tough and dense pancakes","Cooking pancakes on heat that is too high causing burnt outsides and raw centers","Filling pancakes too soon before they are warm and pliable causing them to crack"]','["breakfast","brunch","fusion","handheld","savory","sweet"]','["nut-free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Churro Waffles','churro-waffles','Crispy waffles coated in cinnamon sugar with a light and airy interior inspired by classic Spanish churros. Serve with warm chocolate dipping sauce for an indulgent breakfast or dessert.','Crispy cinnamon sugar waffles served with rich chocolate dipping sauce.','Spanish American Fusion','Easy',10,20,30,4,480,8,62,22,2,'[{"amount":2,"unit":"cups","item":"all purpose flour","group":"waffle batter"},{"amount":2,"unit":"tsp","item":"baking powder","group":"waffle batter"},{"amount":1.5,"unit":"cups","item":"whole milk","group":"waffle batter"},{"amount":2,"unit":"whole","item":"eggs","group":"waffle batter"},{"amount":4,"unit":"tbsp","item":"melted unsalted butter","group":"waffle batter"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"coating"},{"amount":0.5,"unit":"cup","item":"granulated sugar","group":"coating"},{"amount":2,"unit":"tsp","item":"ground cinnamon","group":"coating"},{"amount":0.5,"unit":"cup","item":"semi sweet chocolate chips","group":"dipping sauce"}]','[{"title":"Prepare the Batter","text":"Whisk flour and baking powder in a large bowl. Beat eggs and milk together then stir in melted butter. Pour the wet mixture into the dry ingredients and stir until a smooth batter forms. Let the batter rest for five minutes.","timer":300},{"title":"Cook the Waffles","text":"Preheat your waffle iron and grease lightly with cooking spray. Pour batter into the iron and cook according to your appliance instructions until golden and crispy. Do not open the iron too early or the waffle will split.","timer":360},{"title":"Make the Cinnamon Sugar Coating","text":"Mix granulated sugar and cinnamon together in a shallow dish. Melt the remaining butter in a small bowl. Have both ready before the waffles finish cooking.","timer":60},{"title":"Coat the Waffles","text":"While the waffles are still hot, brush each one generously with melted butter. Immediately press both sides into the cinnamon sugar mixture until fully coated. Place on a wire rack.","timer":120},{"title":"Make the Chocolate Sauce and Serve","text":"Melt chocolate chips in a microwave safe bowl in 30 second intervals, stirring between each until smooth. Add two tablespoons of warm cream if a thinner sauce is desired. Serve waffles alongside the warm chocolate dipping sauce.","timer":90}]','[{"original":"semi sweet chocolate chips","swap":"dark chocolate chips for a richer sauce"},{"original":"granulated sugar","swap":"coconut sugar for a caramel like flavor"},{"original":"whole milk","swap":"buttermilk for extra tenderness"}]','["Opening the waffle iron before the waffle is fully set causing it to tear apart","Skipping the butter brush before applying cinnamon sugar so the coating does not stick","Letting the waffles cool before coating so the sugar mixture slides off instead of adhering"]','["waffles","churro","dessert","brunch","cinnamon","chocolate","sweet"]','["vegetarian","nut-free"]','Breakfast and Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Red Velvet Chicken and Waffles','red-velvet-chicken-and-waffles','Deep red cocoa waffles topped with crispy buttermilk fried chicken and a tangy cream cheese glaze. This showstopping brunch dish combines Southern comfort food with a dramatic red velvet twist.','Striking red velvet waffles piled high with crunchy fried chicken and cream cheese drizzle.','Southern American','Hard',30,40,70,4,780,42,72,34,3,'[{"amount":2,"unit":"cups","item":"all purpose flour","group":"waffle batter"},{"amount":2,"unit":"tbsp","item":"unsweetened cocoa powder","group":"waffle batter"},{"amount":2,"unit":"tbsp","item":"red food coloring","group":"waffle batter"},{"amount":1.5,"unit":"cups","item":"buttermilk","group":"waffle batter"},{"amount":4,"unit":"pieces","item":"boneless skinless chicken thighs","group":"chicken"},{"amount":1,"unit":"cup","item":"buttermilk","group":"chicken marinade"},{"amount":1,"unit":"cup","item":"seasoned flour","group":"chicken coating"},{"amount":4,"unit":"oz","item":"cream cheese softened","group":"glaze"},{"amount":1,"unit":"cup","item":"powdered sugar","group":"glaze"}]','[{"title":"Marinate the Chicken","text":"Place chicken thighs in a bowl and cover with one cup of buttermilk. Add one teaspoon each of garlic powder, onion powder, salt, and hot sauce. Cover and refrigerate for at least one hour or overnight for best results.","timer":3600},{"title":"Make the Red Velvet Waffle Batter","text":"Whisk flour, cocoa powder, baking powder, and a pinch of salt in a bowl. In another bowl combine buttermilk, two eggs, melted butter, red food coloring, and a teaspoon of vanilla. Fold wet ingredients into dry until just combined.","timer":180},{"title":"Fry the Chicken","text":"Heat oil in a deep skillet to 350 degrees Fahrenheit. Dredge marinated chicken in seasoned flour and fry for six to eight minutes per side until golden brown and the internal temperature reaches 165 degrees. Drain on a wire rack.","timer":900},{"title":"Cook the Waffles","text":"Preheat and grease the waffle iron. Ladle batter in and cook until the waffles are set and the iron releases steam less actively. The waffles should be deep red with crispy edges. Do not rush this step.","timer":480},{"title":"Make the Glaze and Plate","text":"Beat softened cream cheese and powdered sugar together with two tablespoons of milk until smooth and pourable. Place a waffle on each plate, top with a piece of fried chicken, and drizzle generously with the cream cheese glaze.","timer":120}]','[{"original":"red food coloring","swap":"beet powder for a natural color"},{"original":"chicken thighs","swap":"chicken tenders for faster cooking"},{"original":"cream cheese glaze","swap":"hot honey for a spicy sweet topping"}]','["Skipping the buttermilk marinade which results in dry and bland fried chicken","Frying chicken at the wrong oil temperature causing greasy undercooked or burnt results","Under mixing the red food coloring into the batter leaving streaks in the finished waffles"]','["chicken and waffles","red velvet","southern","brunch","fried chicken","indulgent"]','["nut-free"]','Brunch','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Savory Breakfast Pancake Tacos with Avocado','savory-breakfast-pancake-tacos-avocado','Herb infused savory pancakes serve as the shell for a fresh avocado, egg, and salsa filling. These protein packed breakfast tacos are a wholesome twist on the classic morning meal.','Herbed savory pancake shells filled with creamy avocado and fresh salsa.','American Mexican Fusion','Easy',10,15,25,4,370,16,38,18,6,'[{"amount":1.5,"unit":"cups","item":"all purpose flour","group":"pancake batter"},{"amount":1,"unit":"cup","item":"whole milk","group":"pancake batter"},{"amount":2,"unit":"whole","item":"eggs","group":"pancake batter"},{"amount":2,"unit":"tbsp","item":"chopped fresh chives","group":"pancake batter"},{"amount":0.5,"unit":"tsp","item":"garlic powder","group":"pancake batter"},{"amount":2,"unit":"whole","item":"ripe avocados","group":"filling"},{"amount":4,"unit":"whole","item":"eggs","group":"filling"},{"amount":0.5,"unit":"cup","item":"fresh pico de gallo","group":"filling"},{"amount":1,"unit":"tbsp","item":"fresh lime juice","group":"filling"}]','[{"title":"Prepare the Savory Batter","text":"Combine flour, a pinch of salt, garlic powder, and baking powder in a bowl. Whisk eggs and milk in another bowl then combine with dry ingredients. Fold in the fresh chives. Let the batter rest for five minutes before cooking.","timer":300},{"title":"Cook the Pancake Shells","text":"Heat a nonstick skillet over medium heat and coat with cooking spray. Pour 4 inch rounds and cook until bubbles form and edges look dry. Flip and cook for another sixty seconds. Keep warm wrapped in a towel.","timer":360},{"title":"Mash the Avocado","text":"Halve and pit the avocados and scoop the flesh into a bowl. Add lime juice and a pinch of salt and mash to a chunky consistency. Do not over mash as the texture adds to the taco experience.","timer":90},{"title":"Cook the Eggs","text":"Cook the filling eggs to your preferred style. Soft scrambled or fried sunny side up both work well in these tacos. Season with salt and pepper and cook in a lightly greased pan over medium low heat.","timer":240},{"title":"Assemble and Serve","text":"Fold warm pancakes into taco shapes and hold them with your hand or prop in a taco stand. Spread a layer of mashed avocado on the inside, add the egg, and top with fresh pico de gallo. Serve immediately.","timer":60}]','[{"original":"pico de gallo","swap":"store bought mild salsa for convenience"},{"original":"fresh chives","swap":"dried dill or parsley"},{"original":"whole milk","swap":"unsweetened almond milk"}]','["Making pancakes too thick which prevents them from folding without cracking","Preparing avocado too far in advance causing it to brown before serving","Cooking eggs on high heat which makes them rubbery and dry"]','["savory","avocado","breakfast tacos","brunch","fusion","healthy"]','["vegetarian","nut-free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cinnamon Roll Pancake Tacos','cinnamon-roll-pancake-tacos','Swirled cinnamon sugar pancakes are folded into taco shells and filled with sweetened cream cheese and fresh berries. This dessert inspired breakfast is a showstopper for weekend brunch.','Cinnamon swirl pancake shells stuffed with cream cheese filling and fresh berries.','American','Medium',15,20,35,4,510,10,68,22,3,'[{"amount":1.5,"unit":"cups","item":"all purpose flour","group":"pancake batter"},{"amount":1,"unit":"cup","item":"whole milk","group":"pancake batter"},{"amount":2,"unit":"whole","item":"eggs","group":"pancake batter"},{"amount":2,"unit":"tbsp","item":"melted butter","group":"pancake batter"},{"amount":3,"unit":"tbsp","item":"softened butter","group":"cinnamon swirl"},{"amount":3,"unit":"tbsp","item":"brown sugar","group":"cinnamon swirl"},{"amount":2,"unit":"tsp","item":"ground cinnamon","group":"cinnamon swirl"},{"amount":4,"unit":"oz","item":"cream cheese softened","group":"filling"},{"amount":1,"unit":"cup","item":"mixed fresh berries","group":"filling"}]','[{"title":"Make the Cinnamon Swirl Paste","text":"Mix softened butter, brown sugar, and cinnamon together in a small bowl until it forms a smooth paste. Transfer to a small zip lock bag and snip a tiny corner off the end to use as a piping bag.","timer":60},{"title":"Prepare the Pancake Batter","text":"Whisk flour, baking powder, and a pinch of salt together. In another bowl beat eggs, milk, and melted butter. Combine the mixtures and stir until just smooth. Do not over stir or the pancakes will be tough.","timer":120},{"title":"Cook the Cinnamon Swirl Pancakes","text":"Pour 4 inch rounds onto a greased skillet over medium heat. Immediately pipe a spiral of cinnamon paste on top of each raw pancake. When bubbles appear on the surface, flip carefully and cook for one more minute.","timer":360},{"title":"Make the Cream Cheese Filling","text":"Beat softened cream cheese with two tablespoons of powdered sugar and one teaspoon of vanilla extract until smooth and fluffy. Add a splash of milk if the mixture is too thick to spread easily.","timer":90},{"title":"Assemble the Tacos","text":"Fold the warm cinnamon swirl pancakes into taco shells with the swirl on the outside. Spoon a generous dollop of cream cheese filling inside each one and pile in the fresh mixed berries. Dust with powdered sugar and serve.","timer":60}]','[{"original":"cream cheese","swap":"mascarpone for a richer filling"},{"original":"mixed fresh berries","swap":"sliced banana and caramel sauce"},{"original":"brown sugar","swap":"maple sugar for a deeper flavor"}]','["Using too much cinnamon paste which causes the pancakes to burn on the swirl side","Flipping the pancake before it is ready which smears the cinnamon swirl and ruins the pattern","Using cold cream cheese straight from the refrigerator which creates a lumpy filling"]','["cinnamon roll","sweet","brunch","cream cheese","berries","indulgent","dessert breakfast"]','["vegetarian","nut-free"]','Breakfast and Brunch','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Pastrami Crunchwrap','pastrami-crunchwrap','A deli-inspired crunchwrap stuffed with savory pastrami, Swiss cheese, and tangy mustard aioli. Crispy on the outside and packed with bold flavors inside.','A griddle-pressed crunchwrap loaded with pastrami and Swiss for a deli-meets-Tex-Mex mashup.','American Fusion','Medium',15,10,25,2,720,38,58,36,3,'[{"amount":2,"unit":"large","item":"flour tortillas","group":"wrap"},{"amount":2,"unit":"small","item":"tostada shells","group":"wrap"},{"amount":6,"unit":"oz","item":"sliced pastrami","group":"filling"},{"amount":4,"unit":"slices","item":"Swiss cheese","group":"filling"},{"amount":0.5,"unit":"cup","item":"sauerkraut","group":"filling"},{"amount":3,"unit":"tbsp","item":"Dijon mustard","group":"sauce"},{"amount":2,"unit":"tbsp","item":"mayonnaise","group":"sauce"},{"amount":1,"unit":"tbsp","item":"butter","group":"cooking"}]','[{"title":"Make the Mustard Aioli","text":"In a small bowl, whisk together the Dijon mustard and mayonnaise until fully combined. Set aside.","timer":60},{"title":"Warm the Pastrami","text":"In a skillet over medium heat, warm the pastrami slices for 2 minutes until heated through and slightly caramelized on the edges.","timer":120},{"title":"Assemble the Crunchwrap","text":"Lay a large flour tortilla flat. Spread mustard aioli in the center, layer with Swiss cheese, warm pastrami, sauerkraut, and place a tostada shell on top. Fold the edges of the tortilla up and over the tostada, pleating as you go to seal.","timer":180},{"title":"Griddle the Crunchwrap","text":"Melt butter in a large skillet over medium heat. Place the crunchwrap seam-side down and press gently with a spatula. Cook for 3 minutes per side until golden brown and crispy.","timer":360},{"title":"Slice and Serve","text":"Remove from heat, let rest for one minute, then slice in half diagonally and serve immediately.","timer":60}]','[{"original":"pastrami","swap":"corned beef"},{"original":"Swiss cheese","swap":"provolone cheese"},{"original":"sauerkraut","swap":"pickled red onions"}]','["Using a tortilla that is too small causes the wrap to burst open during griddling","Skipping the press with a spatula results in uneven browning","Adding cold wet sauerkraut without draining it makes the wrap soggy"]','["crunchwrap","pastrami","deli","fusion","griddle","sandwich"]','["dairy-free optional"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Deep Fried Lasagna Bites','deep-fried-lasagna-bites','Crispy golden bites filled with classic lasagna layers of ricotta, meat sauce, and mozzarella. A fun party snack that delivers all the comfort of lasagna in one crunchy bite.','Bite-sized fried pockets of lasagna filling encased in a crispy panko crust.','Italian American','Hard',30,20,50,4,540,28,46,28,2,'[{"amount":6,"unit":"sheets","item":"lasagna noodles cooked and cooled","group":"base"},{"amount":1,"unit":"cup","item":"whole milk ricotta cheese","group":"filling"},{"amount":1,"unit":"cup","item":"shredded mozzarella cheese","group":"filling"},{"amount":1,"unit":"cup","item":"ground beef meat sauce","group":"filling"},{"amount":2,"unit":"large","item":"eggs beaten","group":"breading"},{"amount":1,"unit":"cup","item":"panko breadcrumbs","group":"breading"},{"amount":0.5,"unit":"cup","item":"all purpose flour","group":"breading"},{"amount":4,"unit":"cups","item":"vegetable oil for frying","group":"cooking"}]','[{"title":"Prepare the Filling","text":"In a bowl, mix ricotta, mozzarella, and meat sauce until combined. Spread a thin layer of filling onto each cooked lasagna noodle, then roll tightly into a log. Refrigerate for 15 minutes to firm up.","timer":900},{"title":"Cut into Bites","text":"Remove the chilled lasagna rolls from the refrigerator and cut each roll into 1.5 inch pieces. Press the ends gently to seal the filling inside each bite.","timer":120},{"title":"Set Up Breading Station","text":"Arrange three shallow bowls with flour, beaten eggs, and panko breadcrumbs. Dredge each lasagna bite in flour first, then dip in egg, then coat thoroughly in panko, pressing gently to adhere.","timer":300},{"title":"Fry the Bites","text":"Heat vegetable oil to 350 degrees Fahrenheit in a deep pot. Fry the breaded bites in batches of 4 to 5 for 3 to 4 minutes until deep golden brown. Do not overcrowd the pot. Drain on paper towels.","timer":240},{"title":"Serve Hot","text":"Sprinkle with grated Parmesan and serve immediately alongside warm marinara sauce for dipping.","timer":30}]','[{"original":"ground beef meat sauce","swap":"Italian sausage crumbles"},{"original":"panko breadcrumbs","swap":"crushed seasoned crackers"},{"original":"ricotta cheese","swap":"cottage cheese drained"}]','["Skipping the refrigeration step causes the rolls to fall apart when cutting","Frying at too low a temperature makes the bites greasy instead of crispy","Overfilling the lasagna noodles causes the filling to burst out during frying"]','["lasagna","fried","party snack","appetizer","Italian","comfort food"]','[]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('General Tso Chicken Pizza','general-tso-chicken-pizza','A bold fusion pizza topped with crispy General Tso chicken, hoisin glaze, and mozzarella on a golden crust. Sweet, spicy, and savory flavors combine for an unforgettable pizza night.','Crispy sweet and spicy General Tso chicken piled high on a cheesy pizza crust.','Asian American Fusion','Medium',20,25,45,4,680,35,72,24,3,'[{"amount":1,"unit":"lb","item":"pizza dough store bought or homemade","group":"base"},{"amount":1,"unit":"lb","item":"boneless skinless chicken thighs cut into chunks","group":"topping"},{"amount":0.5,"unit":"cup","item":"cornstarch","group":"chicken coating"},{"amount":0.5,"unit":"cup","item":"General Tso sauce","group":"sauce"},{"amount":2,"unit":"tbsp","item":"hoisin sauce","group":"sauce"},{"amount":1.5,"unit":"cups","item":"shredded mozzarella cheese","group":"topping"},{"amount":3,"unit":"stalks","item":"scallions thinly sliced","group":"garnish"},{"amount":1,"unit":"tsp","item":"red chili flakes","group":"garnish"}]','[{"title":"Fry the Chicken","text":"Toss chicken chunks in cornstarch until fully coated. Shallow fry in 1 inch of hot oil over medium high heat for 5 to 6 minutes until golden and cooked through. Drain on paper towels.","timer":360},{"title":"Sauce the Chicken","text":"Toss the fried chicken in General Tso sauce until fully coated. Set aside. The chicken should be glossy and sticky.","timer":60},{"title":"Prepare the Pizza Base","text":"Preheat oven to 475 degrees Fahrenheit. Stretch pizza dough onto a greased baking sheet or pizza stone. Mix hoisin sauce with 2 tablespoons of General Tso sauce and spread evenly over the dough as the pizza sauce.","timer":120},{"title":"Top and Bake","text":"Scatter mozzarella over the sauce base, then arrange the sauced General Tso chicken evenly on top. Bake for 12 to 14 minutes until the crust is golden and the cheese is bubbly and slightly browned.","timer":840},{"title":"Garnish and Slice","text":"Remove from oven and immediately top with sliced scallions and red chili flakes. Slice into 8 pieces and serve hot.","timer":60}]','[{"original":"chicken thighs","swap":"chicken breast"},{"original":"General Tso sauce","swap":"sweet chili sauce with a dash of soy sauce"},{"original":"mozzarella cheese","swap":"provolone cheese"}]','["Adding too much sauce to the pizza base makes the crust soggy and undercooked","Using un-fried raw chicken on the pizza results in rubbery undercooked chicken","Skipping cornstarch on the chicken means it will not stay crispy after being sauced"]','["pizza","General Tso","fusion","Chinese American","spicy","chicken"]','["dairy-free optional"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Smash Burger Tacos','smash-burger-tacos','Thin crispy smash burger patties folded into soft flour tortillas with all the classic burger fixings. A viral mashup that delivers double the flavor in half the time.','Crispy smashed beef patties in taco shells loaded with burger sauce and pickles.','American Fusion','Easy',10,10,20,4,560,32,38,30,2,'[{"amount":1,"unit":"lb","item":"80 percent lean ground beef","group":"protein"},{"amount":4,"unit":"small","item":"flour tortillas","group":"base"},{"amount":4,"unit":"slices","item":"American cheese","group":"topping"},{"amount":0.5,"unit":"cup","item":"shredded iceberg lettuce","group":"topping"},{"amount":0.25,"unit":"cup","item":"dill pickle slices","group":"topping"},{"amount":3,"unit":"tbsp","item":"mayonnaise","group":"sauce"},{"amount":2,"unit":"tbsp","item":"ketchup","group":"sauce"},{"amount":1,"unit":"tbsp","item":"yellow mustard","group":"sauce"}]','[{"title":"Make the Burger Sauce","text":"Mix mayonnaise, ketchup, and yellow mustard in a small bowl until smooth. Set aside in the refrigerator until ready to use.","timer":60},{"title":"Portion the Beef","text":"Divide the ground beef into 4 equal balls of about 4 ounces each. Do not overwork the meat. Keep them loose and round.","timer":60},{"title":"Smash and Cook","text":"Heat a cast iron skillet or griddle over high heat until very hot. Place a tortilla flat on the skillet, put a beef ball in the center, and immediately smash flat with a heavy spatula. Cook for 2 minutes until the edges are crispy and browned.","timer":120},{"title":"Melt the Cheese","text":"Flip the tortilla and beef together as one unit. Immediately place a slice of American cheese on top of the beef. Cook for another 90 seconds until the cheese is fully melted and the tortilla is lightly crisped.","timer":90},{"title":"Assemble and Serve","text":"Fold the taco in half, spread burger sauce on the inside, and top with shredded lettuce and pickle slices. Serve immediately while hot and crispy.","timer":30}]','[{"original":"flour tortillas","swap":"corn tortillas"},{"original":"American cheese","swap":"cheddar cheese"},{"original":"ground beef","swap":"ground turkey"}]','["Using a cold pan prevents the beef from getting a proper crust and sear","Smashing the beef before placing it on the tortilla causes it to stick to the spatula","Overworking the beef before portioning makes the patty tough and dense"]','["smash burger","tacos","fusion","beef","quick dinner","viral recipe"]','[]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Butter Cornbread Waffles','honey-butter-cornbread-waffles','Fluffy cornbread batter cooked in a waffle iron for a crispy edged sweet and savory breakfast treat. Drizzled with honey butter and perfect alongside fried chicken or on their own.','Golden crispy cornbread waffles drenched in honey butter for the ultimate sweet savory breakfast.','Southern American','Easy',10,15,25,4,420,9,58,18,2,'[{"amount":1,"unit":"cup","item":"yellow cornmeal","group":"batter"},{"amount":0.5,"unit":"cup","item":"all purpose flour","group":"batter"},{"amount":1,"unit":"cup","item":"buttermilk","group":"batter"},{"amount":2,"unit":"large","item":"eggs","group":"batter"},{"amount":3,"unit":"tbsp","item":"melted butter","group":"batter"},{"amount":2,"unit":"tbsp","item":"honey","group":"batter"},{"amount":1,"unit":"tsp","item":"baking powder","group":"batter"},{"amount":4,"unit":"tbsp","item":"salted butter softened","group":"honey butter"}]','[{"title":"Make the Honey Butter","text":"Beat softened salted butter with 2 tablespoons of honey until smooth and fluffy. Set aside at room temperature.","timer":60},{"title":"Mix the Batter","text":"In a large bowl, whisk together cornmeal, flour, and baking powder. In a separate bowl, whisk buttermilk, eggs, melted butter, and remaining honey. Pour the wet ingredients into the dry and stir until just combined. Do not overmix.","timer":120},{"title":"Preheat the Waffle Iron","text":"Preheat your waffle iron to medium high heat and grease lightly with nonstick spray or butter. Allow it to fully preheat for at least 3 minutes before adding batter.","timer":180},{"title":"Cook the Waffles","text":"Pour enough batter to fill your waffle iron about three quarters full. Close and cook for 4 to 5 minutes until steam stops releasing and the waffle is golden and crispy. Repeat with remaining batter.","timer":300},{"title":"Top and Serve","text":"Serve hot waffles immediately topped with a generous spoonful of honey butter. Optionally drizzle with extra honey and a sprinkle of flaky sea salt.","timer":30}]','[{"original":"buttermilk","swap":"whole milk with 1 tablespoon of white vinegar added"},{"original":"yellow cornmeal","swap":"white cornmeal"},{"original":"salted butter","swap":"unsalted butter with a pinch of sea salt"}]','["Overmixing the batter causes the waffles to become tough and dense instead of fluffy","Opening the waffle iron too early causes the waffle to tear in half","Not fully preheating the iron results in pale soggy waffles that stick to the plates"]','["waffles","cornbread","breakfast","Southern","honey butter","brunch"]','["vegetarian"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Accordion Potatoes','accordion-potatoes','Crispy spiral-cut potatoes roasted until golden and fan-like. A stunning side dish that is as delicious as it looks.','Spiral-cut potatoes roasted to crispy golden perfection with garlic and herbs.','American','Medium',20,45,65,4,280,5,42,11,4,'[{"amount":4,"unit":"large","item":"russet potatoes","group":"main"},{"amount":3,"unit":"tbsp","item":"olive oil","group":"seasoning"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"seasoning"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":1,"unit":"tsp","item":"dried rosemary","group":"seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"garnish"}]','[{"title":"Preheat and Prep","text":"Preheat oven to 425F. Scrub potatoes clean and pat them dry. Place each potato between two wooden chopsticks on a cutting board to act as guides so you do not cut all the way through.","timer":0},{"title":"Cut Accordion Style","text":"Using a sharp knife, make thin slices across each potato at a slight angle about 3mm apart, letting the chopsticks stop the blade. Flip the potato and repeat cuts at the opposite angle to create a crosshatch accordion fan pattern.","timer":0},{"title":"Season the Potatoes","text":"Mix olive oil, minced garlic, smoked paprika, rosemary, salt, and pepper in a small bowl. Gently fan open each potato and use a brush or spoon to work the seasoned oil into every slice and crevice.","timer":0},{"title":"Roast Until Crispy","text":"Place seasoned potatoes on a lined baking sheet. Roast at 425F for 40 to 45 minutes until the edges are deeply golden and crisp. Halfway through cooking, brush any remaining oil mixture over the potatoes again.","timer":2700},{"title":"Garnish and Serve","text":"Remove potatoes from the oven and let rest for 5 minutes. Sprinkle generously with fresh chopped parsley and serve immediately while the edges remain crisp.","timer":300}]','[{"original":"russet potatoes","swap":"Yukon Gold potatoes for a creamier interior"},{"original":"dried rosemary","swap":"dried thyme or Italian seasoning"},{"original":"smoked paprika","swap":"regular paprika or chili powder for extra heat"}]','["Cutting all the way through the potato instead of stopping at the chopstick guides","Skipping the second pass of oil which results in dry and under-seasoned slices","Using potatoes that are too small making the accordion cuts difficult to open"]','["potatoes","roasted","crispy","side dish","accordion","garlic"]','["vegan","gluten-free","dairy-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Elote Corn Ribs','elote-corn-ribs','Corn cut into long rib-like strips and grilled until they curl and char beautifully. Finished with classic Mexican street corn toppings for bold flavor.','Grilled corn rib strips loaded with creamy cotija and chili lime seasoning.','Mexican','Medium',15,20,35,4,310,8,38,16,4,'[{"amount":4,"unit":"ears","item":"fresh corn husked","group":"main"},{"amount":3,"unit":"tbsp","item":"olive oil","group":"seasoning"},{"amount":1,"unit":"tsp","item":"chili powder","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"cumin","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"cup","item":"Mexican crema or sour cream","group":"topping"},{"amount":0.5,"unit":"cup","item":"cotija cheese crumbled","group":"topping"},{"amount":2,"unit":"whole","item":"limes cut into wedges","group":"topping"}]','[{"title":"Cut the Corn Ribs","text":"Stand each ear of corn upright on a stable cutting board. Using a large heavy knife, carefully cut each cob in half lengthwise, then cut each half into two more strips lengthwise so you have 4 long rib strips per cob. Work slowly and apply steady downward pressure.","timer":0},{"title":"Season the Ribs","text":"In a large bowl combine olive oil, chili powder, cumin, and salt. Add all corn rib strips and toss thoroughly so every surface is well coated in the spiced oil mixture.","timer":0},{"title":"Grill the Corn Ribs","text":"Preheat grill or grill pan to medium-high heat. Place corn ribs cut side down on the grates. Grill for 8 to 10 minutes per side until the edges char and the ribs begin to curl upward. Do not move them too often so they develop proper grill marks.","timer":1200},{"title":"Add the Elote Toppings","text":"Transfer grilled corn ribs to a serving platter. While still hot, brush or drizzle generously with Mexican crema. Sprinkle crumbled cotija cheese over the top and dust with an extra pinch of chili powder.","timer":0},{"title":"Finish and Serve","text":"Squeeze fresh lime juice over all the corn ribs just before serving. Arrange extra lime wedges on the platter for guests to add more to taste. Serve immediately while warm.","timer":0}]','[{"original":"cotija cheese","swap":"feta cheese for a similar salty crumbly texture"},{"original":"Mexican crema","swap":"mayonnaise blended with a squeeze of lime juice"},{"original":"fresh corn","swap":"frozen corn cobs thawed completely before cutting"}]','["Using a dull knife when cutting corn which makes the ribs uneven and dangerous","Not oiling the grill grates causing the corn to stick and tear","Adding the crema too early before removing from heat which causes it to melt off"]','["corn","elote","grilled","mexican","street food","summer","vegetarian"]','["vegetarian","gluten-free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Fried Pickle Dippers','fried-pickle-dippers','Crispy golden fried pickle slices with a seasoned cornmeal and flour coating. Served with a tangy ranch dipping sauce for the ultimate snack.','Crunchy beer-battered dill pickle slices fried golden and served with creamy ranch.','American','Easy',15,15,30,4,340,7,44,16,2,'[{"amount":2,"unit":"cups","item":"dill pickle slices drained and patted dry","group":"main"},{"amount":1,"unit":"cup","item":"all-purpose flour","group":"batter"},{"amount":0.5,"unit":"cup","item":"cornmeal","group":"batter"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"batter"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"batter"},{"amount":1,"unit":"cup","item":"buttermilk","group":"batter"},{"amount":4,"unit":"cups","item":"vegetable oil for frying","group":"cooking"},{"amount":0.5,"unit":"cup","item":"ranch dressing for dipping","group":"serving"}]','[{"title":"Dry the Pickles","text":"Drain pickle slices thoroughly and spread them in a single layer on paper towels. Press more paper towels on top and let them dry for at least 10 minutes. Moisture is the enemy of crispy batter so do not skip this step.","timer":600},{"title":"Prepare the Breading Station","text":"In one shallow bowl pour the buttermilk. In a second shallow bowl whisk together flour, cornmeal, garlic powder, smoked paprika, and a pinch of salt and pepper. Having both bowls ready before frying keeps the process smooth and fast.","timer":0},{"title":"Heat the Oil","text":"Pour vegetable oil into a heavy pot or deep skillet to a depth of about 2 inches. Heat over medium-high until the oil reaches 375F. Use a thermometer for accuracy. Oil that is too cool will make the pickles greasy rather than crispy.","timer":300},{"title":"Batter and Fry the Pickles","text":"Dip each pickle slice in buttermilk letting excess drip off, then dredge in the flour and cornmeal mixture pressing gently so the coating adheres. Fry in batches of 8 to 10 slices for 2 to 3 minutes per side until deep golden brown. Do not overcrowd the pot.","timer":180},{"title":"Drain and Serve","text":"Transfer fried pickles to a wire rack or paper towel lined plate. Season immediately with a pinch of extra salt while still hot. Serve right away alongside ranch dressing for dipping.","timer":0}]','[{"original":"buttermilk","swap":"regular milk mixed with 1 tbsp white vinegar left to sit for 5 minutes"},{"original":"cornmeal","swap":"panko breadcrumbs for a lighter crunchier coating"},{"original":"ranch dressing","swap":"remoulade sauce or spicy chipotle mayo"}]','["Not drying the pickles properly which causes the batter to slide off during frying","Overcrowding the oil which drops the temperature and results in soggy greasy pickles","Frying at too low a temperature causing the batter to absorb excess oil before crisping"]','["fried pickles","appetizer","snack","southern","game day","comfort food"]','["vegetarian"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Garlic Butter Accordion Potatoes','garlic-butter-accordion-potatoes','Butter-basted accordion potatoes with sharp parmesan tucked into every fold. These indulgent spuds make a perfect dinner party showstopper.','Accordion potatoes loaded with garlic butter and melted parmesan for rich flavor.','American','Medium',25,50,75,4,360,9,44,17,4,'[{"amount":4,"unit":"large","item":"russet potatoes","group":"main"},{"amount":4,"unit":"tbsp","item":"unsalted butter melted","group":"seasoning"},{"amount":5,"unit":"cloves","item":"garlic minced","group":"seasoning"},{"amount":0.5,"unit":"cup","item":"grated parmesan cheese","group":"topping"},{"amount":1,"unit":"tsp","item":"onion powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh chives chopped","group":"garnish"}]','[{"title":"Prep and Preheat","text":"Preheat oven to 425F. Wash and dry each potato. Place a potato between two chopsticks lengthwise on the cutting board so the chopsticks prevent the knife from cutting all the way through the base.","timer":0},{"title":"Score the Accordions","text":"Slice each potato crosswise at 3mm intervals all the way down using the chopsticks as guides. Then rotate the potato 45 degrees and slice again crosswise creating a diamond crosshatch pattern. Gently fan the slices open slightly.","timer":0},{"title":"Apply Garlic Butter","text":"Whisk together melted butter, minced garlic, onion powder, salt, and pepper. Using a pastry brush work this mixture thoroughly into every cut and crevice of each potato. Reserve half the butter mixture for a second coat.","timer":0},{"title":"Roast and Baste","text":"Place potatoes on a foil-lined baking sheet and roast at 425F for 30 minutes. Pull them out and brush with remaining garlic butter then pack parmesan into the open slices. Return to oven and roast another 20 minutes until edges are deeply golden and cheese is crispy.","timer":3000},{"title":"Garnish and Plate","text":"Remove from oven and let rest 5 minutes. Scatter fresh chives over the top and add a final pinch of flaky salt. Serve on a warm plate immediately while the parmesan edges remain crisp.","timer":300}]','[{"original":"parmesan cheese","swap":"pecorino romano or aged asiago for similar saltiness"},{"original":"unsalted butter","swap":"ghee for a nuttier richer flavor"},{"original":"fresh chives","swap":"green onion tops or fresh dill"}]','["Packing in the parmesan too early before the initial roast causes it to burn","Not fanning the slices open before roasting which traps steam and prevents crispiness","Using small potatoes that collapse during the accordion cutting process"]','["potatoes","garlic butter","parmesan","roasted","side dish","dinner party"]','["vegetarian","gluten-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Spicy Elote Corn Ribs with Tajin','spicy-elote-corn-ribs-tajin','Oven-roasted corn ribs dusted with Tajin and finished with a cooling avocado crema. Bold heat and creamy richness in every bite.','Tajin-spiced oven corn ribs topped with silky avocado crema and fresh cilantro.','Mexican','Medium',20,25,45,4,295,6,36,16,6,'[{"amount":4,"unit":"ears","item":"fresh corn husked","group":"main"},{"amount":3,"unit":"tbsp","item":"avocado oil","group":"seasoning"},{"amount":2,"unit":"tsp","item":"Tajin seasoning","group":"seasoning"},{"amount":1,"unit":"tsp","item":"chipotle chili powder","group":"seasoning"},{"amount":1,"unit":"large","item":"ripe avocado","group":"crema"},{"amount":0.25,"unit":"cup","item":"sour cream","group":"crema"},{"amount":1,"unit":"whole","item":"lime juiced","group":"crema"},{"amount":0.25,"unit":"cup","item":"fresh cilantro chopped","group":"garnish"}]','[{"title":"Cut Corn into Ribs","text":"Stand each ear upright and use a large sharp knife to halve it lengthwise through the cob. Cut each half in half again lengthwise to yield 4 long rib strips per cob. Work carefully with steady pressure as cutting through the cob requires force.","timer":0},{"title":"Season and Coat","text":"Preheat oven to 450F. In a large bowl toss corn rib strips with avocado oil, Tajin, chipotle chili powder, and a pinch of salt until every surface is evenly coated. Arrange in a single layer on a large baking sheet without overlapping.","timer":0},{"title":"Roast Until Curled","text":"Roast corn ribs at 450F for 20 to 25 minutes flipping once at the halfway point. The ribs are done when the kernels are tender and lightly charred and the strips have begun to curl and bow from the heat.","timer":1500},{"title":"Make the Avocado Crema","text":"While the corn roasts blend the ripe avocado, sour cream, lime juice, and a pinch of salt in a blender or food processor until completely smooth and creamy. Taste and adjust lime and salt as needed. Transfer to a squeeze bottle or small bowl.","timer":0},{"title":"Plate and Top","text":"Arrange hot corn ribs on a serving platter. Drizzle avocado crema generously over the top. Dust with an extra sprinkle of Tajin and finish with fresh chopped cilantro. Serve immediately with extra lime wedges.","timer":0}]','[{"original":"Tajin seasoning","swap":"a mix of chili powder, lime zest, and a pinch of salt"},{"original":"avocado crema","swap":"store-bought guacamole thinned with sour cream"},{"original":"avocado oil","swap":"olive oil or melted coconut oil"}]','["Roasting at too low a temperature which steams the corn instead of charring it","Overlapping the corn ribs on the baking sheet causing uneven cooking and no char","Making the avocado crema too far ahead which causes it to oxidize and turn brown"]','["corn ribs","elote","tajin","spicy","mexican","vegan option","roasted"]','["vegetarian","gluten-free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Bacon Wrapped Onion Rings','bacon-wrapped-onion-rings','Crispy bacon hugs thick onion rings in this indulgent appetizer. Each bite delivers smoky, savory flavor with a satisfying crunch.','Thick onion rings wrapped in crispy bacon and baked to perfection.','American','Easy',15,25,40,4,320,14,12,24,1,'[{"amount":2,"unit":"large","item":"yellow onions","group":"main"},{"amount":12,"unit":"strips","item":"thin cut bacon","group":"main"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"brown sugar","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"toothpicks","group":"tools"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"main"}]','[{"title":"Preheat and Prep Onions","text":"Preheat your oven to 400 degrees F. Slice onions into thick rings about 1 inch wide. Separate the rings and select the largest ones for wrapping. Pat the rings dry with paper towels so bacon adheres properly.","timer":0},{"title":"Season the Rings","text":"Mix smoked paprika, garlic powder, black pepper, and brown sugar in a small bowl. Lightly brush each onion ring with olive oil and dust with the seasoning blend on all sides.","timer":0},{"title":"Wrap with Bacon","text":"Take one strip of thin cut bacon and wrap it tightly around each seasoned onion ring, overlapping slightly as you go. Secure the end of the bacon with a toothpick to prevent unraveling during cooking.","timer":0},{"title":"Bake the Rings","text":"Place wrapped onion rings on a wire rack set over a baking sheet to allow fat to drip away. Bake at 400 degrees F for 20 to 25 minutes, flipping halfway through, until bacon is crispy and golden brown.","timer":1500},{"title":"Rest and Serve","text":"Remove toothpicks carefully before serving. Let the rings rest for 3 minutes on the rack so the bacon sets and crisps further. Serve immediately with your favorite dipping sauce.","timer":180}]','[{"original":"yellow onions","swap":"sweet Vidalia onions for a milder flavor"},{"original":"thin cut bacon","swap":"turkey bacon for a lighter option"},{"original":"brown sugar","swap":"maple syrup brushed on for extra glaze"}]','["Using thick cut bacon which does not cook evenly around the onion ring","Skipping the wire rack which causes soggy bottoms from pooling grease","Not patting onions dry which causes bacon to slip off during baking"]','["bacon","onion rings","appetizer","game day","baked","finger food"]','["gluten-free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Bloomin Onion Bread','bloomin-onion-bread','A crusty sourdough loaf is sliced into a bloomin pattern and stuffed with cheese and savory herbs. Pull apart each cheesy segment for a show stopping shareable bread.','Pull apart sourdough bread loaded with melted cheese and caramelized onion flavor.','American','Easy',15,25,40,6,410,16,42,20,2,'[{"amount":1,"unit":"large","item":"round sourdough loaf","group":"main"},{"amount":2,"unit":"cups","item":"shredded mozzarella cheese","group":"filling"},{"amount":0.5,"unit":"cup","item":"shredded cheddar cheese","group":"filling"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"filling"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"filling"},{"amount":1,"unit":"medium","item":"yellow onion finely diced","group":"filling"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"garnish"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"seasoning"}]','[{"title":"Preheat Oven and Score Bread","text":"Preheat oven to 375 degrees F. Place the sourdough loaf on a cutting board. Using a serrated knife, make deep cuts across the loaf in a grid pattern about 1 inch apart, cutting almost but not all the way through the bottom crust to keep the loaf intact.","timer":0},{"title":"Cook the Onion Garlic Butter","text":"Melt butter in a small skillet over medium heat. Add diced onion and cook for 5 minutes until softened and translucent. Add minced garlic and red pepper flakes and cook for 1 more minute. Remove from heat and stir in parsley.","timer":360},{"title":"Stuff the Bread","text":"Place the scored loaf on a large piece of aluminum foil. Carefully open each cut section and spoon the onion garlic butter mixture deep into every crevice. Stuff both mozzarella and cheddar cheese generously into every gap so cheese is visible throughout.","timer":0},{"title":"Wrap and Bake","text":"Wrap the stuffed loaf tightly in foil and place on a baking sheet. Bake at 375 degrees F for 15 minutes. Then open the foil and bake uncovered for an additional 10 minutes until the cheese is fully melted and the top is golden.","timer":1500},{"title":"Serve Immediately","text":"Transfer the loaf to a serving board. Garnish with extra fresh parsley. Serve right away while the cheese is hot and melted, encouraging guests to pull apart individual segments directly from the loaf.","timer":0}]','[{"original":"sourdough loaf","swap":"Italian round bread for a softer texture"},{"original":"mozzarella cheese","swap":"Gruyere cheese for a nuttier richer flavor"},{"original":"fresh parsley","swap":"fresh chives for a mild onion herb finish"}]','["Cutting all the way through the bottom which causes the loaf to fall apart","Not stuffing cheese deep enough into cuts leaving dry pockets inside","Skipping the foil wrap phase which causes the outside to burn before cheese melts"]','["pull apart bread","cheese bread","party food","shareable","baked","comfort food"]','["vegetarian"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Sweet Potato Fries with Marshmallow Dip','sweet-potato-fries-marshmallow-dip','Crispy oven baked sweet potato fries are paired with a fluffy toasted marshmallow dipping sauce. The sweet and savory contrast makes this an irresistible snack or side dish.','Crispy spiced sweet potato fries served alongside a rich and fluffy marshmallow cream dip.','American','Easy',15,30,45,4,340,4,58,10,6,'[{"amount":3,"unit":"large","item":"sweet potatoes","group":"fries"},{"amount":3,"unit":"tbsp","item":"olive oil","group":"fries"},{"amount":1,"unit":"tsp","item":"cinnamon","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":1,"unit":"cup","item":"marshmallow fluff","group":"dip"},{"amount":4,"unit":"oz","item":"cream cheese softened","group":"dip"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"dip"}]','[{"title":"Prep and Soak the Fries","text":"Preheat oven to 425 degrees F. Peel sweet potatoes and cut into uniform fry shaped sticks about 1/4 inch thick. Soak the cut fries in cold water for 20 minutes to remove excess starch, which is key to achieving crispiness. Drain and pat completely dry.","timer":1200},{"title":"Season and Arrange Fries","text":"Toss the dried sweet potato fries in olive oil, cinnamon, smoked paprika, and salt until evenly coated. Spread them in a single layer on two baking sheets, making sure fries do not touch each other. Overcrowding causes steaming instead of crisping.","timer":0},{"title":"Bake the Fries","text":"Bake at 425 degrees F for 15 minutes, then flip every fry with tongs and bake for another 12 to 15 minutes until the edges are caramelized and crisp. Watch closely in the final minutes as sweet potatoes can burn quickly due to their natural sugar content.","timer":1800},{"title":"Make the Marshmallow Dip","text":"While fries bake, beat softened cream cheese with a hand mixer until smooth and fluffy. Add marshmallow fluff and vanilla extract and mix on medium speed for 2 minutes until the dip is light, airy, and fully combined. Refrigerate until ready to serve.","timer":120},{"title":"Serve Hot","text":"Transfer hot crispy fries to a serving platter immediately from the oven. Serve alongside the chilled marshmallow dip in a small bowl. For an extra touch, use a kitchen torch to lightly toast the top of the marshmallow dip before serving.","timer":0}]','[{"original":"marshmallow fluff","swap":"whipped cream cheese with honey for a less sweet dip"},{"original":"smoked paprika","swap":"cayenne pepper for a sweet heat contrast"},{"original":"cream cheese","swap":"mascarpone for a lighter creamier dip texture"}]','["Skipping the soaking step which results in soft and limp fries instead of crispy ones","Overcrowding the baking sheet which causes fries to steam rather than roast","Using cold cream cheese in the dip which creates a lumpy uneven texture"]','["sweet potato","fries","marshmallow","dip","baked","side dish","snack"]','["vegetarian","gluten-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cheesy Bacon Onion Dip','cheesy-bacon-onion-dip','A warm bubbling dip loaded with crispy bacon, caramelized onions, and melted cheese makes the ultimate party appetizer. Serve with chips or crusty bread for a crowd pleasing bite.','Warm creamy dip packed with bacon and caramelized onions topped with melted cheese.','American','Easy',15,30,45,8,290,12,8,24,1,'[{"amount":6,"unit":"strips","item":"bacon chopped","group":"main"},{"amount":2,"unit":"medium","item":"yellow onions thinly sliced","group":"main"},{"amount":8,"unit":"oz","item":"cream cheese softened","group":"base"},{"amount":0.5,"unit":"cup","item":"sour cream","group":"base"},{"amount":0.5,"unit":"cup","item":"mayonnaise","group":"base"},{"amount":1.5,"unit":"cups","item":"shredded Gruyere cheese","group":"topping"},{"amount":1,"unit":"tsp","item":"Worcestershire sauce","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"}]','[{"title":"Cook Bacon and Caramelize Onions","text":"Cook chopped bacon in a large skillet over medium heat until crispy. Remove bacon and set aside, leaving 1 tablespoon of drippings in the pan. Add sliced onions to the drippings and cook over low heat for 20 to 25 minutes, stirring often, until deeply golden and caramelized.","timer":1500},{"title":"Preheat Oven and Mix Base","text":"Preheat oven to 375 degrees F. In a large mixing bowl, combine softened cream cheese, sour cream, mayonnaise, Worcestershire sauce, and black pepper. Beat with a hand mixer or sturdy spatula until the mixture is completely smooth and well blended.","timer":0},{"title":"Combine All Ingredients","text":"Fold the caramelized onions and most of the cooked bacon into the cream cheese base, reserving some bacon for topping. Stir in half of the shredded Gruyere cheese and mix well to distribute evenly throughout the dip mixture.","timer":0},{"title":"Bake the Dip","text":"Transfer the mixture to an oven safe baking dish and spread evenly. Top with remaining Gruyere cheese and reserved bacon pieces. Bake at 375 degrees F for 20 to 25 minutes until the dip is bubbling around the edges and the cheese on top is melted and lightly browned.","timer":1500},{"title":"Cool Slightly and Serve","text":"Remove from oven and let the dip rest for 5 minutes before serving so it thickens slightly and is safe to eat. Serve warm directly from the baking dish with tortilla chips, sliced baguette, or crispy crackers on the side.","timer":300}]','[{"original":"Gruyere cheese","swap":"Swiss cheese for a milder but similar flavor"},{"original":"sour cream","swap":"plain Greek yogurt for a tangier lighter base"},{"original":"mayonnaise","swap":"additional cream cheese for a richer thicker dip"}]','["Rushing the caramelization process by using high heat which burns onions instead of sweetening them","Using cold cream cheese which creates lumps that do not fully blend into the dip","Serving the dip straight from the oven before it rests which makes it too runny to scoop"]','["dip","bacon","onion","cheese","party food","appetizer","warm dip"]','["gluten-free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Crispy Onion Ring Tower','crispy-onion-ring-tower','Golden beer battered onion rings stacked high into an impressive tower make a stunning side dish or appetizer. Each ring is perfectly crispy outside with a tender sweet onion center.','Beer battered onion rings fried to golden perfection and stacked into a shareable tower.','American','Medium',20,20,40,4,380,8,46,18,2,'[{"amount":2,"unit":"large","item":"sweet onions","group":"main"},{"amount":1.5,"unit":"cups","item":"all purpose flour","group":"batter"},{"amount":1,"unit":"cup","item":"cold lager beer","group":"batter"},{"amount":1,"unit":"tsp","item":"baking powder","group":"batter"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":4,"unit":"cups","item":"vegetable oil for frying","group":"frying"}]','[{"title":"Slice and Separate Onions","text":"Slice the sweet onions into rounds about 3/4 inch thick. Carefully separate each slice into individual rings and discard the very small center pieces. Pat all rings completely dry with paper towels as moisture is the enemy of crispy batter.","timer":0},{"title":"Make the Beer Batter","text":"Whisk together flour, baking powder, garlic powder, smoked paprika, and salt in a large bowl. Gradually pour in the cold lager beer while whisking until a smooth thick batter forms with no lumps. Do not overmix and do not use warm beer as cold beer creates a lighter crispier coating.","timer":0},{"title":"Heat the Oil","text":"Pour vegetable oil into a large heavy bottomed pot to a depth of 3 inches. Heat over medium high heat until the oil reaches 375 degrees F. Use a thermometer to monitor temperature carefully. Oil that is too cool produces greasy rings and oil that is too hot burns the batter.","timer":300},{"title":"Batter and Fry the Rings","text":"Working in small batches, dip each onion ring into the beer batter letting excess drip off for 2 seconds. Carefully lower into the hot oil and fry for 2 to 3 minutes per side until deeply golden and crispy. Do not crowd the pot as it drops oil temperature dramatically. Drain on a wire rack.","timer":180},{"title":"Stack and Serve","text":"Stack the fried rings from largest to smallest on a skewer or tall serving spike to create the tower presentation. Season with a pinch of flaky salt immediately while hot. Serve right away as onion rings lose their crispiness quickly once they cool.","timer":0}]','[{"original":"lager beer","swap":"cold sparkling water for an alcohol free version"},{"original":"sweet onions","swap":"white onions for a sharper more pungent flavor"},{"original":"vegetable oil","swap":"peanut oil for a higher smoke point and neutral taste"}]','["Using warm beer in the batter which results in a dense heavy coating instead of light and crispy","Overcrowding the frying pot which drops oil temperature and leads to greasy soggy rings","Not patting onions dry before battering which causes batter to slide off during frying"]','["onion rings","fried","beer batter","appetizer","side dish","crispy","game day"]','["vegetarian"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Mac and Cheese Egg Rolls','mac-and-cheese-egg-rolls','Crispy fried egg rolls stuffed with creamy macaroni and cheese. A fun fusion snack that combines two comfort food classics.','Gooey mac and cheese wrapped in a crunchy fried egg roll shell.','American Fusion','Medium',30,20,50,12,280,10,32,13,1,'[{"amount":2,"unit":"cups","item":"elbow macaroni cooked","group":"filling"},{"amount":2,"unit":"cups","item":"shredded cheddar cheese","group":"filling"},{"amount":4,"unit":"tablespoons","item":"unsalted butter","group":"filling"},{"amount":3,"unit":"tablespoons","item":"all purpose flour","group":"filling"},{"amount":1.5,"unit":"cups","item":"whole milk","group":"filling"},{"amount":0.5,"unit":"teaspoon","item":"garlic powder","group":"filling"},{"amount":12,"unit":"pieces","item":"egg roll wrappers","group":"shell"},{"amount":4,"unit":"cups","item":"vegetable oil for frying","group":"shell"},{"amount":1,"unit":"large","item":"egg beaten for sealing","group":"shell"}]','[{"title":"Make the Cheese Sauce","text":"Melt butter in a saucepan over medium heat. Whisk in flour and cook for 1 minute. Gradually add milk while whisking constantly until thickened. Remove from heat and stir in cheddar cheese and garlic powder until smooth.","timer":300},{"title":"Combine and Chill","text":"Stir the cooked macaroni into the cheese sauce until fully coated. Spread mixture onto a baking sheet and refrigerate for at least 20 minutes until firm enough to handle.","timer":1200},{"title":"Roll the Egg Rolls","text":"Place an egg roll wrapper flat on a clean surface in a diamond shape. Spoon about 3 tablespoons of the chilled mac and cheese mixture near the bottom corner. Fold the bottom corner up, fold in the sides, and roll tightly. Seal the top edge with beaten egg.","timer":0},{"title":"Heat the Oil","text":"Pour vegetable oil into a deep heavy pot and heat to 350 degrees Fahrenheit. Use a thermometer to ensure the correct temperature so the rolls do not absorb excess oil.","timer":300},{"title":"Fry Until Golden","text":"Fry 3 to 4 egg rolls at a time for 3 to 4 minutes, turning occasionally, until deep golden brown. Remove with a slotted spoon and drain on paper towels. Serve immediately with dipping sauce of your choice.","timer":240}]','[{"original":"cheddar cheese","swap":"gruyere or pepper jack cheese"},{"original":"egg roll wrappers","swap":"spring roll wrappers for a thinner crunch"},{"original":"vegetable oil","swap":"canola or peanut oil for frying"}]','["Do not skip chilling the filling or it will leak out during frying","Do not overfill the wrappers or they will burst open in the oil","Do not fry at too low a temperature or the rolls will turn out greasy"]','["mac and cheese","egg rolls","fried","comfort food","party snack","fusion"]','["vegetarian"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Hasselback Potatoes with Queso','hasselback-potatoes-with-queso','Thinly sliced roasted potatoes drizzled with warm homemade queso dip. A showstopping side dish with crispy edges and a creamy topping.','Fan-cut roasted potatoes topped with silky melted queso cheese sauce.','American','Medium',20,60,80,4,390,12,45,19,4,'[{"amount":4,"unit":"large","item":"russet potatoes","group":"potatoes"},{"amount":4,"unit":"tablespoons","item":"unsalted butter melted","group":"potatoes"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"potatoes"},{"amount":1,"unit":"teaspoon","item":"smoked paprika","group":"potatoes"},{"amount":1,"unit":"teaspoon","item":"garlic powder","group":"potatoes"},{"amount":8,"unit":"ounces","item":"processed American cheese cubed","group":"queso"},{"amount":0.5,"unit":"cup","item":"whole milk","group":"queso"},{"amount":1,"unit":"small","item":"jalapeno finely diced","group":"queso"},{"amount":2,"unit":"tablespoons","item":"fresh cilantro chopped","group":"garnish"}]','[{"title":"Slice the Potatoes","text":"Preheat oven to 425 degrees Fahrenheit. Scrub potatoes clean and place each one between two chopsticks or wooden spoons. Slice crosswise at 3 millimeter intervals, letting the chopsticks prevent you from cutting all the way through.","timer":0},{"title":"Season and Roast","text":"Mix melted butter, olive oil, smoked paprika, garlic powder, salt, and pepper together. Brush generously over each potato, working the mixture down into the slices. Place on a baking sheet and roast for 55 to 60 minutes until the edges are golden and crispy.","timer":3600},{"title":"Baste Halfway Through","text":"After 30 minutes of roasting, remove the potatoes from the oven and baste again with any remaining butter mixture. The slices should have begun to fan out. Return to the oven to finish roasting.","timer":1800},{"title":"Make the Queso","text":"Combine American cheese cubes, milk, and diced jalapeno in a small saucepan over low heat. Stir continuously until the cheese is fully melted and the sauce is smooth. Do not allow the queso to boil or it will become grainy.","timer":600},{"title":"Serve","text":"Transfer the roasted hasselback potatoes to a serving platter. Spoon warm queso generously over each potato so it flows down into the slices. Garnish with fresh cilantro and serve immediately.","timer":0}]','[{"original":"processed American cheese","swap":"Velveeta for an extra smooth queso"},{"original":"russet potatoes","swap":"Yukon gold potatoes for a creamier texture"},{"original":"jalapeno","swap":"canned diced green chiles for a milder heat"}]','["Do not cut all the way through the potato or it will fall apart","Do not rush the roasting time or the insides will remain undercooked","Do not make the queso too far in advance or it will thicken and become difficult to pour"]','["hasselback","potatoes","queso","side dish","roasted","cheesy"]','["vegetarian","gluten-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cornbread Waffles','cornbread-waffles','Golden crispy cornbread baked in a waffle iron for the perfect sweet and savory bite. Great for brunch or served alongside chili and pulled pork.','Classic cornbread batter cooked in a waffle iron for a crispy golden result.','Southern American','Easy',10,20,30,6,310,8,42,12,2,'[{"amount":1.5,"unit":"cups","item":"yellow cornmeal","group":"dry"},{"amount":0.5,"unit":"cup","item":"all purpose flour","group":"dry"},{"amount":2,"unit":"teaspoons","item":"baking powder","group":"dry"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"dry"},{"amount":2,"unit":"tablespoons","item":"granulated sugar","group":"dry"},{"amount":2,"unit":"large","item":"eggs","group":"wet"},{"amount":1.25,"unit":"cups","item":"buttermilk","group":"wet"},{"amount":4,"unit":"tablespoons","item":"unsalted butter melted","group":"wet"},{"amount":1,"unit":"cup","item":"creamed corn","group":"wet"}]','[{"title":"Preheat the Waffle Iron","text":"Preheat your waffle iron to medium high heat and grease it lightly with cooking spray or a thin brush of melted butter. A well-heated iron is key to achieving crispy edges on the cornbread waffles.","timer":300},{"title":"Mix the Dry Ingredients","text":"In a large mixing bowl, whisk together the cornmeal, flour, baking powder, salt, and sugar. Make sure the baking powder is evenly distributed throughout the dry mixture.","timer":0},{"title":"Combine the Wet Ingredients","text":"In a separate bowl, whisk the eggs until smooth. Add the buttermilk, melted butter, and creamed corn and whisk until well combined.","timer":0},{"title":"Make the Batter","text":"Pour the wet ingredients into the dry ingredients and stir gently until just combined. Do not overmix the batter or the waffles will turn out tough and dense. A few small lumps are perfectly fine.","timer":0},{"title":"Cook the Waffles","text":"Pour enough batter to fill your waffle iron about three quarters full. Close the lid and cook for 4 to 5 minutes until golden brown and crispy. Repeat with remaining batter. Serve warm with honey butter or alongside your favorite savory dish.","timer":300}]','[{"original":"buttermilk","swap":"regular milk with 1 tablespoon of white vinegar stirred in"},{"original":"creamed corn","swap":"drained canned whole kernel corn for a chunkier texture"},{"original":"unsalted butter","swap":"coconut oil for a subtle sweetness"}]','["Do not overmix the batter or the waffles will become tough and rubbery","Do not open the waffle iron too early or the waffles will tear apart","Do not use too much batter or it will overflow and make a mess"]','["cornbread","waffles","brunch","southern","comfort food","breakfast"]','["vegetarian"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Spicy Buffalo Mac and Cheese Egg Rolls','spicy-buffalo-mac-and-cheese-egg-rolls','Fiery buffalo-spiced mac and cheese loaded into crispy egg roll wrappers and fried to perfection. A bold crowd-pleasing appetizer with a serious kick.','Buffalo mac and cheese packed into crispy egg rolls for a spicy party bite.','American Fusion','Medium',35,20,55,12,295,11,30,15,1,'[{"amount":2,"unit":"cups","item":"elbow macaroni cooked","group":"filling"},{"amount":1.5,"unit":"cups","item":"shredded monterey jack cheese","group":"filling"},{"amount":3,"unit":"tablespoons","item":"buffalo hot sauce","group":"filling"},{"amount":3,"unit":"tablespoons","item":"unsalted butter","group":"filling"},{"amount":3,"unit":"tablespoons","item":"all purpose flour","group":"filling"},{"amount":1.25,"unit":"cups","item":"whole milk","group":"filling"},{"amount":12,"unit":"pieces","item":"egg roll wrappers","group":"shell"},{"amount":4,"unit":"cups","item":"canola oil for frying","group":"shell"},{"amount":1,"unit":"large","item":"egg beaten for sealing","group":"shell"}]','[{"title":"Prepare the Buffalo Cheese Sauce","text":"Melt butter in a saucepan over medium heat. Whisk in flour and cook for 1 minute to form a roux. Slowly add milk while whisking until the sauce thickens. Remove from heat and stir in the shredded monterey jack cheese and buffalo hot sauce until the sauce is smooth and glossy.","timer":300},{"title":"Mix and Chill the Filling","text":"Fold the cooked macaroni into the buffalo cheese sauce until every piece is well coated. Spread the mixture onto a lined baking sheet and refrigerate for 25 minutes until the filling is firm enough to roll.","timer":1500},{"title":"Assemble the Egg Rolls","text":"Lay each egg roll wrapper flat in a diamond orientation. Place about 3 tablespoons of the chilled buffalo mac filling near the bottom corner. Roll the bottom corner up over the filling, fold in the two side corners tightly, and continue rolling to the top. Brush the top edge with beaten egg to seal.","timer":0},{"title":"Heat the Oil","text":"Pour canola oil into a heavy bottomed pot and heat to 350 degrees Fahrenheit. Maintain this temperature throughout frying so the egg rolls cook evenly and do not become overly greasy.","timer":300},{"title":"Fry and Serve","text":"Fry 3 to 4 egg rolls at a time for 3 to 4 minutes turning gently until they are deep golden brown on all sides. Remove and drain on paper towels. Serve hot with blue cheese or ranch dipping sauce on the side.","timer":240}]','[{"original":"monterey jack cheese","swap":"cheddar or colby jack for a milder flavor"},{"original":"buffalo hot sauce","swap":"sriracha mixed with a splash of vinegar for a different heat profile"},{"original":"canola oil","swap":"peanut oil for frying for a higher smoke point"}]','["Do not skip the chilling step or the filling will be too soft to roll properly","Do not seal the wrappers loosely or the filling will escape into the hot oil","Do not crowd the pot with too many egg rolls at once or the oil temperature will drop"]','["buffalo","mac and cheese","egg rolls","spicy","fried","party food","appetizer"]','["vegetarian"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Loaded Hasselback Sweet Potatoes with Queso','loaded-hasselback-sweet-potatoes-with-queso','Oven-roasted hasselback sweet potatoes layered with smoky spices and finished with a drizzle of creamy queso. A stunning balance of sweet and savory flavors.','Fan-cut sweet potatoes roasted until caramelized and drizzled with warm queso sauce.','American','Medium',20,65,85,4,370,10,52,15,6,'[{"amount":4,"unit":"medium","item":"sweet potatoes","group":"potatoes"},{"amount":3,"unit":"tablespoons","item":"olive oil","group":"potatoes"},{"amount":2,"unit":"tablespoons","item":"unsalted butter melted","group":"potatoes"},{"amount":1,"unit":"teaspoon","item":"chili powder","group":"potatoes"},{"amount":0.5,"unit":"teaspoon","item":"cumin","group":"potatoes"},{"amount":8,"unit":"ounces","item":"Velveeta cheese cubed","group":"queso"},{"amount":0.5,"unit":"cup","item":"whole milk","group":"queso"},{"amount":1,"unit":"small","item":"jalapeno seeded and diced","group":"queso"},{"amount":2,"unit":"tablespoons","item":"sour cream for garnish","group":"garnish"}]','[{"title":"Slice and Prep the Sweet Potatoes","text":"Preheat oven to 400 degrees Fahrenheit. Wash and dry each sweet potato. Place each one between two wooden spoons on a cutting board. Cut crosswise slices about 3 millimeters apart, allowing the wooden spoons to stop the knife before cutting all the way through.","timer":0},{"title":"Season and Roast","text":"Whisk together olive oil, melted butter, chili powder, cumin, salt, and pepper. Brush each sweet potato generously with the spice mixture, pressing it down into the slices. Place on a foil-lined baking sheet and roast for 60 to 65 minutes until tender inside and caramelized at the edges.","timer":3900},{"title":"Baste at the Halfway Point","text":"After 30 minutes pull the tray from the oven. Brush the potatoes again with any remaining spice oil mixture. The slices should have fanned open nicely. Return to the oven for the remaining roasting time.","timer":1800},{"title":"Make the Queso Sauce","text":"Combine Velveeta cubes, whole milk, and diced jalapeno in a small saucepan over low heat. Stir constantly until the cheese is fully melted and the sauce is smooth and pourable. Do not allow it to boil or the texture will become grainy.","timer":480},{"title":"Plate and Serve","text":"Arrange the roasted hasselback sweet potatoes on a serving board. Drizzle warm queso sauce liberally over each potato letting it seep down between the slices. Add a small dollop of sour cream and serve immediately while everything is hot.","timer":0}]','[{"original":"Velveeta cheese","swap":"processed American cheese for a similar smooth melt"},{"original":"sweet potatoes","swap":"large Yukon gold potatoes for a less sweet flavor"},{"original":"jalapeno","swap":"pickled banana peppers for a milder tangy heat"}]','["Do not cut completely through the potato or the fans will fall apart during roasting","Do not skip basting halfway through or the tops will dry out before the insides are cooked","Do not boil the queso sauce or it will turn grainy and separate"]','["sweet potato","hasselback","queso","roasted","side dish","game day","vegetarian"]','["vegetarian","gluten-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Street Corn Nachos','street-corn-nachos','Crispy tortilla chips loaded with smoky elote-inspired toppings and melted cheese. A bold and festive snack perfect for game day or casual gatherings.','Loaded nachos topped with Mexican street corn flavors including cotija, chili, and lime crema.','Mexican-American','Easy',15,15,30,4,520,14,48,31,5,'[{"amount":10,"unit":"oz","item":"tortilla chips","group":"base"},{"amount":2,"unit":"cups","item":"shredded Mexican blend cheese","group":"base"},{"amount":2,"unit":"cups","item":"roasted corn kernels","group":"topping"},{"amount":0.5,"unit":"cup","item":"cotija cheese crumbled","group":"topping"},{"amount":0.5,"unit":"cup","item":"sour cream","group":"sauce"},{"amount":2,"unit":"tbsp","item":"mayonnaise","group":"sauce"},{"amount":1,"unit":"tsp","item":"chili powder","group":"seasoning"},{"amount":1,"unit":"whole","item":"lime juiced","group":"seasoning"},{"amount":0.25,"unit":"cup","item":"fresh cilantro chopped","group":"garnish"},{"amount":2,"unit":"whole","item":"jalapenos sliced","group":"garnish"}]','[{"title":"Preheat and Prep","text":"Preheat your oven to 400 degrees F. Line a large baking sheet with parchment paper and spread tortilla chips in a single even layer.","timer":0},{"title":"Add Cheese and Corn","text":"Sprinkle the shredded Mexican blend cheese evenly over the chips. Scatter the roasted corn kernels on top of the cheese.","timer":0},{"title":"Bake Until Melted","text":"Place the baking sheet in the oven and bake for 10 to 12 minutes until the cheese is fully melted and the edges of the chips are golden.","timer":720},{"title":"Mix the Crema","text":"While the nachos bake, whisk together sour cream, mayonnaise, lime juice, and half the chili powder in a small bowl until smooth.","timer":0},{"title":"Top and Serve","text":"Remove nachos from the oven and drizzle the lime crema over everything. Sprinkle cotija cheese, remaining chili powder, cilantro, and jalapeno slices on top. Serve immediately.","timer":0}]','[{"original":"cotija cheese","swap":"feta cheese crumbled"},{"original":"sour cream","swap":"plain Greek yogurt"},{"original":"fresh jalapenos","swap":"pickled jalapeno slices"}]','["Piling chips too thick so the bottom layer stays cold and the cheese does not melt evenly","Adding the crema before baking which causes it to curdle and lose its fresh flavor","Using canned corn without roasting it first which results in a watery and bland topping"]','["nachos","street corn","elote","game day","party food","tex-mex","snack"]','["vegetarian"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Pizza Fries','pizza-fries','Golden crispy fries smothered in marinara, melted mozzarella, and classic pizza toppings. The ultimate mashup of two beloved comfort foods.','Crispy seasoned fries topped with marinara sauce, gooey mozzarella, and pepperoni.','American-Italian','Easy',10,30,40,4,580,20,55,30,4,'[{"amount":32,"unit":"oz","item":"frozen crinkle cut fries","group":"base"},{"amount":1,"unit":"cup","item":"marinara sauce","group":"sauce"},{"amount":2,"unit":"cups","item":"shredded mozzarella cheese","group":"topping"},{"amount":3,"unit":"oz","item":"pepperoni slices","group":"topping"},{"amount":0.5,"unit":"cup","item":"sliced black olives","group":"topping"},{"amount":0.5,"unit":"tsp","item":"dried oregano","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh basil leaves torn","group":"garnish"},{"amount":2,"unit":"tbsp","item":"grated Parmesan cheese","group":"garnish"}]','[{"title":"Bake the Fries","text":"Preheat oven to 425 degrees F. Spread frozen fries in a single layer on a large baking sheet and bake according to package directions until golden and crispy, about 20 to 25 minutes.","timer":1500},{"title":"Season the Fries","text":"Remove fries from the oven and toss them with garlic powder and dried oregano while still hot. Spread them back into an even layer on the baking sheet.","timer":0},{"title":"Add Toppings","text":"Spoon marinara sauce evenly over the fries. Sprinkle shredded mozzarella over the sauce, then layer pepperoni slices and black olives on top.","timer":0},{"title":"Broil Until Bubbly","text":"Switch the oven to broil on high. Return the baking sheet to the oven and broil for 3 to 4 minutes until the cheese is melted, bubbly, and lightly browned. Watch closely to prevent burning.","timer":240},{"title":"Garnish and Serve","text":"Remove from oven and immediately top with torn fresh basil and grated Parmesan. Serve directly from the pan with extra marinara on the side for dipping.","timer":0}]','[{"original":"pepperoni slices","swap":"turkey pepperoni or diced bell peppers for a vegetarian option"},{"original":"frozen crinkle cut fries","swap":"homemade thick-cut potato fries"},{"original":"black olives","swap":"sliced banana peppers or mushrooms"}]','["Not cooking the fries fully before adding toppings which leads to soggy fries that cannot support the sauce","Using too much marinara so the fries become wet and lose their crispiness","Skipping the broil step and just baking which results in cheese that is melted but not bubbly and golden"]','["pizza fries","comfort food","game day","party snack","fries","fusion","easy dinner"]','[]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Soft Pretzels with Beer Cheese Fondue','soft-pretzels-beer-cheese-fondue','Pillowy homemade soft pretzels served alongside a rich and savory beer cheese dipping sauce. A classic pub-inspired pairing that is deeply satisfying.','Warm homemade soft pretzels paired with a silky sharp cheddar and lager beer cheese fondue.','American','Medium',30,25,55,6,610,22,70,25,3,'[{"amount":3,"unit":"cups","item":"all-purpose flour","group":"pretzel dough"},{"amount":1,"unit":"packet","item":"instant yeast 0.25 oz","group":"pretzel dough"},{"amount":1,"unit":"tsp","item":"salt","group":"pretzel dough"},{"amount":1,"unit":"tsp","item":"sugar","group":"pretzel dough"},{"amount":1,"unit":"cup","item":"warm water","group":"pretzel dough"},{"amount":0.25,"unit":"cup","item":"baking soda","group":"pretzel bath"},{"amount":2,"unit":"tbsp","item":"coarse sea salt","group":"pretzel topping"},{"amount":2,"unit":"cups","item":"sharp cheddar cheese shredded","group":"fondue"},{"amount":1,"unit":"cup","item":"lager beer","group":"fondue"},{"amount":2,"unit":"tbsp","item":"butter","group":"fondue"}]','[{"title":"Make the Pretzel Dough","text":"In a large bowl combine warm water, sugar, and instant yeast. Let sit for 5 minutes until foamy. Add flour and salt and mix until a dough forms. Knead for 5 to 7 minutes until smooth and elastic. Cover and let rest for 15 minutes.","timer":900},{"title":"Shape the Pretzels","text":"Preheat oven to 450 degrees F. Divide dough into 6 equal pieces. Roll each piece into a long rope about 24 inches long. Form each rope into a U shape, twist the ends twice, then fold them down to create the classic pretzel shape.","timer":0},{"title":"Baking Soda Bath and Bake","text":"Bring 4 cups of water and baking soda to a boil in a wide pot. Dip each pretzel into the bath for 30 seconds, then place on a lined baking sheet. Sprinkle with coarse sea salt. Bake for 12 to 14 minutes until deep golden brown.","timer":840},{"title":"Make the Beer Cheese Fondue","text":"In a medium saucepan over medium heat melt the butter. Pour in the lager beer and bring to a gentle simmer. Reduce heat to low and gradually add the shredded cheddar one handful at a time, stirring constantly until each addition is fully melted and smooth.","timer":480},{"title":"Serve Together","text":"Transfer the warm beer cheese fondue to a serving bowl or small fondue pot. Arrange the fresh-baked pretzels on a board alongside the fondue. Serve immediately while everything is hot.","timer":0}]','[{"original":"lager beer","swap":"non-alcoholic beer or low-sodium chicken broth"},{"original":"sharp cheddar cheese","swap":"Gruyere or smoked gouda for a different flavor profile"},{"original":"all-purpose flour","swap":"bread flour for a chewier pretzel texture"}]','["Skipping the baking soda bath which is essential for achieving the signature dark color and chewy crust on soft pretzels","Adding cheese to the fondue all at once instead of gradually which causes the sauce to become grainy and separated","Under-kneading the dough which results in pretzels that are dense and do not have the proper soft and chewy texture"]','["soft pretzels","beer cheese","fondue","game day","pub food","homemade","dipping sauce","baking"]','["vegetarian"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Spicy Buffalo Cauliflower Bites','spicy-buffalo-cauliflower-bites','Crispy oven-baked cauliflower florets tossed in tangy buffalo sauce and served with cool ranch dip. A satisfying plant-based alternative to classic buffalo wings.','Crispy baked cauliflower florets coated in bold buffalo sauce with a creamy ranch dipping sauce.','American','Easy',15,25,40,4,280,7,32,14,5,'[{"amount":1,"unit":"large head","item":"cauliflower cut into florets","group":"base"},{"amount":0.75,"unit":"cup","item":"all-purpose flour","group":"batter"},{"amount":0.75,"unit":"cup","item":"water","group":"batter"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"batter"},{"amount":0.5,"unit":"tsp","item":"smoked paprika","group":"batter"},{"amount":0.75,"unit":"cup","item":"buffalo hot sauce","group":"sauce"},{"amount":2,"unit":"tbsp","item":"melted butter","group":"sauce"},{"amount":1,"unit":"cup","item":"ranch dressing","group":"dipping sauce"},{"amount":2,"unit":"stalks","item":"celery cut into sticks","group":"serving"}]','[{"title":"Make the Batter and Coat","text":"Preheat oven to 425 degrees F and line a baking sheet with parchment. Whisk together flour, water, garlic powder, smoked paprika, and a pinch of salt until smooth. Toss cauliflower florets in the batter until fully coated, letting excess drip off.","timer":0},{"title":"First Bake","text":"Arrange the battered florets in a single layer on the baking sheet. Bake for 20 minutes, flipping halfway through, until the batter is set and the edges are beginning to crisp up.","timer":1200},{"title":"Toss in Buffalo Sauce","text":"While cauliflower bakes, whisk together buffalo sauce and melted butter in a large bowl. Remove cauliflower from the oven and carefully toss all florets in the buffalo butter sauce until fully coated.","timer":0},{"title":"Second Bake","text":"Return the sauced florets to the baking sheet in a single layer. Bake for an additional 8 to 10 minutes until caramelized and sticky with the sauce set onto the surface.","timer":540},{"title":"Serve with Dipping Sauce","text":"Arrange hot buffalo cauliflower bites on a platter alongside celery sticks and a bowl of ranch dressing for dipping. Serve immediately for best texture.","timer":0}]','[{"original":"all-purpose flour","swap":"chickpea flour for a gluten-free version"},{"original":"butter in sauce","swap":"vegan butter to keep the dish fully plant-based"},{"original":"ranch dressing","swap":"blue cheese dressing for a more classic buffalo pairing"}]','["Crowding the florets on the baking sheet which causes them to steam instead of crisp up properly","Skipping the first bake before saucing which means the batter does not set and slides off during tossing","Using too thin of a batter consistency which results in barely any coating adhering to the cauliflower"]','["cauliflower","buffalo","vegetarian","game day","party snack","baked","spicy","wings alternative"]','["vegetarian"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Loaded Queso Fundido','loaded-queso-fundido','A bubbling skillet of melted cheese mixed with spicy chorizo, roasted peppers, and warm spices. Served straight from the pan with warm tortillas for dipping.','Melted Oaxaca and Monterey Jack cheese with chorizo and roasted peppers served in a sizzling skillet.','Mexican','Easy',10,20,30,6,430,20,12,34,1,'[{"amount":8,"unit":"oz","item":"Mexican chorizo casings removed","group":"filling"},{"amount":1.5,"unit":"cups","item":"shredded Oaxaca cheese","group":"cheese"},{"amount":1.5,"unit":"cups","item":"shredded Monterey Jack cheese","group":"cheese"},{"amount":1,"unit":"whole","item":"poblano pepper roasted and diced","group":"filling"},{"amount":0.5,"unit":"whole","item":"white onion diced","group":"filling"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"filling"},{"amount":1,"unit":"tsp","item":"cumin","group":"seasoning"},{"amount":8,"unit":"whole","item":"flour tortillas warmed","group":"serving"},{"amount":2,"unit":"tbsp","item":"fresh cilantro chopped","group":"garnish"}]','[{"title":"Cook the Chorizo","text":"Heat an oven-safe skillet over medium-high heat. Add chorizo and cook, breaking it into crumbles, for 5 to 6 minutes until fully cooked and browned. Use a slotted spoon to transfer chorizo to a paper towel-lined plate, leaving about 1 tablespoon of fat in the pan.","timer":360},{"title":"Saute the Vegetables","text":"In the same skillet over medium heat, add diced onion and cook for 3 minutes until softened. Add garlic and cumin and cook for 1 more minute until fragrant. Stir in the roasted diced poblano and remove from heat.","timer":240},{"title":"Preheat the Broiler","text":"Preheat your oven broiler to high. Return the cooked chorizo to the skillet and stir to combine with the vegetables. Spread the mixture evenly across the bottom of the skillet.","timer":0},{"title":"Add Cheese and Broil","text":"Evenly layer the shredded Oaxaca and Monterey Jack cheese over the chorizo mixture in the skillet. Place the skillet under the broiler for 4 to 5 minutes until the cheese is completely melted, bubbly, and lightly browned on top.","timer":300},{"title":"Garnish and Serve","text":"Remove the skillet carefully from the oven using oven mitts. Sprinkle fresh cilantro over the top of the bubbling queso fundido. Serve immediately straight from the skillet with warm flour tortillas for scooping.","timer":0}]','[{"original":"Mexican chorizo","swap":"plant-based chorizo crumbles for a vegetarian version"},{"original":"Oaxaca cheese","swap":"low-moisture mozzarella which melts in a similar stretchy way"},{"original":"poblano pepper","swap":"roasted red bell pepper for a milder heat level"}]','["Using pre-shredded cheese that contains anti-caking agents which prevent it from melting into a smooth and gooey consistency","Not draining excess grease from the chorizo which makes the final dish oily and heavy","Letting the queso fundido sit too long before serving as it firms up quickly and loses its ideal melted texture"]','["queso fundido","Mexican","chorizo","melted cheese","party dip","game day","skillet","fondue"]','[]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Crookie Croissant Cookie','crookie-croissant-cookie','A flaky buttery croissant stuffed with gooey chocolate chip cookie dough and baked until golden. This viral mashup delivers the best of both worlds in every single bite.','A buttery croissant filled with melty chocolate chip cookie dough baked to golden perfection.','French-American Fusion','Medium',20,18,38,4,520,7,58,29,2,'[{"amount":4,"unit":"whole","item":"store-bought croissants","group":"base"},{"amount":1,"unit":"cup","item":"all-purpose flour","group":"cookie dough"},{"amount":0.5,"unit":"cup","item":"unsalted butter softened","group":"cookie dough"},{"amount":0.5,"unit":"cup","item":"brown sugar packed","group":"cookie dough"},{"amount":0.25,"unit":"cup","item":"granulated sugar","group":"cookie dough"},{"amount":1,"unit":"whole","item":"large egg","group":"cookie dough"},{"amount":1,"unit":"cup","item":"semi-sweet chocolate chips","group":"cookie dough"},{"amount":0.5,"unit":"tsp","item":"vanilla extract","group":"cookie dough"},{"amount":0.5,"unit":"tsp","item":"baking soda","group":"cookie dough"},{"amount":0.25,"unit":"tsp","item":"salt","group":"cookie dough"}]','[{"title":"Make the Cookie Dough","text":"Beat butter with both sugars until light and fluffy. Add egg and vanilla and mix well. Stir in flour baking soda and salt until just combined. Fold in chocolate chips. Do not overmix the dough.","timer":0},{"title":"Prepare the Croissants","text":"Preheat oven to 375 degrees F. Using a serrated knife slice each croissant along the side lengthwise leaving a hinge so it opens like a book. Do not cut all the way through.","timer":0},{"title":"Stuff and Top the Croissants","text":"Spoon about 3 tablespoons of cookie dough inside each croissant. Press gently to close. Place additional cookie dough on top of each croissant pressing it lightly to adhere.","timer":0},{"title":"Bake Until Golden","text":"Place stuffed croissants on a parchment-lined baking sheet. Bake for 15 to 18 minutes until the cookie dough on top is golden and the croissant is warmed through and slightly crisp.","timer":1080},{"title":"Cool and Serve","text":"Remove from oven and let cool for 5 minutes before serving. The interior will be gooey and melty. Serve warm for the best experience.","timer":300}]','[{"original":"semi-sweet chocolate chips","swap":"dark chocolate chunks or peanut butter chips"},{"original":"store-bought croissants","swap":"homemade croissants for a more elevated result"},{"original":"unsalted butter","swap":"salted butter and omit the added salt"}]','["Overfilling the croissant causes the dough to spill out and burn on the pan","Baking at too high a temperature makes the outside burn before the inside heats through","Using cold butter in the dough results in a lumpy mixture that does not bake evenly"]','["viral","croissant","cookie dough","chocolate chip","baked","dessert","fusion","indulgent"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Deep Fried Oreos','deep-fried-oreos','Classic Oreo cookies dipped in a fluffy pancake batter and deep fried until puffy and golden brown. A beloved state fair treat you can make right at home in under 30 minutes.','Oreo cookies coated in pancake batter and deep fried to crispy golden perfection.','American','Easy',10,15,25,6,310,4,42,15,1,'[{"amount":24,"unit":"whole","item":"Oreo cookies","group":"base"},{"amount":1,"unit":"cup","item":"pancake mix","group":"batter"},{"amount":0.75,"unit":"cup","item":"whole milk","group":"batter"},{"amount":1,"unit":"whole","item":"large egg","group":"batter"},{"amount":1,"unit":"tbsp","item":"granulated sugar","group":"batter"},{"amount":0.5,"unit":"tsp","item":"vanilla extract","group":"batter"},{"amount":4,"unit":"cups","item":"vegetable oil for frying","group":"frying"},{"amount":0.25,"unit":"cup","item":"powdered sugar for dusting","group":"topping"}]','[{"title":"Heat the Oil","text":"Pour vegetable oil into a deep heavy-bottomed pot and heat over medium-high heat until it reaches 375 degrees F. Use a thermometer to monitor the temperature. Do not let the oil overheat.","timer":600},{"title":"Make the Batter","text":"In a large bowl whisk together pancake mix milk egg sugar and vanilla extract until a smooth thick batter forms. The batter should coat the back of a spoon. Let it rest for 2 minutes.","timer":120},{"title":"Coat the Oreos","text":"Working in batches dip each Oreo cookie fully into the batter using a fork or skewer. Allow excess batter to drip off. Make sure each cookie is fully coated with no gaps.","timer":0},{"title":"Fry Until Golden","text":"Carefully lower battered Oreos into the hot oil in batches of 4 to 6. Fry for 2 to 3 minutes per side until puffed up and deep golden brown. Remove with a slotted spoon to a paper towel lined plate.","timer":180},{"title":"Dust and Serve","text":"While still warm dust generously with powdered sugar. Serve immediately as they are best enjoyed fresh and hot. Pair with whipped cream or vanilla ice cream if desired.","timer":0}]','[{"original":"pancake mix","swap":"homemade batter using flour baking powder milk and egg"},{"original":"Oreo cookies","swap":"any cream-filled sandwich cookie such as Double Stuf or a store brand"},{"original":"vegetable oil","swap":"canola oil or peanut oil for frying"}]','["Frying in oil that is not hot enough results in greasy soggy cookies instead of crispy ones","Overcrowding the pot drops the oil temperature and leads to uneven cooking","Making the batter too thin causes it to slide off the cookie before it sets in the oil"]','["state fair","fried","oreo","dessert","party snack","indulgent","quick","American"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Banana Pudding Taco','banana-pudding-taco','A crispy cinnamon sugar taco shell filled with creamy vanilla banana pudding fresh banana slices and whipped cream. This fun dessert taco is a crowd-pleasing twist on a Southern classic.','Cinnamon sugar taco shells loaded with creamy banana pudding and fresh banana slices.','American Fusion','Easy',25,10,35,6,390,5,54,18,2,'[{"amount":6,"unit":"whole","item":"small flour tortillas","group":"shell"},{"amount":4,"unit":"tbsp","item":"unsalted butter melted","group":"shell"},{"amount":3,"unit":"tbsp","item":"cinnamon sugar mixture","group":"shell"},{"amount":1,"unit":"package","item":"instant vanilla pudding mix 3.4 oz","group":"filling"},{"amount":2,"unit":"cups","item":"cold whole milk","group":"filling"},{"amount":3,"unit":"whole","item":"ripe bananas sliced","group":"filling"},{"amount":1,"unit":"cup","item":"whipped cream","group":"topping"},{"amount":10,"unit":"whole","item":"Nilla wafers crushed","group":"topping"},{"amount":0.5,"unit":"tsp","item":"vanilla extract","group":"filling"}]','[{"title":"Bake the Taco Shells","text":"Preheat oven to 400 degrees F. Brush both sides of each flour tortilla with melted butter then coat generously with cinnamon sugar. Drape tortillas over two oven rack bars to form a taco shell shape and bake for 8 to 10 minutes until crisp.","timer":600},{"title":"Make the Banana Pudding","text":"Whisk instant vanilla pudding mix with cold whole milk and vanilla extract for 2 minutes until it begins to thicken. Refrigerate for at least 10 minutes to set fully before filling the shells.","timer":600},{"title":"Prepare the Bananas","text":"Peel and slice the ripe bananas into even rounds about one quarter inch thick. Set aside. Use bananas that are ripe but still firm so they hold their shape inside the taco.","timer":0},{"title":"Assemble the Tacos","text":"Spoon a generous amount of the set banana pudding into each cooled cinnamon taco shell. Layer banana slices on top of the pudding pressing them gently into the filling.","timer":0},{"title":"Top and Serve","text":"Pipe or dollop whipped cream over each taco. Finish with a sprinkle of crushed Nilla wafers for crunch. Serve immediately so the shells stay crisp.","timer":0}]','[{"original":"instant vanilla pudding mix","swap":"homemade pastry cream or banana-flavored pudding mix"},{"original":"small flour tortillas","swap":"large wonton wrappers shaped and baked in a muffin tin for mini cups"},{"original":"whipped cream","swap":"sweetened cream cheese whipped with a splash of milk for a tangier topping"}]','["Filling the taco shells while they are still warm causes them to soften and lose their crunch","Using overripe bananas makes the filling too mushy and the slices fall apart","Assembling too far in advance causes the shell to become soggy from the pudding moisture"]','["banana pudding","dessert taco","Southern","no-bake filling","fun dessert","party food","easy","banana"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Churro Bites','classic-churro-bites','Bite-sized fried dough pieces rolled in cinnamon sugar with a crisp exterior and soft fluffy interior. Served with a rich chocolate dipping sauce these little bites are impossible to resist.','Crispy fried dough bites rolled in cinnamon sugar and served with chocolate dipping sauce.','Spanish-Mexican','Medium',15,20,35,8,280,4,36,13,1,'[{"amount":1,"unit":"cup","item":"water","group":"dough"},{"amount":0.5,"unit":"cup","item":"unsalted butter","group":"dough"},{"amount":1,"unit":"cup","item":"all-purpose flour","group":"dough"},{"amount":3,"unit":"whole","item":"large eggs","group":"dough"},{"amount":0.5,"unit":"tsp","item":"salt","group":"dough"},{"amount":0.5,"unit":"cup","item":"granulated sugar","group":"coating"},{"amount":1.5,"unit":"tsp","item":"ground cinnamon","group":"coating"},{"amount":4,"unit":"cups","item":"vegetable oil for frying","group":"frying"},{"amount":0.5,"unit":"cup","item":"semi-sweet chocolate chips melted","group":"dipping sauce"}]','[{"title":"Make the Choux Dough","text":"Combine water butter and salt in a saucepan over medium heat. Bring to a boil then add flour all at once and stir vigorously until a smooth dough ball forms and pulls away from the sides. Remove from heat.","timer":300},{"title":"Add the Eggs","text":"Let the dough cool for 5 minutes then beat in eggs one at a time mixing well after each addition until the dough is smooth glossy and pipeable. The dough should fall slowly from a spoon.","timer":300},{"title":"Heat Oil and Pipe Dough","text":"Heat oil to 375 degrees F. Transfer dough to a piping bag fitted with a star tip. Pipe 1 inch pieces of dough directly into the hot oil cutting with scissors. Do not pipe too many at once.","timer":600},{"title":"Fry Until Golden","text":"Fry the churro bites for 3 to 4 minutes turning occasionally until they are deep golden and cooked through. Remove with a slotted spoon and drain briefly on paper towels.","timer":240},{"title":"Coat and Serve","text":"While still hot toss churro bites in the cinnamon sugar mixture until fully coated. Serve immediately alongside melted chocolate for dipping.","timer":0}]','[{"original":"vegetable oil","swap":"canola oil or sunflower oil for frying"},{"original":"semi-sweet chocolate chips","swap":"dulce de leche or caramel sauce for dipping"},{"original":"all-purpose flour","swap":"bread flour for a slightly chewier interior texture"}]','["Adding eggs to dough that is too hot scrambles them and ruins the texture","Frying at too low a temperature results in greasy dough that does not puff properly","Skipping the cinnamon sugar coating while the churros are still hot means it will not adhere"]','["churro","fried","cinnamon sugar","Spanish","Mexican","dessert","party snack","dipping sauce"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Strawberry Cheesecake Egg Rolls','strawberry-cheesecake-egg-rolls','Crispy golden egg roll wrappers filled with sweetened cream cheese and fresh strawberry jam then fried until shatteringly crunchy. Dusted with powdered sugar these are a stunning party dessert.','Golden fried egg rolls stuffed with cream cheese filling and strawberry jam dusted with powdered sugar.','American Fusion','Medium',20,15,35,8,340,6,38,18,1,'[{"amount":8,"unit":"whole","item":"egg roll wrappers","group":"shell"},{"amount":8,"unit":"oz","item":"cream cheese softened","group":"filling"},{"amount":0.25,"unit":"cup","item":"powdered sugar plus more for dusting","group":"filling"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"filling"},{"amount":0.5,"unit":"cup","item":"strawberry jam","group":"filling"},{"amount":0.5,"unit":"cup","item":"fresh strawberries diced","group":"filling"},{"amount":4,"unit":"cups","item":"vegetable oil for frying","group":"frying"},{"amount":2,"unit":"tbsp","item":"water for sealing","group":"shell"},{"amount":1,"unit":"tsp","item":"lemon zest","group":"filling"}]','[{"title":"Make the Cheesecake Filling","text":"Beat softened cream cheese with powdered sugar vanilla extract and lemon zest until completely smooth. Fold in strawberry jam and diced fresh strawberries gently. Do not overmix or the filling becomes too runny.","timer":0},{"title":"Fill the Egg Rolls","text":"Lay an egg roll wrapper on a clean surface in a diamond shape. Spoon 2 tablespoons of filling in the center. Do not overfill or the wrappers will burst during frying.","timer":0},{"title":"Roll and Seal","text":"Fold the bottom corner up over the filling then fold in the sides. Roll tightly toward the top corner. Dab water along the top corner edge to seal completely. Press firmly to ensure no gaps remain.","timer":0},{"title":"Fry Until Crispy","text":"Heat oil to 350 degrees F in a deep pot. Fry egg rolls in batches of 3 to 4 for 3 to 4 minutes turning once until evenly golden brown and crispy on all sides. Remove to a paper towel lined plate.","timer":240},{"title":"Dust and Serve","text":"Dust the warm egg rolls generously with powdered sugar. Slice in half on a diagonal to reveal the filling. Serve with extra strawberry jam or whipped cream on the side.","timer":0}]','[{"original":"strawberry jam","swap":"blueberry jam raspberry preserves or Nutella for different flavor variations"},{"original":"egg roll wrappers","swap":"spring roll wrappers for a thinner crispier shell"},{"original":"cream cheese","swap":"mascarpone cheese for a richer more Italian-inspired filling"}]','["Overfilling the wrappers causes them to split open and leak filling into the hot oil","Not sealing the edges tightly enough allows oil to seep in and makes the filling greasy","Using cream cheese that is still cold makes the filling lumpy and difficult to mix smooth"]','["cheesecake","egg roll","strawberry","fried","dessert","party food","fusion","cream cheese"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cookie Dough Egg Rolls','cookie-dough-egg-rolls','Crispy fried egg roll wrappers filled with sweet edible cookie dough loaded with chocolate chips. A fun and indulgent dessert that combines two classic treats into one irresistible bite.','Crispy egg roll wrappers stuffed with safe-to-eat chocolate chip cookie dough and fried until golden.','American Fusion','Easy',20,10,30,8,320,4,42,15,1,'[{"amount":8,"unit":"sheets","item":"egg roll wrappers","group":"wrapper"},{"amount":0.5,"unit":"cup","item":"heat treated all purpose flour","group":"cookie dough"},{"amount":0.5,"unit":"cup","item":"packed brown sugar","group":"cookie dough"},{"amount":0.25,"unit":"cup","item":"unsalted butter softened","group":"cookie dough"},{"amount":2,"unit":"tablespoons","item":"milk","group":"cookie dough"},{"amount":1,"unit":"teaspoon","item":"vanilla extract","group":"cookie dough"},{"amount":0.5,"unit":"cup","item":"mini chocolate chips","group":"cookie dough"},{"amount":2,"unit":"cups","item":"vegetable oil for frying","group":"frying"},{"amount":2,"unit":"tablespoons","item":"powdered sugar for dusting","group":"garnish"}]','[{"title":"Make the Edible Cookie Dough","text":"Beat softened butter and brown sugar together until fluffy. Mix in milk and vanilla extract. Stir in heat treated flour and mini chocolate chips until a soft dough forms. Do not use raw untreated flour as it is not safe to eat.","timer":0},{"title":"Fill the Egg Roll Wrappers","text":"Lay an egg roll wrapper on a clean surface in a diamond orientation. Place about 2 tablespoons of cookie dough in the center. Fold the bottom corner up over the filling, fold in the sides, then roll tightly to the top corner. Seal the edge with a dab of water.","timer":0},{"title":"Heat the Oil","text":"Pour vegetable oil into a deep saucepan and heat over medium high heat until it reaches 350 degrees Fahrenheit. Use a thermometer to monitor the temperature and do not let the oil overheat.","timer":300},{"title":"Fry the Egg Rolls","text":"Carefully lower egg rolls into the hot oil in batches of 2 or 3. Fry for about 2 to 3 minutes per side until golden brown and crispy. Remove with a slotted spoon and drain on a paper towel lined plate.","timer":180},{"title":"Dust and Serve","text":"Allow the egg rolls to cool for 2 minutes before dusting generously with powdered sugar. Serve immediately while the outside is still crispy. Pair with a chocolate dipping sauce or vanilla ice cream for extra indulgence.","timer":120}]','[{"original":"vegetable oil","swap":"canola oil or peanut oil"},{"original":"mini chocolate chips","swap":"peanut butter chips or white chocolate chips"},{"original":"brown sugar","swap":"coconut sugar for a slightly less sweet flavor"}]','["Using raw untreated flour which can contain harmful bacteria and is not safe to eat without heat treatment","Overfilling the wrappers which causes them to burst open during frying","Frying at the wrong temperature which results in greasy or burnt egg rolls"]','["dessert","fried","cookie dough","chocolate chip","party food","finger food"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Apple Pie Egg Rolls','apple-pie-egg-rolls','Warm spiced apple filling wrapped in a golden crispy egg roll shell for a handheld twist on a classic dessert. These are perfectly sweet and satisfying with every cinnamon-scented bite.','Golden fried egg rolls packed with cinnamon spiced apple pie filling for an easy crowd-pleasing dessert.','American Fusion','Easy',15,15,30,8,280,3,46,10,2,'[{"amount":8,"unit":"sheets","item":"egg roll wrappers","group":"wrapper"},{"amount":3,"unit":"medium","item":"apples peeled cored and diced small","group":"filling"},{"amount":3,"unit":"tablespoons","item":"unsalted butter","group":"filling"},{"amount":0.33,"unit":"cup","item":"granulated sugar","group":"filling"},{"amount":1.5,"unit":"teaspoons","item":"ground cinnamon","group":"filling"},{"amount":0.25,"unit":"teaspoon","item":"ground nutmeg","group":"filling"},{"amount":1,"unit":"tablespoon","item":"cornstarch","group":"filling"},{"amount":2,"unit":"cups","item":"vegetable oil for frying","group":"frying"},{"amount":3,"unit":"tablespoons","item":"cinnamon sugar for rolling","group":"garnish"}]','[{"title":"Cook the Apple Filling","text":"Melt butter in a skillet over medium heat. Add diced apples, sugar, cinnamon, and nutmeg. Cook for 5 to 7 minutes until the apples are tender. Stir in cornstarch and cook for 1 more minute until the filling thickens. Remove from heat and let cool completely.","timer":420},{"title":"Wrap the Egg Rolls","text":"Place an egg roll wrapper in a diamond shape on a flat surface. Spoon 2 to 3 tablespoons of cooled apple filling into the center. Do not use hot filling as steam will make the wrappers soggy. Fold and roll tightly, sealing the edge with water.","timer":0},{"title":"Heat the Frying Oil","text":"Heat vegetable oil in a deep pot over medium high heat to 350 degrees Fahrenheit. Maintain this temperature throughout frying for the best crispy results.","timer":300},{"title":"Fry Until Golden","text":"Fry egg rolls in small batches for 2 to 3 minutes per side until deep golden brown. Work in batches to avoid crowding the pot which drops the oil temperature. Drain on paper towels immediately after removing from the oil.","timer":180},{"title":"Coat in Cinnamon Sugar and Serve","text":"While still warm, roll each egg roll in cinnamon sugar to coat the outside. Serve immediately with a side of caramel dipping sauce or a scoop of vanilla ice cream.","timer":60}]','[{"original":"fresh apples","swap":"canned apple pie filling for a quicker shortcut"},{"original":"vegetable oil","swap":"canola oil for frying"},{"original":"granulated sugar","swap":"brown sugar for a deeper caramel flavor"}]','["Using hot apple filling which creates steam inside the wrapper and causes soggy or bursting egg rolls","Skipping the cornstarch which leaves the filling watery and messy","Crowding the frying pot which lowers the oil temperature and produces greasy egg rolls"]','["dessert","fried","apple","cinnamon","fall","party food","handheld"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cheesecake Stuffed Strawberries','cheesecake-stuffed-strawberries','Fresh ripe strawberries hollowed out and filled with a rich and creamy no-bake cheesecake mixture. These elegant little bites are perfect for parties, showers, or any occasion that calls for a simple impressive dessert.','Fresh strawberries piped full of fluffy cream cheese filling for a simple no-bake party dessert.','American','Easy',20,0,20,24,60,1,5,4,0,'[{"amount":24,"unit":"large","item":"fresh strawberries hulled","group":"base"},{"amount":8,"unit":"ounces","item":"cream cheese softened","group":"filling"},{"amount":0.5,"unit":"cup","item":"powdered sugar sifted","group":"filling"},{"amount":1,"unit":"teaspoon","item":"vanilla extract","group":"filling"},{"amount":0.5,"unit":"cup","item":"heavy whipping cream","group":"filling"},{"amount":0.25,"unit":"cup","item":"graham cracker crumbs","group":"topping"},{"amount":2,"unit":"tablespoons","item":"mini chocolate chips optional","group":"topping"},{"amount":1,"unit":"tablespoon","item":"lemon juice","group":"filling"}]','[{"title":"Prepare the Strawberries","text":"Wash and dry strawberries thoroughly. Cut a thin slice off the bottom of each strawberry so they stand upright. Use a small paring knife or melon baller to carefully hollow out the inside of each strawberry creating a small cavity for the filling.","timer":0},{"title":"Make the Cheesecake Filling","text":"Beat softened cream cheese with powdered sugar, vanilla extract, and lemon juice using a hand mixer until completely smooth and fluffy. Do not use cold cream cheese as it will leave lumps in the filling.","timer":0},{"title":"Whip and Fold in the Cream","text":"In a separate bowl, whip the heavy cream until stiff peaks form. Gently fold the whipped cream into the cream cheese mixture until fully combined and fluffy. This step gives the filling a light airy texture.","timer":0},{"title":"Pipe the Filling","text":"Transfer the cheesecake filling to a piping bag fitted with a star tip or simply use a zip lock bag with the corner snipped off. Pipe the filling generously into each hollowed strawberry, creating a swirl that rises above the top.","timer":0},{"title":"Garnish and Chill","text":"Sprinkle each filled strawberry with graham cracker crumbs and optional mini chocolate chips. Arrange on a serving platter and refrigerate for at least 15 minutes before serving to allow the filling to set slightly.","timer":900}]','[{"original":"heavy whipping cream","swap":"whipped topping such as Cool Whip for a quicker no-whip option"},{"original":"cream cheese","swap":"mascarpone cheese for a richer and silkier filling"},{"original":"graham cracker crumbs","swap":"crushed golden Oreos or digestive biscuits"}]','["Using cold cream cheese straight from the refrigerator which results in a lumpy filling that does not pipe smoothly","Skipping the step to dry the strawberries which causes the filling to slip and not adhere properly","Hollowing the strawberries too aggressively which breaks through the sides and makes them collapse when filled"]','["dessert","no-bake","strawberry","cheesecake","party food","finger food","Valentine''s Day","bridal shower"]','["vegetarian","gluten-free optional"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Nutella Banana Egg Rolls','nutella-banana-egg-rolls','Crispy fried egg roll wrappers filled with creamy Nutella and fresh banana slices for a decadent dessert. These come together in minutes and taste like a warm chocolate banana crepe in handheld form.','Fried egg rolls stuffed with Nutella and banana for a fast and indulgent dessert that everyone will love.','American Fusion','Easy',10,10,20,6,310,4,40,14,2,'[{"amount":6,"unit":"sheets","item":"egg roll wrappers","group":"wrapper"},{"amount":0.5,"unit":"cup","item":"Nutella or chocolate hazelnut spread","group":"filling"},{"amount":3,"unit":"medium","item":"ripe bananas sliced into coins","group":"filling"},{"amount":2,"unit":"cups","item":"vegetable oil for frying","group":"frying"},{"amount":2,"unit":"tablespoons","item":"powdered sugar","group":"garnish"},{"amount":0.25,"unit":"teaspoon","item":"ground cinnamon","group":"garnish"},{"amount":1,"unit":"tablespoon","item":"water for sealing","group":"wrapper"},{"amount":0.25,"unit":"cup","item":"crushed graham crackers optional topping","group":"garnish"}]','[{"title":"Prep the Filling Ingredients","text":"Slice bananas into quarter inch coins and set aside. Have the Nutella ready at room temperature so it spreads easily. Do not use cold Nutella as it will tear the wrappers when you try to spread it.","timer":0},{"title":"Assemble the Egg Rolls","text":"Lay an egg roll wrapper flat in a diamond shape. Spread about 1 heaping tablespoon of Nutella in the center. Lay 4 to 5 banana slices on top of the Nutella. Fold up the bottom corner, tuck in the sides, and roll tightly. Seal the final corner with a dab of water.","timer":0},{"title":"Heat the Oil","text":"Pour oil into a medium saucepan and heat over medium high heat until it reaches 350 degrees Fahrenheit. Test the temperature with a thermometer for accurate results.","timer":300},{"title":"Fry to Golden Perfection","text":"Carefully slide egg rolls seam side down into the hot oil. Fry 2 to 3 at a time for 2 minutes per side until deeply golden and crispy. Remove with tongs and rest on a paper towel lined plate to drain excess oil.","timer":240},{"title":"Dust and Serve","text":"Mix powdered sugar with cinnamon and dust generously over the warm egg rolls. Serve immediately with a side of vanilla ice cream or a drizzle of extra Nutella for dipping.","timer":60}]','[{"original":"Nutella","swap":"peanut butter or cookie butter spread"},{"original":"banana","swap":"sliced strawberries or pitted cherries"},{"original":"vegetable oil","swap":"coconut oil for a subtle tropical flavor"}]','["Overfilling the wrappers with too many banana slices causing them to tear or burst during frying","Not sealing the edges properly with water which causes the egg rolls to unfold and leak in the oil","Frying at too high a temperature which burns the outside before the inside is warmed through"]','["dessert","fried","Nutella","banana","chocolate","quick","party food"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Strawberry Cheesecake Egg Rolls','strawberry-cheesecake-egg-rolls','Crispy golden egg rolls filled with a luscious cream cheese and fresh strawberry mixture for a dessert mashup that is impossible to resist. Each bite delivers warm creamy filling surrounded by a perfectly crunchy shell.','Fried egg rolls packed with creamy cheesecake filling and fresh strawberries rolled in cinnamon sugar.','American Fusion','Medium',20,15,35,8,295,5,38,13,1,'[{"amount":8,"unit":"sheets","item":"egg roll wrappers","group":"wrapper"},{"amount":8,"unit":"ounces","item":"cream cheese softened","group":"filling"},{"amount":0.33,"unit":"cup","item":"powdered sugar","group":"filling"},{"amount":1,"unit":"teaspoon","item":"vanilla extract","group":"filling"},{"amount":1,"unit":"cup","item":"fresh strawberries diced small","group":"filling"},{"amount":2,"unit":"tablespoons","item":"strawberry jam","group":"filling"},{"amount":2,"unit":"cups","item":"vegetable oil for frying","group":"frying"},{"amount":0.25,"unit":"cup","item":"cinnamon sugar for coating","group":"garnish"},{"amount":1,"unit":"tablespoon","item":"water for sealing wrappers","group":"wrapper"}]','[{"title":"Make the Cheesecake Filling","text":"Beat softened cream cheese, powdered sugar, and vanilla extract with a hand mixer until completely smooth. Fold in diced strawberries and strawberry jam. Refrigerate the filling for 10 minutes so it firms up slightly and is easier to work with.","timer":600},{"title":"Fill and Roll","text":"Place an egg roll wrapper in a diamond orientation on a clean surface. Spoon about 2 heaping tablespoons of chilled filling into the center. Do not add too much filling or the wrapper will not seal properly. Fold, tuck, and roll tightly, sealing the end with water.","timer":0},{"title":"Heat Oil for Frying","text":"Add vegetable oil to a deep saucepan and heat over medium high heat to 350 degrees Fahrenheit. Use a kitchen thermometer to verify the temperature before adding the egg rolls.","timer":300},{"title":"Fry Until Crispy","text":"Fry egg rolls in batches of 2 to 3 for about 2 to 3 minutes per side until they are a deep golden brown. Remove carefully and drain on paper towels. Do not stack the hot egg rolls or they will lose their crispiness.","timer":180},{"title":"Coat and Serve","text":"While still warm roll each egg roll in cinnamon sugar until evenly coated. Plate and serve immediately alongside a bowl of extra strawberry jam or whipped cream for dipping.","timer":60}]','[{"original":"fresh strawberries","swap":"frozen strawberries thawed and drained well"},{"original":"cream cheese","swap":"ricotta cheese for a lighter texture"},{"original":"strawberry jam","swap":"raspberry preserves for a tangier flavor"}]','["Using warm filling straight away without chilling it which makes it runny and difficult to keep inside the wrapper","Adding too much filling which prevents the wrapper from sealing and causes blowouts in the hot oil","Not patting strawberries dry before using them which adds excess moisture and makes the filling watery"]','["dessert","fried","strawberry","cheesecake","party food","finger food","summer"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Brownie Brittle Nachos','brownie-brittle-nachos','Crispy brownie brittle shards topped with warm fudge, colorful candies, and a drizzle of white chocolate. This dessert nacho platter is perfect for sharing at parties.','A fun and shareable dessert platter made with crunchy brownie brittle loaded with sweet toppings.','American','Easy',15,20,35,6,420,5,58,19,2,'[{"amount":2,"unit":"cups","item":"brownie brittle pieces","group":"base"},{"amount":0.5,"unit":"cup","item":"hot fudge sauce","group":"topping"},{"amount":0.5,"unit":"cup","item":"white chocolate chips","group":"topping"},{"amount":0.25,"unit":"cup","item":"mini M and M candies","group":"topping"},{"amount":0.25,"unit":"cup","item":"rainbow sprinkles","group":"topping"},{"amount":0.5,"unit":"cup","item":"mini marshmallows","group":"topping"},{"amount":1,"unit":"tablespoon","item":"coconut oil","group":"sauce"},{"amount":2,"unit":"scoops","item":"vanilla ice cream","group":"serving"}]','[{"title":"Prepare the Base","text":"Spread brownie brittle pieces in a single layer on a large serving platter or baking sheet, overlapping slightly like nachos.","timer":0},{"title":"Warm the Fudge","text":"Combine hot fudge sauce with coconut oil in a microwave-safe bowl. Heat in 20-second intervals, stirring between each, until smooth and pourable.","timer":60},{"title":"Melt White Chocolate","text":"Melt white chocolate chips in a separate microwave-safe bowl in 20-second intervals, stirring until fully smooth. Transfer to a small piping bag or zip-lock bag with a corner snipped.","timer":60},{"title":"Add the Toppings","text":"Drizzle hot fudge over the brittle base, then pipe white chocolate in a zigzag pattern. Scatter mini M and M candies, mini marshmallows, and rainbow sprinkles evenly across the platter.","timer":0},{"title":"Serve Immediately","text":"Add scoops of vanilla ice cream on top of the platter just before serving. Serve right away so the brittle stays crunchy.","timer":0}]','[{"original":"brownie brittle","swap":"chocolate graham crackers broken into shards"},{"original":"mini M and M candies","swap":"chopped Reese''s Pieces"},{"original":"white chocolate chips","swap":"caramel sauce drizzle"}]','["Letting the hot fudge sit too long before drizzling causes it to harden and clump rather than drizzle smoothly","Piling toppings too thick in the center and leaving the edges bare creates uneven bites","Adding ice cream too early causes the brittle to become soggy before serving"]','["dessert nachos","party dessert","brownie","sharing platter","no bake toppings"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Churro Ice Cream Bowls','churro-ice-cream-bowls','Golden fried dough bowls coated in cinnamon sugar and filled with scoops of rich ice cream. These edible churro cups bring a fairground classic to your dinner table.','Crispy cinnamon sugar churro bowls filled with creamy ice cream for an indulgent handheld dessert.','Mexican-American','Medium',20,25,45,4,510,7,62,26,1,'[{"amount":1,"unit":"cup","item":"all-purpose flour","group":"dough"},{"amount":1,"unit":"cup","item":"water","group":"dough"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"dough"},{"amount":2,"unit":"tablespoons","item":"unsalted butter","group":"dough"},{"amount":2,"unit":"cups","item":"vegetable oil for frying","group":"frying"},{"amount":0.5,"unit":"cup","item":"granulated sugar","group":"coating"},{"amount":1.5,"unit":"teaspoons","item":"ground cinnamon","group":"coating"},{"amount":4,"unit":"scoops","item":"dulce de leche ice cream","group":"filling"}]','[{"title":"Make the Choux Dough","text":"Combine water, butter, and salt in a medium saucepan over medium heat. Bring to a boil, then remove from heat and stir in flour until a smooth dough ball forms. Let it cool for 5 minutes.","timer":300},{"title":"Shape the Bowls","text":"Press the dough evenly around the outside of greased upside-down muffin tin cups or small oven-safe bowls, forming a thin shell. Aim for an even thickness so they fry uniformly.","timer":0},{"title":"Fry the Bowls","text":"Heat vegetable oil in a deep pot to 375 degrees Fahrenheit. Carefully lower each dough shell into the oil and fry for 3 to 4 minutes per side until deep golden brown. Do not overcrowd the pot.","timer":240},{"title":"Coat in Cinnamon Sugar","text":"Mix granulated sugar and ground cinnamon in a shallow dish. While the fried bowls are still warm, gently roll and press them in the cinnamon sugar until fully coated on all sides.","timer":0},{"title":"Fill and Serve","text":"Allow the coated bowls to cool for 2 minutes so the ice cream does not melt instantly upon contact. Place one scoop of dulce de leche ice cream inside each bowl and serve immediately.","timer":120}]','[{"original":"dulce de leche ice cream","swap":"cinnamon vanilla ice cream"},{"original":"all-purpose flour","swap":"gluten-free 1-to-1 baking flour"},{"original":"vegetable oil","swap":"canola oil for frying"}]','["Frying at too low a temperature results in greasy bowls that do not crisp up properly","Making the dough walls too thick causes the inside to remain doughy and undercooked","Coating the bowls in cinnamon sugar after they have cooled completely means the coating does not adhere well"]','["churro","ice cream","fried dessert","edible bowl","cinnamon sugar"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Peanut Butter Cup Lava Cake','peanut-butter-cup-lava-cake','Warm chocolate cakes with a molten peanut butter center that flows out with every spoonful. Each individual cake hides a full peanut butter cup inside for a gooey surprise.','Decadent individual chocolate cakes with a flowing peanut butter molten center baked in minutes.','American','Medium',15,12,27,4,580,10,52,38,3,'[{"amount":4,"unit":"ounces","item":"dark chocolate chips","group":"batter"},{"amount":0.5,"unit":"cup","item":"unsalted butter","group":"batter"},{"amount":2,"unit":"whole","item":"large eggs","group":"batter"},{"amount":2,"unit":"whole","item":"egg yolks","group":"batter"},{"amount":0.25,"unit":"cup","item":"granulated sugar","group":"batter"},{"amount":2,"unit":"tablespoons","item":"all-purpose flour","group":"batter"},{"amount":4,"unit":"whole","item":"full-size peanut butter cups unwrapped","group":"filling"},{"amount":1,"unit":"teaspoon","item":"cocoa powder for dusting","group":"prep"}]','[{"title":"Prep the Ramekins","text":"Preheat oven to 425 degrees Fahrenheit. Grease four 6-ounce ramekins thoroughly with butter, then dust each one with cocoa powder, tapping out any excess. This ensures the cakes release cleanly.","timer":0},{"title":"Melt Chocolate and Butter","text":"Combine dark chocolate chips and butter in a heatproof bowl set over a saucepan of simmering water. Stir constantly until fully melted and smooth. Remove from heat and let cool for 2 minutes.","timer":120},{"title":"Mix the Batter","text":"Whisk together eggs, egg yolks, and granulated sugar in a large bowl until pale and slightly thickened. Fold in the melted chocolate mixture, then gently fold in flour until just combined. Do not overmix.","timer":0},{"title":"Fill and Add Peanut Butter Cup","text":"Pour batter into each prepared ramekin until half full. Press one unwrapped peanut butter cup into the center of each, then cover with remaining batter so the cup is fully submerged.","timer":0},{"title":"Bake and Unmold","text":"Bake for 11 to 12 minutes until the edges are set but the center still has a slight jiggle. Run a knife around the edge of each ramekin and invert onto a dessert plate. Serve within 60 seconds.","timer":720}]','[{"original":"dark chocolate chips","swap":"semi-sweet chocolate chips for a milder flavor"},{"original":"full-size peanut butter cups","swap":"a tablespoon of peanut butter mixed with powdered sugar frozen into a disk"},{"original":"all-purpose flour","swap":"almond flour for a denser gluten-free version"}]','["Overbaking by even one minute causes the center to set fully and eliminates the molten lava effect","Not greasing the ramekins thoroughly enough causes the cake to stick and tear when unmolded","Using cold eggs straight from the refrigerator makes it harder to incorporate them into the batter smoothly"]','["lava cake","molten cake","peanut butter","chocolate","individual dessert"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Strawberry Shortcake Skillet','strawberry-shortcake-skillet','A buttery golden biscuit cake baked in a cast iron skillet and topped with fresh macerated strawberries and whipped cream. This rustic one-pan dessert comes together with simple pantry ingredients.','A golden cast iron biscuit cake topped with juicy strawberries and fluffy whipped cream.','American','Easy',20,25,45,6,390,6,47,20,2,'[{"amount":2,"unit":"cups","item":"all-purpose flour","group":"biscuit"},{"amount":1,"unit":"tablespoon","item":"baking powder","group":"biscuit"},{"amount":3,"unit":"tablespoons","item":"granulated sugar","group":"biscuit"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"biscuit"},{"amount":0.5,"unit":"cup","item":"cold unsalted butter cubed","group":"biscuit"},{"amount":0.75,"unit":"cup","item":"whole milk","group":"biscuit"},{"amount":2,"unit":"cups","item":"fresh strawberries hulled and sliced","group":"topping"},{"amount":1,"unit":"cup","item":"heavy whipping cream","group":"topping"}]','[{"title":"Macerate the Strawberries","text":"Toss sliced strawberries with one tablespoon of granulated sugar in a bowl. Let them sit at room temperature for at least 15 minutes so they release their juices and become syrupy.","timer":900},{"title":"Make the Biscuit Dough","text":"Whisk together flour, baking powder, remaining sugar, and salt in a large bowl. Cut in cold butter using a pastry cutter or your fingers until the mixture resembles coarse crumbs. Stir in milk until a shaggy dough just forms.","timer":0},{"title":"Bake in the Skillet","text":"Preheat oven to 400 degrees Fahrenheit. Press biscuit dough evenly into a well-buttered 10-inch cast iron skillet. Bake for 22 to 25 minutes until the top is golden brown and a toothpick inserted in the center comes out clean.","timer":1500},{"title":"Whip the Cream","text":"While the skillet bakes, whip heavy cream with a hand mixer on medium-high speed until soft peaks form. Do not overwhip or the cream will become grainy and butter-like.","timer":180},{"title":"Assemble and Serve","text":"Allow the baked skillet cake to cool for 5 minutes. Spoon macerated strawberries and all their collected juices over the top, then dollop generously with whipped cream. Serve directly from the skillet.","timer":300}]','[{"original":"fresh strawberries","swap":"fresh peaches or mixed berries"},{"original":"whole milk","swap":"buttermilk for a tangier biscuit flavor"},{"original":"heavy whipping cream","swap":"store-bought whipped topping for convenience"}]','["Using warm or melted butter instead of cold butter prevents the biscuit from developing its flaky tender texture","Overmixing the dough after adding the milk develops gluten and results in a tough dense cake","Skipping the macerating step means the strawberries will be less juicy and flavorful on top"]','["strawberry","shortcake","skillet dessert","biscuit","summer dessert"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('S''mores Cookie Bars','smores-cookie-bars','Thick and chewy cookie bars layered with graham cracker crumbs, melty chocolate, and toasted marshmallow on top. Every bite delivers the classic campfire flavor without the bonfire.','Chewy layered cookie bars packed with graham cracker, chocolate, and toasted marshmallow flavors.','American','Easy',15,25,40,12,310,4,43,14,1,'[{"amount":1.5,"unit":"cups","item":"graham cracker crumbs","group":"base"},{"amount":0.5,"unit":"cup","item":"unsalted butter melted","group":"base"},{"amount":0.25,"unit":"cup","item":"granulated sugar","group":"base"},{"amount":1,"unit":"cup","item":"semi-sweet chocolate chips","group":"filling"},{"amount":2,"unit":"cups","item":"mini marshmallows","group":"topping"},{"amount":0.5,"unit":"cup","item":"brown sugar packed","group":"cookie layer"},{"amount":1,"unit":"whole","item":"large egg","group":"cookie layer"},{"amount":1,"unit":"teaspoon","item":"vanilla extract","group":"cookie layer"}]','[{"title":"Prepare the Graham Cracker Crust","text":"Preheat oven to 350 degrees Fahrenheit. Line an 8x8 inch baking pan with parchment paper. Mix graham cracker crumbs, melted butter, and granulated sugar until combined. Press firmly into the bottom of the pan.","timer":0},{"title":"Mix the Cookie Layer","text":"In a bowl, stir together remaining melted butter, brown sugar, egg, and vanilla extract until smooth. Fold in half the chocolate chips. Spread this mixture evenly over the graham cracker crust.","timer":0},{"title":"Add Chocolate Layer","text":"Scatter the remaining semi-sweet chocolate chips evenly over the cookie batter layer. This creates an extra burst of melted chocolate throughout each bar.","timer":0},{"title":"Bake Until Set","text":"Bake for 20 to 22 minutes until the edges are golden and the center appears mostly set but still slightly soft. Remove from oven and immediately scatter mini marshmallows evenly across the top.","timer":1320},{"title":"Toast the Marshmallows","text":"Switch the oven to broil on high. Return the pan to the oven and broil for 60 to 90 seconds, watching constantly, until marshmallows are puffed and golden brown. Do not walk away as they burn quickly. Cool for 10 minutes before slicing.","timer":90}]','[{"original":"semi-sweet chocolate chips","swap":"milk chocolate chips for a sweeter bar"},{"original":"mini marshmallows","swap":"large marshmallows cut in half with scissors"},{"original":"graham cracker crumbs","swap":"digestive biscuit crumbs for a similar texture"}]','["Pressing the graham cracker crust too loosely means it will crumble apart when the bars are sliced","Overbaking the cookie layer before adding marshmallows results in dry crumbly bars","Walking away during broiling even briefly risks burning the marshmallows to black in under a minute"]','["smores","cookie bars","marshmallow","chocolate","baked dessert","campfire inspired"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Oklahoma Fried Onion Burger','classic-oklahoma-fried-onion-burger','A smash-style burger pressed into a mountain of thinly sliced onions that caramelize right into the patty. This Depression-era Oklahoma staple delivers intense savory flavor in every bite.','A smashed beef patty cooked into caramelized onions on a griddle for a deeply savory Oklahoma classic.','American','Easy',10,15,25,4,520,28,32,30,2,'[{"amount":1.5,"unit":"lb","item":"80/20 ground beef","group":"Patty"},{"amount":2,"unit":"large","item":"yellow onions thinly sliced","group":"Patty"},{"amount":1,"unit":"tsp","item":"kosher salt","group":"Patty"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"Patty"},{"amount":4,"unit":"slices","item":"American cheese","group":"Toppings"},{"amount":4,"unit":"tbsp","item":"yellow mustard","group":"Sauce"},{"amount":4,"unit":"tbsp","item":"mayonnaise","group":"Sauce"},{"amount":4,"unit":"whole","item":"soft hamburger buns","group":"Buns"}]','[{"title":"Portion and prep the beef","text":"Divide the ground beef into 4 equal balls of about 6 ounces each. Do not overwork the meat. Season each ball generously with salt and pepper on all sides. Set aside at room temperature while you prep the onions.","timer":0},{"title":"Pile onions onto the griddle","text":"Heat a cast iron skillet or griddle over high heat until smoking hot. Place a large mound of sliced onions directly on the dry griddle. Set one beef ball on top of each onion mound and immediately smash it down hard with a spatula, pressing the onions into the patty.","timer":60},{"title":"Cook the first side","text":"Let the patty cook undisturbed for 3 to 4 minutes. The onions will begin to steam and caramelize against the hot griddle while the beef develops a deep brown crust. Do not move or press the burger again during this time.","timer":210},{"title":"Flip and add cheese","text":"Carefully scrape and flip the patty so the onion side faces up. Immediately lay a slice of American cheese over the onions. Cook for 1 to 2 more minutes until the cheese melts fully and the bottom of the patty is cooked through.","timer":90},{"title":"Toast buns and assemble","text":"Toast the buns cut-side down on the same griddle for 30 seconds. Spread mustard on the bottom bun and mayonnaise on the top bun. Place the burger patty onion-side up on the bottom bun and close with the top bun. Serve immediately.","timer":30}]','[{"original":"yellow onions","swap":"white onions for a sharper more pungent flavor"},{"original":"American cheese","swap":"white cheddar for a sharper taste"},{"original":"80/20 ground beef","swap":"85/15 ground beef for a slightly leaner patty"}]','["Not getting the griddle hot enough before adding the onions and beef","Pressing the burger more than once which squeezes out all the juices","Slicing the onions too thick so they do not soften properly during cooking"]','["burger","smash burger","oklahoma","comfort food","griddle","onion"]','["Dairy-Free Option"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('NYC Chopped Cheese','nyc-chopped-cheese','A New York City bodega icon made from ground beef chopped and mixed with onions and American cheese on a griddle. It is served on a hoagie roll with all the fixings.','Ground beef chopped with onions and melted American cheese stuffed into a toasted hoagie roll Harlem-style.','American','Easy',10,12,22,2,780,42,52,42,3,'[{"amount":1,"unit":"lb","item":"80/20 ground beef","group":"Filling"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"Filling"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"kosher salt","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"Seasoning"},{"amount":4,"unit":"slices","item":"American cheese","group":"Filling"},{"amount":2,"unit":"whole","item":"hero or hoagie rolls","group":"Bread"},{"amount":2,"unit":"tbsp","item":"ketchup","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"mayonnaise","group":"Sauce"}]','[{"title":"Cook the onions","text":"Heat a cast iron skillet or flat griddle over medium-high heat. Add the diced onions with a small drizzle of oil and cook for 3 to 4 minutes stirring occasionally until they are softened and beginning to turn golden at the edges.","timer":240},{"title":"Add and brown the beef","text":"Add the ground beef directly on top of the onions. Season with garlic powder, salt, and pepper. Let the beef cook without stirring for 2 minutes to develop browning on the bottom, then break it apart and mix it with the onions.","timer":180},{"title":"Chop and combine","text":"Using a stiff spatula or bench scraper, chop and fold the beef and onions together repeatedly until the mixture is finely broken down and well combined. This chopping action is what defines the texture of a proper chopped cheese.","timer":60},{"title":"Melt the cheese","text":"Shape the beef mixture into two mounds roughly the length of your rolls. Lay 2 slices of American cheese over each mound. Cover with a dome lid or a metal bowl for 30 seconds to trap steam and melt the cheese completely.","timer":30},{"title":"Load the roll and serve","text":"Toast the inside of the hero rolls on the griddle for 30 seconds. Spread mayo on one side and ketchup on the other. Use a spatula to slide each cheese-covered mound into a roll. Add shredded lettuce and sliced tomato if desired and serve immediately.","timer":30}]','[{"original":"American cheese","swap":"Velveeta slices for an even creamier melt"},{"original":"hero roll","swap":"a toasted sub roll or thick Italian bread"},{"original":"ketchup","swap":"hot sauce for a spicier bodega-style version"}]','["Not chopping the beef finely enough which makes the texture too chunky","Skipping the cheese-melting step with a cover which results in unmelted cheese","Using lean ground beef which makes the filling dry instead of juicy"]','["chopped cheese","nyc","bodega","street food","sandwich","ground beef"]','[]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Juicy Lucy Burger','juicy-lucy-burger','A Minneapolis legend where molten cheese is sealed inside the beef patty itself rather than placed on top. Biting into it releases a lava-like flood of cheese that is pure burger magic.','Two thin beef patties sealed around a core of American cheese to create a burger with a molten cheese center.','American','Medium',15,12,27,4,610,34,30,38,1,'[{"amount":2,"unit":"lb","item":"80/20 ground beef","group":"Patty"},{"amount":8,"unit":"slices","item":"American cheese folded into quarters","group":"Filling"},{"amount":1,"unit":"tsp","item":"kosher salt","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"onion powder","group":"Seasoning"},{"amount":4,"unit":"whole","item":"soft hamburger buns","group":"Buns"},{"amount":4,"unit":"tbsp","item":"yellow mustard","group":"Condiments"},{"amount":4,"unit":"tbsp","item":"dill pickle slices","group":"Toppings"}]','[{"title":"Form the thin patties","text":"Divide the beef into 8 equal portions of 4 ounces each. Gently flatten each portion into a thin round patty about 4 inches in diameter. Do not overwork the meat or the patties will become tough. Season the outsides lightly with salt, pepper, and onion powder.","timer":0},{"title":"Stuff and seal the burgers","text":"Place 2 folded slices of American cheese in the center of 4 patties leaving a half-inch border around the edge. Top each with a second patty. Firmly pinch and crimp the edges all the way around to form a tight seal. Make sure there are no gaps where cheese can escape.","timer":0},{"title":"Cook the first side","text":"Heat a cast iron skillet over medium-high heat. Cook the stuffed patties for 5 to 6 minutes on the first side without pressing. Pressing will force the seal to break and the cheese will leak out onto the pan.","timer":330},{"title":"Flip and finish cooking","text":"Carefully flip each burger once. Cook for another 5 to 6 minutes until the internal temperature reaches 160 degrees Fahrenheit. Let the burgers rest in the pan off the heat for 2 minutes. Warn anyone eating that the cheese inside will be extremely hot.","timer":360},{"title":"Toast buns and serve","text":"Toast the buns cut-side down in the same pan for 30 seconds. Add mustard and pickles to the bottom bun. Set the Juicy Lucy on top and close the bun. Instruct guests to wait 2 minutes before biting in so the molten cheese does not burn them.","timer":30}]','[{"original":"American cheese","swap":"pepper jack cheese for a spicy molten center"},{"original":"80/20 ground beef","swap":"a blend of ground chuck and ground brisket for richer flavor"},{"original":"yellow mustard","swap":"spicy brown mustard for extra punch"}]','["Not sealing the edges tightly enough which causes the cheese to burst out during cooking","Pressing the burger while it cooks which breaks the seal and loses all the cheese","Biting into the burger immediately without resting it which results in a severe cheese burn"]','["juicy lucy","minneapolis","stuffed burger","cheese burger","comfort food","cast iron"]','[]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Smash Burger with Special Sauce','smash-burger-with-special-sauce','A thin crispy-edged smash burger with a lacy caramelized crust and a tangy homemade special sauce. This fast-food-inspired recipe uses simple techniques that deliver maximum flavor.','A griddle-smashed beef patty with a crispy lacey crust served with a creamy tangy special sauce.','American','Easy',10,10,20,4,570,26,34,34,2,'[{"amount":1.5,"unit":"lb","item":"80/20 ground beef","group":"Patty"},{"amount":1,"unit":"tsp","item":"kosher salt","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"Seasoning"},{"amount":4,"unit":"slices","item":"American cheese","group":"Toppings"},{"amount":4,"unit":"tbsp","item":"mayonnaise","group":"Special Sauce"},{"amount":2,"unit":"tbsp","item":"ketchup","group":"Special Sauce"},{"amount":1,"unit":"tbsp","item":"sweet pickle relish","group":"Special Sauce"},{"amount":4,"unit":"whole","item":"brioche buns","group":"Buns"}]','[{"title":"Make the special sauce","text":"In a small bowl combine the mayonnaise, ketchup, and sweet pickle relish. Stir until fully blended and smooth. Taste and adjust with a pinch of salt if needed. Refrigerate until ready to use. This sauce can be made up to 3 days ahead.","timer":0},{"title":"Portion the beef","text":"Divide the ground beef into 4 equal balls of about 6 ounces. Do not season or shape them yet. Keep them loose and do not compact the balls tightly. Season with salt and pepper only on the outside of each ball right before cooking.","timer":0},{"title":"Smash and sear","text":"Heat a cast iron skillet or griddle over high heat until it is smoking. Place a beef ball on the surface and immediately smash it flat with a heavy spatula pressing down firmly for 10 full seconds. The patty should be very thin with ragged lacy edges. Cook undisturbed for 2 minutes.","timer":120},{"title":"Flip and add cheese","text":"Scrape the patty from the griddle using a thin metal spatula and flip it in one quick motion. Place a slice of American cheese immediately on top. Cook for 1 more minute until the cheese is fully melted and the bottom has a good crust.","timer":60},{"title":"Toast and assemble","text":"Toast the brioche buns cut-side down on the griddle for 20 to 30 seconds until golden. Spread special sauce on both cut sides. Layer the burger patty on the bottom bun and top with shredded lettuce and thinly sliced white onion before closing the bun.","timer":30}]','[{"original":"brioche buns","swap":"potato rolls for a softer slightly sweet bun"},{"original":"sweet pickle relish","swap":"finely diced dill pickles for a tangier sauce"},{"original":"American cheese","swap":"Muenster cheese for a milder creamier melt"}]','["Not heating the griddle hot enough before smashing which prevents the Maillard crust from forming","Pressing the burger after the initial smash which removes the juices instead of sealing them","Using lean ground beef which produces a dry patty without enough fat for a proper crust"]','["smash burger","special sauce","fast food","griddle","comfort food","american"]','[]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Steakhouse Mushroom Swiss Burger','steakhouse-mushroom-swiss-burger','A thick steakhouse-style beef patty topped with buttery sauteed mushrooms and melted Swiss cheese. This elevated burger brings restaurant quality results to your home kitchen.','A thick juicy beef patty topped with garlic butter mushrooms and melted Swiss cheese on a toasted brioche bun.','American','Medium',15,18,33,4,680,38,35,42,2,'[{"amount":2,"unit":"lb","item":"80/20 ground beef","group":"Patty"},{"amount":8,"unit":"oz","item":"cremini mushrooms sliced","group":"Topping"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"Topping"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"Topping"},{"amount":1,"unit":"tsp","item":"Worcestershire sauce","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"kosher salt","group":"Seasoning"},{"amount":4,"unit":"slices","item":"Swiss cheese","group":"Topping"},{"amount":4,"unit":"whole","item":"brioche buns","group":"Buns"}]','[{"title":"Shape and season the patties","text":"Divide the ground beef into 4 equal portions of 8 ounces each. Gently shape into round patties about three-quarters of an inch thick. Press a slight dimple into the center of each patty with your thumb to prevent doming during cooking. Season both sides generously with salt and pepper.","timer":0},{"title":"Saute the mushrooms","text":"Melt the butter in a skillet over medium-high heat. Add the sliced mushrooms in a single layer and do not stir for 2 minutes to allow browning. Then add the minced garlic and Worcestershire sauce. Toss and cook for another 3 to 4 minutes until the mushrooms are golden and all liquid has evaporated.","timer":360},{"title":"Cook the patties","text":"Heat a separate cast iron skillet over high heat. Sear the patties for 4 minutes per side for medium doneness. Do not press the patties or move them during the first 4 minutes of cooking. Use a thermometer and target an internal temperature of 155 degrees Fahrenheit.","timer":480},{"title":"Melt the cheese","text":"During the last minute of cooking place a slice of Swiss cheese on each patty. Spoon a portion of the garlic mushrooms on top of the cheese. Cover the pan with a lid for 45 seconds to trap steam and melt the cheese fully around the mushrooms.","timer":45},{"title":"Toast buns and serve","text":"Toast the brioche buns cut-side down in the same skillet for 30 seconds. Spread a thin layer of mayonnaise on the bottom bun and Dijon mustard on the top bun. Place the patty loaded with mushrooms and cheese on the bottom bun and serve immediately.","timer":30}]','[{"original":"cremini mushrooms","swap":"portobello mushrooms sliced for a meatier texture"},{"original":"Swiss cheese","swap":"Gruyere for a nuttier more complex flavor"},{"original":"brioche buns","swap":"pretzel buns for a chewier saltier contrast"}]','["Crowding the mushrooms in the pan which causes them to steam instead of brown","Skipping the dimple in the center of the patty which causes it to puff up into a meatball shape","Flipping the patty multiple times which prevents a proper steakhouse sear from forming"]','["mushroom swiss","steakhouse burger","cast iron","comfort food","american","weeknight dinner"]','[]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Patty Melt','classic-patty-melt','A diner-style sandwich with a seasoned beef patty, caramelized onions, and melted Swiss cheese pressed between rye bread. This comfort food classic is crispy on the outside and rich on the inside.','A crispy rye bread sandwich loaded with beef, Swiss cheese, and sweet caramelized onions.','American','Medium',10,40,50,2,720,38,42,44,3,'[{"amount":1,"unit":"lb","item":"ground beef 80/20","group":"patty"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"patty"},{"amount":1,"unit":"tsp","item":"salt","group":"patty"},{"amount":1,"unit":"tsp","item":"black pepper","group":"patty"},{"amount":2,"unit":"large","item":"yellow onions sliced thin","group":"filling"},{"amount":4,"unit":"slices","item":"Swiss cheese","group":"filling"},{"amount":4,"unit":"slices","item":"rye bread","group":"bread"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"bread"}]','[{"title":"Caramelize the Onions","text":"Melt 1 tablespoon of butter in a skillet over medium-low heat. Add sliced onions and cook slowly, stirring every few minutes, until deep golden and sweet. Do not rush this step or the onions will burn instead of caramelize.","timer":1800},{"title":"Form and Season the Patties","text":"Divide the ground beef into two equal portions and press each into a thin oval patty slightly larger than your bread slices. Season both sides generously with garlic powder, salt, and black pepper.","timer":0},{"title":"Cook the Patties","text":"Heat a cast iron skillet over medium-high heat. Cook patties for 3 to 4 minutes per side until cooked through. Remove from pan and set aside. Do not press down on the patties while cooking.","timer":480},{"title":"Assemble the Melts","text":"Butter one side of each bread slice. On the unbuttered side, layer one slice of Swiss cheese, a cooked patty, a generous scoop of caramelized onions, another slice of Swiss cheese, and top with the second bread slice buttered side up.","timer":0},{"title":"Press and Grill","text":"Cook assembled sandwiches in the same skillet over medium heat for 3 to 4 minutes per side, pressing gently with a spatula, until both sides are deep golden brown and cheese is fully melted.","timer":480}]','[{"original":"Swiss cheese","swap":"American cheese or provolone"},{"original":"rye bread","swap":"sourdough or Texas toast"},{"original":"ground beef","swap":"ground turkey for a lighter option"}]','["Rushing the caramelized onions over high heat results in burnt bitter onions instead of sweet golden ones","Making patties too thick causes them to be undercooked in the center before the bread browns","Using too much butter causes the bread to become soggy rather than crispy and golden"]','["diner","comfort food","beef","sandwich","skillet"]','["gluten-containing"]','Sandwiches','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('New Mexico Green Chile Cheeseburger','new-mexico-green-chile-cheeseburger','A bold and smoky burger topped with roasted Hatch green chiles and melted pepper jack cheese on a toasted brioche bun. This New Mexico classic delivers heat, flavor, and satisfying richness in every bite.','A smoky beef burger loaded with roasted green chiles and melted pepper jack on a brioche bun.','American Southwest','Medium',15,20,35,4,680,42,38,38,2,'[{"amount":1.5,"unit":"lbs","item":"ground beef 80/20","group":"patty"},{"amount":1,"unit":"tsp","item":"cumin","group":"patty"},{"amount":1,"unit":"tsp","item":"salt","group":"patty"},{"amount":1,"unit":"tsp","item":"black pepper","group":"patty"},{"amount":4,"unit":"whole","item":"Hatch green chiles roasted and peeled","group":"topping"},{"amount":4,"unit":"slices","item":"pepper jack cheese","group":"topping"},{"amount":4,"unit":"whole","item":"brioche burger buns","group":"bun"},{"amount":2,"unit":"tbsp","item":"mayonnaise","group":"sauce"}]','[{"title":"Roast the Green Chiles","text":"Place whole chiles directly over a gas flame or under the broiler, turning with tongs until the skin is blackened and blistered on all sides. Place in a covered bowl for 10 minutes to steam, then peel, seed, and slice them open flat.","timer":600},{"title":"Form the Patties","text":"Divide ground beef into four equal portions. Gently form each into a patty about three quarters of an inch thick, pressing a slight dimple in the center with your thumb. Season both sides with cumin, salt, and pepper.","timer":0},{"title":"Grill the Patties","text":"Heat a grill or cast iron skillet to high heat. Cook patties for 3 to 4 minutes on the first side without moving them. Flip once and cook 3 more minutes. Do not press the patties with a spatula as this squeezes out the juices.","timer":420},{"title":"Add Chile and Cheese","text":"In the last 90 seconds of cooking, place a roasted green chile slice on each patty followed by a slice of pepper jack cheese. Cover the pan or close the grill lid to melt the cheese fully.","timer":90},{"title":"Toast and Assemble","text":"Toast the brioche buns cut side down on the grill or in a dry skillet until golden. Spread mayonnaise on the bottom bun, add the patty with chile and cheese, and serve immediately while hot.","timer":120}]','[{"original":"Hatch green chiles","swap":"canned roasted green chiles or poblano peppers"},{"original":"pepper jack cheese","swap":"Monterey Jack or white cheddar"},{"original":"brioche buns","swap":"potato rolls or sesame seed buns"}]','["Skipping the steaming step after roasting makes it very difficult to peel the chile skins","Pressing down on patties while grilling forces out moisture and results in dry burgers","Adding cheese too early causes it to burn before the patty is fully cooked"]','["burger","green chile","New Mexico","grilled","spicy"]','["gluten-containing"]','Burgers','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Southern Pimento Cheese Burger','southern-pimento-cheese-burger','A Southern-inspired burger piled high with creamy homemade pimento cheese that melts beautifully over a juicy smash patty. The tangy spread adds bold flavor and a velvety richness that sets this burger apart.','A smash burger topped with rich homemade pimento cheese spread for a classic Southern twist.','American Southern','Easy',15,15,30,4,710,40,36,45,1,'[{"amount":1.5,"unit":"lbs","item":"ground beef 80/20","group":"patty"},{"amount":1,"unit":"tsp","item":"salt","group":"patty"},{"amount":1,"unit":"tsp","item":"black pepper","group":"patty"},{"amount":1.5,"unit":"cups","item":"shredded sharp cheddar cheese","group":"pimento cheese"},{"amount":4,"unit":"oz","item":"diced pimentos drained","group":"pimento cheese"},{"amount":4,"unit":"tbsp","item":"mayonnaise","group":"pimento cheese"},{"amount":0.5,"unit":"tsp","item":"cayenne pepper","group":"pimento cheese"},{"amount":4,"unit":"whole","item":"potato burger buns toasted","group":"bun"}]','[{"title":"Make the Pimento Cheese","text":"Combine shredded sharp cheddar, drained diced pimentos, mayonnaise, and cayenne pepper in a bowl. Stir until fully mixed and creamy. Do not use pre-shredded cheese as the coating prevents it from blending smoothly. Refrigerate until ready to use.","timer":0},{"title":"Portion the Beef","text":"Divide the ground beef into four loose 6-ounce balls. Do not overwork or tightly pack the meat as this leads to a dense and tough patty instead of a juicy smash burger.","timer":0},{"title":"Smash and Cook","text":"Heat a cast iron skillet or griddle over high heat until smoking hot. Place a beef ball on the surface and immediately smash it flat with a heavy spatula using firm pressure. Season with salt and pepper and cook for 2 minutes until edges are crispy and brown.","timer":120},{"title":"Flip and Add Pimento Cheese","text":"Flip the patty and immediately add a generous spoonful of pimento cheese on top. Cook for 90 more seconds. The residual heat will melt and soften the cheese into a luscious topping.","timer":90},{"title":"Toast Buns and Assemble","text":"Toast potato buns cut side down in the same skillet for 30 seconds. Place the pimento cheese patty on the bottom bun and serve immediately. Add pickles or sliced onion if desired.","timer":30}]','[{"original":"sharp cheddar","swap":"white cheddar or smoked gouda for a different flavor profile"},{"original":"diced pimentos","swap":"roasted red peppers finely chopped"},{"original":"potato buns","swap":"brioche buns or sesame seed buns"}]','["Using pre-shredded cheese which contains anti-caking agents that prevent the pimento cheese from coming together smoothly","Not heating the skillet hot enough before smashing which prevents the signature crispy crust from forming","Overworking the beef when forming balls which creates a dense and tough patty texture"]','["smash burger","Southern","pimento cheese","comfort food","beef"]','["gluten-containing"]','Burgers','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Mushroom Swiss Burger','mushroom-swiss-burger','A hearty pub-style burger topped with buttery sauteed cremini mushrooms and gooey melted Swiss cheese. The earthy mushrooms and nutty cheese make this a deeply satisfying and savory burger.','A juicy beef burger loaded with golden sauteed mushrooms and melted Swiss cheese.','American','Easy',10,20,30,4,650,41,34,38,2,'[{"amount":1.5,"unit":"lbs","item":"ground beef 80/20","group":"patty"},{"amount":1,"unit":"tsp","item":"Worcestershire sauce","group":"patty"},{"amount":1,"unit":"tsp","item":"salt","group":"patty"},{"amount":1,"unit":"tsp","item":"black pepper","group":"patty"},{"amount":8,"unit":"oz","item":"cremini mushrooms sliced","group":"topping"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"topping"},{"amount":4,"unit":"slices","item":"Swiss cheese","group":"topping"},{"amount":4,"unit":"whole","item":"brioche buns toasted","group":"bun"}]','[{"title":"Saute the Mushrooms","text":"Melt butter in a skillet over medium-high heat. Add sliced cremini mushrooms in a single layer and cook without stirring for 3 to 4 minutes until golden brown on one side. Stir and cook 2 more minutes. Season with salt and pepper.","timer":360},{"title":"Form the Patties","text":"Mix ground beef gently with Worcestershire sauce, salt, and pepper. Form into four equal patties about three quarters of an inch thick. Press a small dimple in the center of each to prevent puffing during cooking.","timer":0},{"title":"Grill or Pan-Fry the Patties","text":"Cook patties over medium-high heat for 3 to 4 minutes per side for medium doneness. Do not flip more than once as repeated flipping prevents a good sear from developing on the surface.","timer":480},{"title":"Melt the Cheese","text":"In the last minute of cooking, place a slice of Swiss cheese on each patty. Cover the pan with a lid or tent with foil to trap steam and fully melt the cheese in about 60 seconds.","timer":60},{"title":"Assemble and Serve","text":"Toast brioche buns cut side down in a dry skillet until golden. Place each cheesy patty on the bottom bun and top generously with the sauteed mushrooms. Serve immediately while everything is hot.","timer":60}]','[{"original":"cremini mushrooms","swap":"baby bella or white button mushrooms"},{"original":"Swiss cheese","swap":"Gruyere for a deeper nuttier flavor"},{"original":"brioche buns","swap":"pretzel buns or potato rolls"}]','["Overcrowding the mushrooms in the pan causes them to steam instead of developing a golden sear","Flipping the patties multiple times prevents a proper crust from forming on the outside","Skipping the dimple in the center of patties causes them to puff up into a dome shape while cooking"]','["burger","mushroom","Swiss","pub style","beef"]','["gluten-containing"]','Burgers','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Oklahoma Onion Burger','oklahoma-onion-burger','A Depression-era classic where thinly sliced onions are smashed directly into the beef patty as it cooks, creating a deeply caramelized and crispy crust. Simple ingredients come together for an incredibly flavorful thin burger.','A thin smash burger with onions pressed into the patty for a crispy caramelized crust.','American Midwest','Easy',10,15,25,4,580,36,32,32,1,'[{"amount":1.5,"unit":"lbs","item":"ground beef 80/20","group":"patty"},{"amount":1,"unit":"tsp","item":"salt","group":"patty"},{"amount":1,"unit":"tsp","item":"black pepper","group":"patty"},{"amount":2,"unit":"large","item":"yellow onions sliced paper thin","group":"topping"},{"amount":4,"unit":"slices","item":"American cheese","group":"topping"},{"amount":4,"unit":"whole","item":"plain white hamburger buns","group":"bun"},{"amount":2,"unit":"tbsp","item":"yellow mustard","group":"sauce"},{"amount":1,"unit":"tbsp","item":"vegetable oil","group":"cooking"}]','[{"title":"Prep the Onions and Beef","text":"Slice onions as thin as possible using a sharp knife or mandoline. Divide the ground beef into four loose balls of equal size. Do not season the beef yet as salting early draws out moisture before cooking.","timer":0},{"title":"Heat the Skillet","text":"Heat a cast iron skillet or heavy griddle over high heat until it is very hot and just starting to smoke. Add vegetable oil and swirl to coat. A properly hot surface is essential for achieving the crispy crust that defines this burger.","timer":180},{"title":"Smash with Onions","text":"Place a handful of sliced onions on the hot surface and immediately set a beef ball on top of the onions. Smash firmly with a heavy spatula to press the onions into the patty. Season the top with salt and pepper and cook for 2 minutes.","timer":120},{"title":"Flip and Add Cheese","text":"Flip the patty onion side up so the embedded onions face up and are golden and crispy. Place a slice of American cheese on top immediately. Cook for 90 more seconds. Do not flip again after this point.","timer":90},{"title":"Assemble and Serve","text":"Lightly toast the white buns in the same skillet for 20 seconds. Spread yellow mustard on the top bun. Place the patty on the bottom bun with the onion side facing up and serve immediately while hot and crispy.","timer":20}]','[{"original":"American cheese","swap":"cheddar cheese or Velveeta slices"},{"original":"yellow mustard","swap":"deli mustard or spicy brown mustard"},{"original":"yellow onions","swap":"white onions for a sharper flavor"}]','["Not heating the skillet hot enough before cooking prevents the onions and beef from crisping properly","Making the beef balls too compact before smashing results in a dense and chewy patty","Slicing onions too thick causes them to remain raw and crunchy instead of softening and caramelizing into the patty"]','["smash burger","Oklahoma","onion burger","diner style","American"]','["gluten-containing"]','Burgers','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('San Diego Fish Tacos','san-diego-fish-tacos','Crispy battered fish tucked into warm corn tortillas with tangy cabbage slaw and creamy white sauce. This coastal classic brings the flavors of Baja California straight to your kitchen.','Light and crispy fish tacos with cabbage slaw and creamy sauce in just 30 minutes.','Mexican-American','Easy',15,15,30,4,420,28,38,18,4,'[{"amount":1.5,"unit":"lb","item":"cod fillets cut into strips","group":"fish"},{"amount":1,"unit":"cup","item":"all purpose flour","group":"batter"},{"amount":1,"unit":"cup","item":"light beer","group":"batter"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"batter"},{"amount":2,"unit":"cups","item":"shredded green cabbage","group":"slaw"},{"amount":0.5,"unit":"cup","item":"Mexican crema","group":"sauce"},{"amount":2,"unit":"tbsp","item":"fresh lime juice","group":"sauce"},{"amount":8,"unit":"piece","item":"small corn tortillas","group":"base"},{"amount":2,"unit":"cup","item":"vegetable oil for frying","group":"cooking"}]','[{"title":"Make the Batter","text":"Whisk together flour, garlic powder, salt, and beer in a bowl until a smooth batter forms. Do not over-mix. Let the batter rest for 5 minutes while you prepare the other components.","timer":300},{"title":"Prepare the Slaw and Sauce","text":"Toss shredded cabbage with a pinch of salt and set aside. Mix Mexican crema with lime juice, a pinch of salt, and a dash of hot sauce to create the white sauce. Refrigerate until ready to serve.","timer":0},{"title":"Heat the Oil","text":"Pour vegetable oil into a heavy skillet to about 1 inch depth and heat over medium-high heat to 375 degrees Fahrenheit. Use a thermometer for accuracy to ensure crispy results.","timer":300},{"title":"Fry the Fish","text":"Dip each fish strip into the batter and let the excess drip off. Carefully lower into the hot oil and fry for 3 to 4 minutes per side until golden brown and crispy. Drain on paper towels.","timer":240},{"title":"Assemble and Serve","text":"Warm corn tortillas on a dry skillet for 30 seconds per side. Place one or two fish strips on each tortilla, top with cabbage slaw, drizzle with crema sauce, and finish with a squeeze of fresh lime juice.","timer":60}]','[{"original":"cod","swap":"mahi mahi or tilapia"},{"original":"light beer","swap":"sparkling water or club soda"},{"original":"Mexican crema","swap":"sour cream mixed with mayonnaise"}]','["Using oil that is not hot enough which results in greasy soggy fish","Overcrowding the pan which drops oil temperature dramatically","Skipping the resting time for the batter which makes it less crispy"]','["tacos","fish","seafood","fried","baja","san diego","street food"]','["dairy-free option"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Birria Tacos with Consome','birria-tacos-with-consome','Slow-braised beef tacos dipped in rich chile-infused broth and crisped on a griddle until golden. Served alongside a bowl of warming consome for dipping.','Crispy braised beef tacos with a deeply flavored consomme for dipping.','Mexican','Hard',45,210,255,6,580,42,32,29,5,'[{"amount":3,"unit":"lb","item":"beef chuck roast cut into large chunks","group":"meat"},{"amount":4,"unit":"piece","item":"dried guajillo chiles stemmed and seeded","group":"chile sauce"},{"amount":2,"unit":"piece","item":"dried ancho chiles stemmed and seeded","group":"chile sauce"},{"amount":4,"unit":"clove","item":"garlic","group":"chile sauce"},{"amount":1,"unit":"tsp","item":"ground cumin","group":"spices"},{"amount":1,"unit":"tsp","item":"dried oregano","group":"spices"},{"amount":12,"unit":"piece","item":"corn tortillas","group":"base"},{"amount":1,"unit":"cup","item":"white onion finely diced","group":"topping"},{"amount":0.5,"unit":"cup","item":"fresh cilantro chopped","group":"topping"}]','[{"title":"Make the Chile Sauce","text":"Toast dried guajillo and ancho chiles in a dry skillet for 30 seconds per side until fragrant. Soak in hot water for 15 minutes until softened. Blend with garlic, cumin, oregano, soaking liquid, and salt until completely smooth.","timer":900},{"title":"Braise the Beef","text":"Season beef chunks generously with salt. Place in a large Dutch oven and pour the chile sauce over the top. Add enough water to nearly submerge the beef. Bring to a boil then reduce heat to low. Cover and braise for 3 hours until the beef is fork tender and falling apart.","timer":10800},{"title":"Shred and Prepare the Consome","text":"Remove beef from the braising liquid and shred with two forks. Strain the remaining liquid and skim excess fat from the surface to create the consome. Season the consome with salt and keep warm over low heat.","timer":600},{"title":"Dip and Griddle the Tacos","text":"Heat a large griddle or skillet over medium-high heat. Dip each tortilla briefly into the consome fat layer on the surface then place on the hot griddle. Add shredded beef to one half of the tortilla and fold over. Cook for 2 minutes per side until crispy and deeply golden.","timer":240},{"title":"Serve with Consome","text":"Plate the crispy tacos alongside a small bowl of hot consome for dipping. Top the tacos with diced white onion and fresh cilantro. Squeeze lime juice over everything before eating.","timer":0}]','[{"original":"beef chuck roast","swap":"bone-in short ribs or goat meat"},{"original":"guajillo chiles","swap":"New Mexico dried chiles"},{"original":"corn tortillas","swap":"small flour tortillas"}]','["Not toasting the dried chiles first which results in a flat and bitter sauce","Rushing the braise at high heat which makes the beef tough instead of tender","Skipping the fat dip for the tortilla which is what creates the signature crispy exterior"]','["birria","tacos","beef","slow cooked","mexican","consome","dipping tacos","viral"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Mission Style Burrito','mission-style-burrito','A giant flour tortilla wrapped around seasoned rice, creamy beans, grilled meat, salsa, and sour cream in the iconic San Francisco Mission District style. Everything is layered and tightly wrapped into one satisfying package.','A fully loaded oversized burrito packed with rice, beans, meat, and fresh toppings.','Mexican-American','Medium',20,40,60,4,720,38,82,24,10,'[{"amount":1,"unit":"lb","item":"skirt steak or chicken thighs","group":"protein"},{"amount":1,"unit":"tsp","item":"ground cumin","group":"seasoning"},{"amount":1,"unit":"tsp","item":"chili powder","group":"seasoning"},{"amount":2,"unit":"cup","item":"cooked long grain white rice","group":"filling"},{"amount":1,"unit":"can","item":"pinto beans drained and warmed","group":"filling"},{"amount":4,"unit":"piece","item":"extra large flour tortillas 12 inch","group":"base"},{"amount":0.5,"unit":"cup","item":"sour cream","group":"topping"},{"amount":0.5,"unit":"cup","item":"fresh pico de gallo","group":"topping"},{"amount":1,"unit":"piece","item":"ripe avocado sliced","group":"topping"}]','[{"title":"Season and Cook the Protein","text":"Season the skirt steak or chicken thighs with cumin, chili powder, salt, and pepper on all sides. Heat a cast iron skillet or grill pan over high heat with a little oil. Cook steak 3 to 4 minutes per side for medium or chicken until internal temperature reaches 165 degrees Fahrenheit.","timer":480},{"title":"Rest and Slice the Protein","text":"Transfer the cooked protein to a cutting board and let it rest for 5 minutes. This step is essential and do not skip it. Slice skirt steak against the grain into thin strips or chop chicken into bite sized pieces.","timer":300},{"title":"Warm the Tortillas and Fillings","text":"Warm each large flour tortilla directly over a gas burner flame or in a dry skillet for about 20 seconds per side until pliable and slightly charred. Warm the pinto beans in a small saucepan over medium heat and season with salt.","timer":120},{"title":"Layer the Burrito","text":"Lay the warm tortilla flat. Spread sour cream in the center leaving a 3 inch border on all sides. Add a layer of rice, then beans, then sliced meat, then pico de gallo, then avocado slices. Do not overfill or the burrito will be impossible to wrap.","timer":0},{"title":"Wrap and Seal","text":"Fold the two sides of the tortilla inward over the filling. Then fold the bottom up and over the filling while tucking tightly. Roll forward firmly to seal. Wrap tightly in aluminum foil and press gently to hold the shape. Serve immediately.","timer":0}]','[{"original":"skirt steak","swap":"carnitas or grilled shrimp"},{"original":"pinto beans","swap":"black beans or refried beans"},{"original":"sour cream","swap":"Greek yogurt or cashew cream"}]','["Using a cold or stiff tortilla that cracks and tears during wrapping","Overfilling the burrito so it cannot be sealed properly","Not resting the meat before slicing which causes all the juices to run out"]','["burrito","mission style","san francisco","rice and beans","wrap","meal prep"]','["high protein"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Grilled Carne Asada Tacos','grilled-carne-asada-tacos','Thinly sliced marinated flank steak grilled over high heat and served in warm corn tortillas with fresh salsa and guacamole. A simple weeknight taco that delivers bold smoky flavors.','Juicy marinated grilled steak tacos ready in under 30 minutes.','Mexican','Easy',15,12,27,4,460,35,30,20,4,'[{"amount":1.5,"unit":"lb","item":"flank steak","group":"protein"},{"amount":3,"unit":"tbsp","item":"fresh lime juice","group":"marinade"},{"amount":2,"unit":"tbsp","item":"orange juice","group":"marinade"},{"amount":3,"unit":"clove","item":"garlic minced","group":"marinade"},{"amount":1,"unit":"tsp","item":"chili powder","group":"marinade"},{"amount":8,"unit":"piece","item":"small corn tortillas","group":"base"},{"amount":0.5,"unit":"cup","item":"white onion finely diced","group":"topping"},{"amount":0.5,"unit":"cup","item":"fresh cilantro chopped","group":"topping"},{"amount":1,"unit":"piece","item":"avocado mashed","group":"topping"}]','[{"title":"Marinate the Steak","text":"Combine lime juice, orange juice, minced garlic, chili powder, and salt in a bowl. Place the flank steak in a zip lock bag and pour the marinade over it. Seal and massage the marinade into the meat. Marinate for at least 30 minutes or up to 4 hours in the refrigerator.","timer":1800},{"title":"Prepare the Toppings","text":"While the steak marinates, mash the avocado with a pinch of salt and a squeeze of lime juice. Dice the white onion finely and chop the cilantro. Set all toppings aside at room temperature.","timer":0},{"title":"Grill the Steak","text":"Heat a grill or grill pan to high heat. Remove the steak from the marinade and pat dry slightly with paper towels. Grill for 5 to 6 minutes per side for medium rare. Do not move the steak around too much so a proper char can develop.","timer":720},{"title":"Rest and Slice","text":"Transfer the grilled steak to a cutting board and let it rest for 5 to 7 minutes. Slice the steak very thinly across the grain at a slight diagonal angle. This step is critical for tender carne asada.","timer":420},{"title":"Assemble the Tacos","text":"Warm corn tortillas on the grill or in a dry skillet for 20 to 30 seconds per side. Spoon a small amount of mashed avocado on each tortilla. Top with sliced carne asada, diced onion, and fresh cilantro. Serve with lime wedges.","timer":60}]','[{"original":"flank steak","swap":"skirt steak or sirloin"},{"original":"corn tortillas","swap":"flour tortillas"},{"original":"mashed avocado","swap":"store bought guacamole"}]','["Slicing the steak with the grain instead of against it which makes the meat very chewy","Not allowing the grill to get hot enough before placing the steak on it","Cutting into the steak immediately after grilling without letting it rest"]','["carne asada","tacos","grilled","beef","mexican","weeknight","street food"]','["gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Al Pastor Tacos with Pineapple','al-pastor-tacos-with-pineapple','Thinly sliced marinated pork layered with sweet charred pineapple in the classic Mexican spit-roasted style. This pan version brings the authentic flavors home without a vertical rotisserie.','Sweet and savory spiced pork tacos with charred pineapple served street taco style.','Mexican','Medium',30,25,55,5,390,30,34,14,3,'[{"amount":2,"unit":"lb","item":"pork shoulder thinly sliced","group":"protein"},{"amount":3,"unit":"piece","item":"dried guajillo chiles rehydrated","group":"marinade"},{"amount":1,"unit":"piece","item":"chipotle chile in adobo sauce","group":"marinade"},{"amount":0.5,"unit":"cup","item":"pineapple juice","group":"marinade"},{"amount":1,"unit":"tsp","item":"ground achiote or paprika","group":"marinade"},{"amount":1,"unit":"cup","item":"fresh pineapple chunks","group":"topping"},{"amount":10,"unit":"piece","item":"small corn tortillas","group":"base"},{"amount":0.5,"unit":"cup","item":"white onion finely diced","group":"topping"},{"amount":0.5,"unit":"cup","item":"fresh cilantro chopped","group":"topping"}]','[{"title":"Blend the Marinade","text":"Blend rehydrated guajillo chiles, chipotle chile, pineapple juice, achiote, garlic, cumin, and salt until completely smooth. The marinade should be a deep red color and very fragrant.","timer":0},{"title":"Marinate the Pork","text":"Place thinly sliced pork shoulder in a large bowl and pour the marinade over it. Toss thoroughly to coat every piece. Cover and refrigerate for at least 2 hours or overnight for best results. Do not skip the marinating time.","timer":7200},{"title":"Cook the Pork","text":"Heat a large cast iron skillet over high heat with a small amount of oil. Cook the marinated pork in a single layer without overcrowding for 3 to 4 minutes per side until caramelized and slightly charred on the edges. Work in batches.","timer":480},{"title":"Char the Pineapple","text":"In the same hot skillet add the pineapple chunks and cook for 2 to 3 minutes without stirring until they develop a golden char on one side. The natural sugars will caramelize quickly so keep a close eye on them.","timer":180},{"title":"Assemble and Serve","text":"Warm corn tortillas in a dry skillet or directly over a flame. Pile al pastor pork onto each tortilla and top with a piece or two of charred pineapple, diced white onion, and fresh cilantro. Serve with salsa verde on the side.","timer":60}]','[{"original":"pork shoulder","swap":"boneless pork loin or chicken thighs"},{"original":"achiote","swap":"smoked paprika"},{"original":"fresh pineapple","swap":"canned pineapple rings drained"}]','["Slicing the pork too thick which prevents proper caramelization and a charred crust","Overcrowding the skillet which causes the pork to steam instead of sear","Skipping the full marinating time which results in bland and pale pork"]','["al pastor","tacos","pork","pineapple","mexican","street food","marinated"]','["gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Garlic Parmesan Wings','garlic-parmesan-wings','Crispy baked wings tossed in a rich garlic butter and Parmesan coating. These wings are packed with bold savory flavor and make the perfect party appetizer.','Crispy wings coated in garlic butter and freshly grated Parmesan cheese.','American','Easy',15,45,60,4,520,38,4,39,0,'[{"amount":2,"unit":"lbs","item":"chicken wings","group":"Main"},{"amount":1,"unit":"tsp","item":"baking powder","group":"Main"},{"amount":1,"unit":"tsp","item":"salt","group":"Main"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"Main"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"Sauce"},{"amount":5,"unit":"cloves","item":"garlic minced","group":"Sauce"},{"amount":0.75,"unit":"cup","item":"grated Parmesan cheese","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"Garnish"},{"amount":1,"unit":"tsp","item":"red pepper flakes","group":"Sauce"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"Main"}]','[{"title":"Prep the Wings","text":"Pat the chicken wings completely dry with paper towels. Toss them with baking powder, salt, black pepper, and olive oil until evenly coated. Drying the wings is essential for achieving a crispy skin.","timer":0},{"title":"Bake the Wings","text":"Arrange wings in a single layer on a wire rack set over a baking sheet. Bake at 425 degrees F for 45 minutes, flipping halfway through, until golden and crispy.","timer":2700},{"title":"Make the Garlic Butter Sauce","text":"While wings bake, melt butter in a small saucepan over medium heat. Add minced garlic and cook for 2 minutes until fragrant. Remove from heat and stir in red pepper flakes.","timer":120},{"title":"Toss the Wings","text":"Transfer hot wings to a large mixing bowl. Pour the garlic butter sauce over the wings and toss to coat thoroughly. Add half the Parmesan and toss again.","timer":0},{"title":"Finish and Serve","text":"Transfer wings to a serving platter. Top with remaining Parmesan and fresh parsley. Serve immediately while hot and crispy.","timer":0}]','[{"original":"unsalted butter","swap":"vegan butter for a dairy-free option"},{"original":"Parmesan cheese","swap":"Pecorino Romano for a sharper flavor"},{"original":"fresh parsley","swap":"dried parsley using half the amount"}]','["Skipping the baking powder which is key to getting crispy skin without frying","Not patting the wings dry before seasoning which leads to steaming instead of crisping","Adding all the Parmesan to the sauce while it is still on the heat which causes it to clump"]','["wings","garlic","parmesan","baked","appetizer","game day","party food"]','["Gluten-Free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey BBQ Chicken Tenders','honey-bbq-chicken-tenders','Juicy breaded chicken tenders glazed in a sticky honey BBQ sauce. These crowd-pleasing tenders are crispy on the outside and tender on the inside.','Golden crispy chicken tenders coated in a sweet and smoky honey BBQ glaze.','American','Easy',20,20,40,4,480,34,42,18,1,'[{"amount":1.5,"unit":"lbs","item":"chicken tenderloins","group":"Main"},{"amount":1,"unit":"cup","item":"panko breadcrumbs","group":"Breading"},{"amount":0.5,"unit":"cup","item":"all purpose flour","group":"Breading"},{"amount":2,"unit":"large","item":"eggs beaten","group":"Breading"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"Breading"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"Breading"},{"amount":0.75,"unit":"cup","item":"BBQ sauce","group":"Sauce"},{"amount":3,"unit":"tbsp","item":"honey","group":"Sauce"},{"amount":1,"unit":"tsp","item":"salt","group":"Breading"},{"amount":2,"unit":"tbsp","item":"vegetable oil","group":"Main"}]','[{"title":"Set Up Breading Station","text":"Set up three shallow bowls. Fill the first with flour seasoned with salt and garlic powder. Fill the second with beaten eggs. Fill the third with panko breadcrumbs mixed with smoked paprika.","timer":0},{"title":"Bread the Chicken","text":"Dredge each chicken tenderloin in flour and shake off excess. Dip into the egg wash and let excess drip off. Press firmly into the panko breadcrumbs on both sides until fully coated.","timer":0},{"title":"Cook the Tenders","text":"Heat oil in a large oven-safe skillet over medium-high heat. Sear tenders for 3 minutes per side until golden brown. Transfer the skillet to a 400 degree F oven and bake for 10 minutes.","timer":600},{"title":"Make the Honey BBQ Sauce","text":"Combine BBQ sauce and honey in a small saucepan over medium-low heat. Stir until warmed through and well combined, about 3 minutes. Do not let the sauce boil or it will become too thick.","timer":180},{"title":"Glaze and Serve","text":"Brush the warm honey BBQ sauce generously over each tender. Serve with extra sauce on the side for dipping. Plate immediately and enjoy while hot.","timer":0}]','[{"original":"panko breadcrumbs","swap":"crushed cornflakes for an extra crunchy coating"},{"original":"honey","swap":"maple syrup for a deeper sweetness"},{"original":"vegetable oil","swap":"avocado oil for a higher smoke point"}]','["Not pressing the panko firmly onto the chicken which causes the coating to fall off during cooking","Overcrowding the pan which lowers the oil temperature and results in soggy breading","Applying the BBQ glaze too early in the oven which causes the sugars to burn before the chicken is cooked through"]','["chicken tenders","honey BBQ","crispy","kid-friendly","comfort food","game day"]','["Dairy-Free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lemon Pepper Wings','lemon-pepper-wings','Bright and zesty chicken wings seasoned with a bold lemon pepper blend and finished with fresh lemon zest. These wings are a tangy and savory alternative to saucy wings.','Crispy wings bursting with tangy lemon and bold cracked black pepper seasoning.','American','Easy',10,45,55,4,490,37,2,36,0,'[{"amount":2,"unit":"lbs","item":"chicken wings","group":"Main"},{"amount":1,"unit":"tsp","item":"baking powder","group":"Main"},{"amount":2,"unit":"tsp","item":"coarsely cracked black pepper","group":"Seasoning"},{"amount":2,"unit":"tsp","item":"lemon zest","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"onion powder","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"Seasoning"},{"amount":4,"unit":"tbsp","item":"unsalted butter melted","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"fresh lemon juice","group":"Sauce"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"Main"}]','[{"title":"Prep and Season the Wings","text":"Pat wings completely dry with paper towels. Toss with baking powder, olive oil, salt, garlic powder, and onion powder. Make sure every wing is evenly coated for maximum crispiness.","timer":0},{"title":"Bake Until Crispy","text":"Place wings on a wire rack over a lined baking sheet in a single layer. Bake at 425 degrees F for 45 minutes, flipping once at the halfway point, until deeply golden and crispy.","timer":2700},{"title":"Make the Lemon Pepper Butter","text":"Combine melted butter, fresh lemon juice, cracked black pepper, and lemon zest in a large mixing bowl. Whisk together until well blended. The butter will carry the lemon pepper flavor onto every wing.","timer":0},{"title":"Toss the Wings","text":"Add the hot crispy wings directly to the bowl with the lemon pepper butter. Toss vigorously until every wing is fully coated in the glossy lemon pepper sauce.","timer":0},{"title":"Serve Immediately","text":"Transfer wings to a serving platter and garnish with additional lemon zest and cracked pepper if desired. Serve with lemon wedges on the side for an extra burst of citrus.","timer":0}]','[{"original":"fresh lemon juice","swap":"bottled lemon juice in a pinch but fresh is strongly preferred"},{"original":"unsalted butter","swap":"ghee for a nuttier richer finish"},{"original":"cracked black pepper","swap":"store-bought lemon pepper seasoning to simplify the recipe"}]','["Using pre-ground fine black pepper instead of coarsely cracked pepper which loses the bold peppery bite","Skipping the wire rack and baking wings flat on a sheet pan which traps steam and makes the skin soft","Adding lemon juice directly to the dry wings before baking which prevents crisping and adds unwanted moisture"]','["wings","lemon pepper","baked","crispy","citrus","game day","appetizer"]','["Gluten-Free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Buffalo Cauliflower Bites','buffalo-cauliflower-bites','Crispy roasted cauliflower florets tossed in classic buffalo sauce for a spicy plant-based snack. These bites deliver all the heat and tang of traditional buffalo wings without the meat.','Spicy crispy cauliflower florets coated in tangy buffalo sauce for a plant-based game day snack.','American','Easy',15,30,45,4,210,5,22,12,4,'[{"amount":1,"unit":"large head","item":"cauliflower cut into florets","group":"Main"},{"amount":0.5,"unit":"cup","item":"all purpose flour","group":"Batter"},{"amount":0.5,"unit":"cup","item":"water","group":"Batter"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"Batter"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"Batter"},{"amount":0.5,"unit":"tsp","item":"salt","group":"Batter"},{"amount":0.5,"unit":"cup","item":"buffalo hot sauce","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"vegan butter melted","group":"Sauce"},{"amount":1,"unit":"tbsp","item":"apple cider vinegar","group":"Sauce"},{"amount":1,"unit":"tsp","item":"honey or agave","group":"Sauce"}]','[{"title":"Make the Batter","text":"Whisk together flour, water, garlic powder, smoked paprika, and salt in a large bowl until a smooth thin batter forms. The batter should coat the back of a spoon without being too thick.","timer":0},{"title":"Coat and Bake the Cauliflower","text":"Dip each cauliflower floret into the batter and let excess drip off. Place on a parchment-lined baking sheet in a single layer. Bake at 425 degrees F for 20 minutes until the batter is set and edges are golden.","timer":1200},{"title":"Make the Buffalo Sauce","text":"Whisk together buffalo hot sauce, melted vegan butter, apple cider vinegar, and honey in a bowl until combined. Taste and adjust heat level by adding more hot sauce if desired.","timer":0},{"title":"Toss and Return to Oven","text":"Remove cauliflower from the oven and toss each piece in the buffalo sauce until well coated. Return to the baking sheet and bake for an additional 10 minutes until caramelized and sticky.","timer":600},{"title":"Serve with Dipping Sauce","text":"Transfer the buffalo cauliflower bites to a serving platter. Serve immediately with ranch or blue cheese dressing and celery sticks on the side.","timer":0}]','[{"original":"all purpose flour","swap":"gluten-free flour blend to make this recipe fully gluten-free"},{"original":"vegan butter","swap":"regular unsalted butter if not following a vegan diet"},{"original":"honey","swap":"agave nectar to keep the recipe fully vegan"}]','["Making the batter too thick which results in a doughy coating that does not crisp up properly in the oven","Overcrowding the baking sheet which causes the florets to steam instead of roast and crisp","Skipping the second bake after saucing which is essential for the sauce to caramelize and stick to the cauliflower"]','["cauliflower","buffalo","vegan","plant-based","appetizer","game day","spicy"]','["Vegan","Dairy-Free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Teriyaki Chicken Skewers','teriyaki-chicken-skewers','Tender grilled chicken skewers brushed with a glossy homemade teriyaki glaze. These skewers are sweet, savory, and perfectly charred from the grill.','Juicy grilled chicken skewers lacquered in a sweet and savory homemade teriyaki sauce.','Japanese-American','Medium',20,15,35,4,390,35,28,14,1,'[{"amount":1.5,"unit":"lbs","item":"boneless skinless chicken thighs cut into chunks","group":"Main"},{"amount":0.5,"unit":"cup","item":"soy sauce","group":"Marinade"},{"amount":0.25,"unit":"cup","item":"honey","group":"Marinade"},{"amount":2,"unit":"tbsp","item":"rice vinegar","group":"Marinade"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"Marinade"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"Marinade"},{"amount":1,"unit":"tsp","item":"fresh ginger grated","group":"Marinade"},{"amount":1,"unit":"tbsp","item":"cornstarch","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"sesame seeds","group":"Garnish"},{"amount":3,"unit":"stalks","item":"green onions sliced","group":"Garnish"}]','[{"title":"Make the Teriyaki Sauce","text":"Whisk together soy sauce, honey, rice vinegar, sesame oil, garlic, and ginger in a bowl. Pour half the sauce into a separate small saucepan and reserve it for glazing. The other half will be used as the marinade.","timer":0},{"title":"Marinate the Chicken","text":"Add chicken chunks to the marinade portion of the teriyaki sauce. Toss to coat, cover, and refrigerate for at least 30 minutes. Do not skip the marinating time as it builds deep flavor in the chicken.","timer":1800},{"title":"Thicken the Glaze","text":"Whisk cornstarch with 1 tablespoon of cold water and stir into the reserved sauce in the saucepan. Cook over medium heat for 3 to 4 minutes stirring constantly until the glaze thickens and becomes glossy.","timer":240},{"title":"Skewer and Grill the Chicken","text":"Thread marinated chicken onto pre-soaked wooden skewers or metal skewers. Grill over medium-high heat for 5 to 6 minutes per side, brushing with the thickened glaze during the last 2 minutes of cooking.","timer":720},{"title":"Garnish and Serve","text":"Remove skewers from the grill and brush with one final layer of teriyaki glaze. Sprinkle with sesame seeds and sliced green onions. Serve over steamed rice or alongside grilled vegetables.","timer":0}]','[{"original":"soy sauce","swap":"tamari or coconut aminos for a gluten-free version"},{"original":"chicken thighs","swap":"chicken breast for a leaner option though it may be slightly less juicy"},{"original":"honey","swap":"brown sugar dissolved in a small amount of warm water"}]','["Not soaking wooden skewers in water for at least 30 minutes before grilling which causes them to catch fire on the grill","Using the same marinade that touched raw chicken as a finishing glaze which is a food safety risk","Cooking the chicken over heat that is too high which chars the outside before the inside is fully cooked through"]','["teriyaki","chicken skewers","grilled","Japanese","sweet","savory","meal prep"]','["Dairy-Free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Korean Soy Garlic Wings','korean-soy-garlic-wings','Crispy baked wings coated in a savory soy garlic glaze with a hint of sweetness. These wings are sticky, bold, and impossible to stop eating.','Crispy wings glazed in a rich Korean soy garlic sauce.','Korean','Medium',20,45,65,4,520,38,22,30,1,'[{"amount":2,"unit":"lbs","item":"chicken wings","group":"wings"},{"amount":1,"unit":"tbsp","item":"baking powder","group":"wings"},{"amount":0.5,"unit":"tsp","item":"salt","group":"wings"},{"amount":0.25,"unit":"cup","item":"soy sauce","group":"sauce"},{"amount":3,"unit":"tbsp","item":"honey","group":"sauce"},{"amount":6,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"sauce"},{"amount":1,"unit":"tbsp","item":"rice vinegar","group":"sauce"},{"amount":1,"unit":"tsp","item":"cornstarch","group":"sauce"},{"amount":1,"unit":"tbsp","item":"sesame seeds","group":"garnish"}]','[{"title":"Prep and Dry the Wings","text":"Pat chicken wings completely dry with paper towels. Toss with baking powder and salt until evenly coated. Place on a wire rack over a baking sheet.","timer":0},{"title":"Bake the Wings","text":"Bake wings at 425F for 45 minutes, flipping halfway through, until golden brown and crispy.","timer":2700},{"title":"Make the Soy Garlic Sauce","text":"Combine soy sauce, honey, minced garlic, sesame oil, and rice vinegar in a small saucepan over medium heat. Mix cornstarch with one tablespoon of water and stir into the sauce. Cook until thickened, about 3 minutes.","timer":180},{"title":"Glaze the Wings","text":"Transfer crispy wings to a large bowl. Pour warm sauce over wings and toss until every wing is fully coated in the glaze.","timer":0},{"title":"Garnish and Serve","text":"Sprinkle sesame seeds over the wings and serve immediately while hot and sticky.","timer":0}]','[{"original":"honey","swap":"maple syrup"},{"original":"rice vinegar","swap":"apple cider vinegar"},{"original":"sesame oil","swap":"toasted walnut oil"}]','["Skipping the baking powder step which is essential for crispiness","Not patting the wings dry before coating them","Adding sauce too early and making the wings soggy"]','["wings","Korean","game day","sticky","garlic","soy"]','["dairy-free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('General Tso Chicken Bites','general-tso-chicken-bites','Crispy bite-sized chicken pieces tossed in a tangy sweet and spicy General Tso sauce. This classic takeout favorite is easy to make at home in under 40 minutes.','Crispy chicken bites coated in a bold sweet and spicy General Tso sauce.','Chinese-American','Medium',15,20,35,4,480,34,40,18,2,'[{"amount":1.5,"unit":"lbs","item":"boneless chicken thighs cut into bite-sized pieces","group":"chicken"},{"amount":0.5,"unit":"cup","item":"cornstarch","group":"chicken"},{"amount":2,"unit":"large","item":"eggs beaten","group":"chicken"},{"amount":3,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":2,"unit":"tbsp","item":"rice vinegar","group":"sauce"},{"amount":3,"unit":"tbsp","item":"hoisin sauce","group":"sauce"},{"amount":2,"unit":"tbsp","item":"sugar","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tsp","item":"red chili flakes","group":"sauce"},{"amount":2,"unit":"cups","item":"vegetable oil for frying","group":"frying"}]','[{"title":"Coat the Chicken","text":"Dip chicken pieces in beaten egg then dredge thoroughly in cornstarch until fully coated. Shake off any excess cornstarch.","timer":0},{"title":"Fry the Chicken","text":"Heat oil in a wok or deep skillet to 350F. Fry chicken in batches for 4 to 5 minutes until golden and cooked through. Drain on paper towels.","timer":300},{"title":"Make the Sauce","text":"Drain most of the oil leaving about one tablespoon. Saute garlic and chili flakes for 30 seconds. Add soy sauce, rice vinegar, hoisin sauce, and sugar. Stir and bring to a simmer.","timer":120},{"title":"Toss and Coat","text":"Add fried chicken to the sauce and toss quickly over high heat until every piece is well coated and the sauce clings to the chicken.","timer":60},{"title":"Serve","text":"Serve immediately over steamed white rice and garnish with sliced green onions and extra chili flakes if desired.","timer":0}]','[{"original":"chicken thighs","swap":"chicken breast"},{"original":"hoisin sauce","swap":"oyster sauce"},{"original":"vegetable oil","swap":"peanut oil"}]','["Overcrowding the pan when frying which causes steaming instead of crisping","Not getting the oil hot enough before adding chicken","Letting the sauce cook too long before adding chicken which makes it too thick"]','["Chinese-American","takeout","fried chicken","spicy","sweet","weeknight"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Bourbon Chicken','bourbon-chicken','Tender chunks of chicken simmered in a rich bourbon-spiked sweet and savory sauce. This Southern-inspired dish is a guaranteed crowd pleaser over fluffy white rice.','Juicy chicken simmered in a bold bourbon and soy glaze.','Southern American','Easy',10,25,35,4,460,36,32,14,1,'[{"amount":1.5,"unit":"lbs","item":"boneless chicken thighs cut into chunks","group":"chicken"},{"amount":1,"unit":"tbsp","item":"vegetable oil","group":"chicken"},{"amount":0.25,"unit":"cup","item":"bourbon","group":"sauce"},{"amount":0.25,"unit":"cup","item":"soy sauce","group":"sauce"},{"amount":3,"unit":"tbsp","item":"brown sugar","group":"sauce"},{"amount":2,"unit":"tbsp","item":"apple juice","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tsp","item":"ginger powder","group":"sauce"},{"amount":1,"unit":"tbsp","item":"cornstarch","group":"sauce"},{"amount":2,"unit":"tbsp","item":"water","group":"sauce"}]','[{"title":"Sear the Chicken","text":"Heat vegetable oil in a large skillet over medium-high heat. Add chicken chunks and cook for 5 to 6 minutes until browned on all sides. Remove and set aside.","timer":360},{"title":"Build the Sauce","text":"In the same pan, add garlic and cook for 30 seconds. Pour in bourbon and let it cook down for one minute. Add soy sauce, brown sugar, apple juice, and ginger powder. Stir to combine.","timer":90},{"title":"Simmer the Chicken","text":"Return the chicken to the pan. Reduce heat to medium and let everything simmer together for 10 minutes, stirring occasionally.","timer":600},{"title":"Thicken the Sauce","text":"Mix cornstarch with water to create a slurry. Pour into the pan and stir continuously until the sauce thickens and coats the chicken, about 2 minutes.","timer":120},{"title":"Serve","text":"Serve hot over steamed white rice and garnish with sliced green onions.","timer":0}]','[{"original":"bourbon","swap":"apple cider for a non-alcoholic version"},{"original":"chicken thighs","swap":"chicken breast"},{"original":"brown sugar","swap":"honey"}]','["Using too much bourbon without letting it cook down which leaves a harsh alcohol taste","Skipping the sear step and missing out on deep caramelized flavor","Adding the cornstarch slurry before the sauce has simmered which causes lumps"]','["bourbon","Southern","chicken","weeknight","comfort food","sweet"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Garlic Chicken Thighs','honey-garlic-chicken-thighs','Juicy pan-seared chicken thighs glazed in a sticky honey garlic butter sauce. Ready in 30 minutes and packed with bold simple flavors.','Pan-seared chicken thighs finished in a rich honey garlic glaze.','American','Easy',10,22,32,4,430,35,18,22,0,'[{"amount":4,"unit":"pieces","item":"bone-in skin-on chicken thighs","group":"chicken"},{"amount":1,"unit":"tsp","item":"salt","group":"chicken"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"chicken"},{"amount":2,"unit":"tbsp","item":"butter","group":"sauce"},{"amount":5,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":3,"unit":"tbsp","item":"honey","group":"sauce"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":1,"unit":"tbsp","item":"lemon juice","group":"sauce"},{"amount":1,"unit":"tsp","item":"fresh thyme","group":"garnish"}]','[{"title":"Season the Chicken","text":"Pat chicken thighs dry and season generously with salt and black pepper on both sides.","timer":0},{"title":"Sear Skin Side Down","text":"Place chicken skin-side down in a cold oven-safe skillet. Turn heat to medium-high and cook undisturbed for 10 minutes until skin is deeply golden and crispy.","timer":600},{"title":"Flip and Finish in Oven","text":"Flip the chicken and transfer the skillet to a 400F oven. Roast for 10 to 12 minutes until internal temperature reaches 165F.","timer":720},{"title":"Make the Honey Garlic Sauce","text":"Remove chicken and set aside. Over medium heat add butter to the same pan. Cook garlic for 30 seconds then add honey, soy sauce, and lemon juice. Stir until combined and slightly reduced.","timer":120},{"title":"Glaze and Serve","text":"Return chicken to the pan and spoon sauce over the top. Garnish with fresh thyme and serve immediately.","timer":0}]','[{"original":"honey","swap":"agave nectar"},{"original":"butter","swap":"ghee"},{"original":"lemon juice","swap":"apple cider vinegar"}]','["Starting with a hot pan which causes uneven rendering of the chicken skin","Moving the chicken too early before the skin has properly crisped","Overcooking in the oven and drying out the meat"]','["honey garlic","chicken thighs","easy","weeknight","pan seared"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Teriyaki Chicken Bowl','teriyaki-chicken-bowl','Grilled chicken breast glazed with homemade teriyaki sauce served over steamed rice with fresh vegetables. A clean and satisfying meal that comes together in about 30 minutes.','Juicy teriyaki glazed chicken served over rice with crisp vegetables.','Japanese-American','Easy',10,20,30,4,490,40,52,10,3,'[{"amount":1.5,"unit":"lbs","item":"boneless skinless chicken breast","group":"chicken"},{"amount":0.25,"unit":"cup","item":"soy sauce","group":"sauce"},{"amount":3,"unit":"tbsp","item":"mirin","group":"sauce"},{"amount":2,"unit":"tbsp","item":"honey","group":"sauce"},{"amount":1,"unit":"tsp","item":"fresh ginger grated","group":"sauce"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tsp","item":"cornstarch","group":"sauce"},{"amount":2,"unit":"cups","item":"cooked white rice","group":"bowl"},{"amount":1,"unit":"cup","item":"broccoli florets steamed","group":"bowl"},{"amount":1,"unit":"tbsp","item":"sesame seeds","group":"garnish"}]','[{"title":"Make the Teriyaki Sauce","text":"Whisk together soy sauce, mirin, honey, ginger, and garlic in a small bowl. Mix cornstarch with one tablespoon of water and stir into the sauce.","timer":0},{"title":"Cook the Chicken","text":"Heat a grill pan or skillet over medium-high heat. Cook chicken breast for 6 to 7 minutes per side until cooked through and internal temperature reaches 165F.","timer":840},{"title":"Glaze with Sauce","text":"Pour teriyaki sauce over the chicken in the pan during the last 3 minutes of cooking. Let the sauce bubble and caramelize, turning chicken to coat both sides.","timer":180},{"title":"Slice the Chicken","text":"Remove chicken from heat and let it rest for 5 minutes. Slice against the grain into even strips.","timer":300},{"title":"Assemble the Bowls","text":"Divide rice into bowls and top with sliced chicken and steamed broccoli. Drizzle remaining sauce over the top and garnish with sesame seeds.","timer":0}]','[{"original":"mirin","swap":"dry sherry mixed with a pinch of sugar"},{"original":"honey","swap":"brown sugar"},{"original":"broccoli","swap":"snap peas or bok choy"}]','["Adding the sauce too early which causes it to burn before the chicken is cooked through","Cutting the chicken immediately without resting which causes juices to run out","Using low heat which prevents proper caramelization of the sauce"]','["teriyaki","Japanese","bowl","healthy","meal prep","weeknight"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Disco Fries','disco-fries','A New Jersey diner classic loaded with gravy and melted mozzarella on top of crispy fries. This indulgent comfort dish is perfect for late night cravings.','Crispy fries smothered in brown gravy and melted mozzarella cheese.','American','Easy',10,30,40,4,620,18,72,30,5,'[{"amount":2,"unit":"lbs","item":"frozen crinkle cut fries","group":"fries"},{"amount":2,"unit":"cups","item":"shredded mozzarella cheese","group":"topping"},{"amount":2,"unit":"cups","item":"beef brown gravy","group":"sauce"},{"amount":1,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"onion powder","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":1,"unit":"tsp","item":"kosher salt","group":"seasoning"}]','[{"title":"Bake the Fries","text":"Preheat oven to 425 degrees F. Spread the frozen crinkle cut fries in a single layer on a large baking sheet. Season with salt, pepper, garlic powder, and onion powder. Bake for 25 to 30 minutes until golden and crispy, flipping halfway through.","timer":1800},{"title":"Warm the Gravy","text":"While the fries bake, heat the beef brown gravy in a small saucepan over medium heat. Add butter and stir until melted and fully incorporated. Keep warm on low heat until ready to serve.","timer":300},{"title":"Add the Cheese","text":"Remove the fries from the oven and immediately scatter the shredded mozzarella evenly over the top. Return the baking sheet to the oven and bake for an additional 3 to 4 minutes until the cheese is fully melted and bubbly.","timer":240},{"title":"Pour on the Gravy","text":"Transfer the cheesy fries to a serving platter or individual plates. Ladle the warm brown gravy generously over the top, covering the melted cheese and fries evenly. Do not skimp on the gravy as it is the heart of this dish.","timer":60},{"title":"Serve Immediately","text":"Serve the disco fries right away while the cheese is melted and the gravy is hot. These are best enjoyed fresh as the fries will soften over time. Add extra gravy on the side if desired.","timer":0}]','[{"original":"beef brown gravy","swap":"mushroom gravy for a vegetarian version"},{"original":"mozzarella cheese","swap":"white American cheese for extra meltiness"},{"original":"frozen crinkle cut fries","swap":"fresh hand cut potato fries"}]','["Not baking the fries long enough causing them to be soggy under the gravy","Adding cold gravy which cools down the dish too quickly","Piling fries too thick on the pan which leads to uneven cooking"]','["comfort food","diner","cheese","gravy","fries","New Jersey","late night"]','["vegetarian-optional"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Fried Dill Pickles','fried-dill-pickles','Tangy dill pickle slices coated in a seasoned cornmeal and flour batter then fried to golden perfection. These crunchy bites are a beloved Southern snack and appetizer.','Crunchy Southern fried pickle slices with a seasoned cornmeal coating.','Southern American','Easy',15,15,30,4,310,6,38,15,2,'[{"amount":2,"unit":"cups","item":"dill pickle slices","group":"main"},{"amount":1,"unit":"cup","item":"all purpose flour","group":"batter"},{"amount":0.5,"unit":"cup","item":"fine yellow cornmeal","group":"batter"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"cayenne pepper","group":"seasoning"},{"amount":1,"unit":"cup","item":"buttermilk","group":"batter"},{"amount":3,"unit":"cups","item":"vegetable oil for frying","group":"cooking"}]','[{"title":"Drain and Dry the Pickles","text":"Remove pickle slices from the jar and spread them out on a layer of paper towels. Pat the tops with additional paper towels to remove as much moisture as possible. Dry pickles are essential so the batter will stick properly and the oil will not splatter.","timer":600},{"title":"Prepare the Batter","text":"In one shallow bowl pour the buttermilk. In a second shallow bowl whisk together the flour, cornmeal, smoked paprika, garlic powder, cayenne pepper, and a generous pinch of salt. Mix until all dry ingredients are evenly combined.","timer":120},{"title":"Heat the Oil","text":"Pour vegetable oil into a heavy bottomed skillet or Dutch oven to a depth of about 2 inches. Heat over medium high heat until the oil reaches 375 degrees F. Use a thermometer to verify the temperature before frying.","timer":300},{"title":"Coat and Fry the Pickles","text":"Dip each pickle slice in the buttermilk then dredge thoroughly in the seasoned flour and cornmeal mixture, pressing gently to adhere. Working in batches, carefully lower the coated pickles into the hot oil. Fry for 2 to 3 minutes per side until deep golden brown. Do not overcrowd the pan.","timer":180},{"title":"Drain and Serve","text":"Remove fried pickles with a slotted spoon and transfer to a paper towel lined plate to drain excess oil. Season immediately with a little extra salt. Serve hot with ranch dressing or remoulade sauce on the side.","timer":60}]','[{"original":"buttermilk","swap":"regular milk mixed with one tablespoon of white vinegar"},{"original":"yellow cornmeal","swap":"panko breadcrumbs for an extra crunchy coating"},{"original":"vegetable oil","swap":"peanut oil for a higher smoke point and clean flavor"}]','["Skipping the drying step which causes the batter to fall off during frying","Frying at too low a temperature which makes the pickles greasy instead of crispy","Overcrowding the pan which drops oil temperature and leads to soggy results"]','["Southern","appetizer","snack","fried","pickles","party food","game day"]','["vegetarian"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Southern Hushpuppies','classic-southern-hushpuppies','Golden deep fried cornmeal fritters with a crispy exterior and a soft fluffy interior packed with onion flavor. These iconic Southern side dishes pair perfectly with fried fish and coleslaw.','Crispy golden cornmeal fritters with sweet onion flavor fried to perfection.','Southern American','Easy',10,20,30,6,280,5,34,14,2,'[{"amount":1.5,"unit":"cups","item":"yellow cornmeal","group":"batter"},{"amount":0.5,"unit":"cup","item":"all purpose flour","group":"batter"},{"amount":1,"unit":"tsp","item":"baking powder","group":"batter"},{"amount":0.5,"unit":"tsp","item":"baking soda","group":"batter"},{"amount":1,"unit":"cup","item":"buttermilk","group":"batter"},{"amount":1,"unit":"large","item":"egg","group":"batter"},{"amount":0.5,"unit":"cup","item":"finely diced yellow onion","group":"mix-in"},{"amount":4,"unit":"cups","item":"vegetable oil for frying","group":"cooking"}]','[{"title":"Mix the Dry Ingredients","text":"In a large mixing bowl combine the yellow cornmeal, all purpose flour, baking powder, baking soda, and one teaspoon of salt. Whisk everything together until evenly distributed. Good leavening is key to achieving that light and fluffy interior.","timer":60},{"title":"Add the Wet Ingredients","text":"In a separate bowl whisk together the buttermilk and egg until smooth. Pour the wet mixture into the dry ingredients and stir until just combined. Fold in the finely diced yellow onion. Do not overmix the batter as this will make the hushpuppies tough.","timer":120},{"title":"Heat the Oil","text":"Pour vegetable oil into a deep skillet or Dutch oven to a depth of 3 inches. Heat over medium high heat to 365 degrees F. Maintaining the right temperature ensures the hushpuppies cook through without burning on the outside.","timer":360},{"title":"Fry the Hushpuppies","text":"Using a small cookie scoop or two spoons carefully drop rounded tablespoon sized portions of batter into the hot oil. Fry in batches of 6 to 8 at a time for 3 to 4 minutes, turning occasionally, until they are deep golden brown all over. They will naturally roll over as they cook.","timer":240},{"title":"Drain and Serve","text":"Remove the hushpuppies with a slotted spoon and place them on a paper towel lined plate to drain. Sprinkle lightly with salt while still hot. Serve immediately alongside fried catfish, coleslaw, or any Southern meal.","timer":60}]','[{"original":"buttermilk","swap":"whole milk with one teaspoon of apple cider vinegar stirred in"},{"original":"yellow onion","swap":"sliced green onions for a milder and brighter flavor"},{"original":"all purpose flour","swap":"gluten free 1 to 1 flour blend to make them gluten free"}]','["Overmixing the batter which develops gluten and creates dense rubbery hushpuppies","Frying at too high a temperature which browns the outside before the center cooks through","Making the portions too large which results in undercooked centers"]','["Southern","side dish","cornmeal","fried","comfort food","seafood pairing","cookout"]','["vegetarian"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Jalapeno Cheddar Hushpuppies','jalapeno-cheddar-hushpuppies','A spicy twist on the Southern classic with sharp cheddar and fresh jalapenos folded into the cornmeal batter. These bold flavored fritters add excitement to any cookout or fish fry.','Spicy cheesy cornmeal fritters with jalapeno and sharp cheddar baked inside.','Southern American','Easy',12,20,32,6,320,8,32,18,2,'[{"amount":1.5,"unit":"cups","item":"yellow cornmeal","group":"batter"},{"amount":0.5,"unit":"cup","item":"all purpose flour","group":"batter"},{"amount":1,"unit":"tsp","item":"baking powder","group":"batter"},{"amount":1,"unit":"cup","item":"buttermilk","group":"batter"},{"amount":1,"unit":"large","item":"egg","group":"batter"},{"amount":0.75,"unit":"cup","item":"shredded sharp cheddar cheese","group":"mix-in"},{"amount":2,"unit":"whole","item":"jalapenos seeded and finely diced","group":"mix-in"},{"amount":4,"unit":"cups","item":"vegetable oil for frying","group":"cooking"}]','[{"title":"Prepare the Mix Ins","text":"Seed and finely dice the jalapenos. Shred the sharp cheddar cheese if not already shredded. Set both aside. Removing the seeds from the jalapenos controls the heat level so do not skip this step if you prefer a milder spice.","timer":300},{"title":"Make the Batter","text":"In a large bowl whisk together the cornmeal, flour, baking powder, and half a teaspoon of salt. In a small bowl whisk the buttermilk and egg together. Add the wet ingredients to the dry and stir until just combined. Fold in the shredded cheddar and diced jalapenos gently.","timer":120},{"title":"Heat the Oil","text":"Fill a heavy skillet or Dutch oven with vegetable oil to a depth of 3 inches. Heat over medium high heat until the oil reaches 365 degrees F. Test the temperature with a thermometer for best results before dropping in any batter.","timer":360},{"title":"Fry in Batches","text":"Use a small cookie scoop to drop rounded tablespoons of batter into the hot oil, frying 6 to 8 at a time. Cook for 3 to 4 minutes turning occasionally until all sides are deep golden brown. The cheese inside will melt and create pockets of rich flavor throughout.","timer":240},{"title":"Drain and Serve","text":"Lift the hushpuppies out with a slotted spoon and set on paper towels to drain. Season with a pinch of salt right away. Serve hot with cool ranch dressing, sour cream, or a drizzle of honey for a sweet and spicy contrast.","timer":60}]','[{"original":"sharp cheddar cheese","swap":"pepper jack cheese for an extra spicy kick"},{"original":"fresh jalapenos","swap":"pickled jalapenos for a tangier and more mellow heat"},{"original":"buttermilk","swap":"sour cream thinned with a splash of milk"}]','["Not draining excess moisture from the jalapenos which makes the batter too wet","Using pre shredded cheese with anti caking agents which does not melt as smoothly","Dropping too many into the oil at once causing the temperature to drop and making greasy fritters"]','["Southern","spicy","cheesy","side dish","fried","jalapeno","game day","cookout"]','["vegetarian"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Ranch Dill Pickle Fries','ranch-dill-pickle-fries','Crispy oven baked fries seasoned with a bold ranch and dill pickle spice blend for an addictive tangy flavor. These loaded seasoned fries are a crowd pleasing snack with no frying required.','Tangy ranch and dill seasoned baked fries with crispy golden edges.','American','Easy',10,35,45,4,340,5,52,13,4,'[{"amount":2,"unit":"lbs","item":"russet potatoes cut into fry strips","group":"main"},{"amount":3,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":1,"unit":"tbsp","item":"dry ranch seasoning mix","group":"seasoning"},{"amount":1,"unit":"tsp","item":"dried dill weed","group":"seasoning"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"onion powder","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"white vinegar powder","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"cayenne pepper","group":"seasoning"}]','[{"title":"Cut and Soak the Potatoes","text":"Wash and cut the russet potatoes into quarter inch thick fry strips. Place the cut fries in a large bowl of cold water and soak for 20 minutes to draw out excess starch. This step is key to getting crispy edges in the oven. Do not skip the soak.","timer":1200},{"title":"Dry and Season the Fries","text":"Drain the soaked fries and pat them completely dry with paper towels. Transfer to a large dry bowl and toss with olive oil until well coated. In a small bowl mix together the ranch seasoning, dried dill, garlic powder, onion powder, vinegar powder, and cayenne. Sprinkle over the fries and toss to coat evenly.","timer":300},{"title":"Arrange on Baking Sheets","text":"Preheat oven to 425 degrees F. Arrange the seasoned fries in a single layer on two large baking sheets lined with parchment paper. Make sure fries are not touching each other. Overcrowding leads to steaming rather than crisping.","timer":120},{"title":"Bake Until Crispy","text":"Bake the fries for 20 minutes then flip each one with a spatula. Return to the oven and bake for another 12 to 15 minutes until golden and crispy. Rotate the pans halfway through to ensure even browning on both sheets.","timer":2100},{"title":"Season and Serve","text":"Remove from the oven and immediately season with a touch more dried dill and a pinch of salt if desired. Transfer to a serving bowl or platter and serve right away with extra ranch dressing for dipping. These are best eaten fresh from the oven.","timer":0}]','[{"original":"russet potatoes","swap":"sweet potatoes for a sweeter and more nutritious version"},{"original":"dry ranch seasoning mix","swap":"homemade blend of dried parsley, chives, and garlic salt"},{"original":"white vinegar powder","swap":"a splash of apple cider vinegar tossed with the fries before baking"}]','["Not soaking the potatoes which prevents them from getting crispy in the oven","Overcrowding the baking sheet which traps steam and makes fries soggy","Not flipping the fries halfway through which results in uneven browning"]','["baked","fries","ranch","dill","snack","side dish","tangy","healthier"]','["vegetarian","vegan"]','Side Dish','ai');